INSERT INTO lines (section_id,number,array_index,speaker,text) VALUES
('king_lear_act1_scene1',1,0,'KENT','I thought the king had more affected the Duke of Albany than Cornwall.'),
('king_lear_act1_scene1',2,1,'GLOUCESTER','It did always seem so to us: but now, in the division'),
('king_lear_act1_scene1',3,2,'GLOUCESTER','of the kingdom, it appears not which of the dukes he values'),
('king_lear_act1_scene1',4,3,'GLOUCESTER','most; for equalities are so weighed, that curiosity in neither can make'),
('king_lear_act1_scene1',5,4,'GLOUCESTER','choice of either’s moiety.'),
('king_lear_act1_scene1',6,5,'KENT','Is not this your son, my lord?'),
('king_lear_act1_scene1',7,6,'GLOUCESTER','His breeding, sir, hath been at my charge: I have so often'),
('king_lear_act1_scene1',8,7,'GLOUCESTER','blushed to acknowledge him, that now I am brazed to it.'),
('king_lear_act1_scene1',9,8,'KENT','I cannot conceive you.'),
('king_lear_act1_scene1',10,9,'GLOUCESTER','Sir, this young fellow’s mother could: whereupon she grew round-wombed, and had,'),
('king_lear_act1_scene1',11,10,'GLOUCESTER','indeed, sir, a son for her cradle ere she had a husband'),
('king_lear_act1_scene1',12,11,'GLOUCESTER','for her bed. Do you smell a fault?'),
('king_lear_act1_scene1',13,12,'KENT','I cannot wish the fault undone, the issue of it being so proper.'),
('king_lear_act1_scene1',14,13,'GLOUCESTER','But I have, sir, a son by order of law, some year'),
('king_lear_act1_scene1',15,14,'GLOUCESTER','elder than this, who yet is no dearer in my account: though'),
('king_lear_act1_scene1',16,15,'GLOUCESTER','this knave came something saucily into the world before he was sent'),
('king_lear_act1_scene1',17,16,'GLOUCESTER','for, yet was his mother fair; there was good sport at his'),
('king_lear_act1_scene1',18,17,'GLOUCESTER','making, and the whoreson must be acknowledged. Do you know this noble'),
('king_lear_act1_scene1',19,18,'GLOUCESTER','gentleman, Edmund?'),
('king_lear_act1_scene1',19,19,'EDMUND','No, my lord.'),
('king_lear_act1_scene1',20,20,'GLOUCESTER','My lord of Kent: remember him hereafter as my honourable friend.'),
('king_lear_act1_scene1',21,21,'EDMUND','My services to your lordship.'),
('king_lear_act1_scene1',22,22,'KENT','I must love you, and sue to know you better.'),
('king_lear_act1_scene1',23,23,'EDMUND','Sir, I shall study deserving.'),
('king_lear_act1_scene1',24,24,'GLOUCESTER','He hath been out nine years, and away he shall again. The king is coming.'),
('king_lear_act1_scene1',25,25,'KING LEAR','Attend the lords of France and Burgundy, Gloucester.'),
('king_lear_act1_scene1',26,26,'GLOUCESTER','I shall, my liege.'),
('king_lear_act1_scene1',27,27,'KING LEAR','Meantime we shall express our darker purpose.'),
('king_lear_act1_scene1',28,28,'KING LEAR','Give me the map there. Know that we have divided'),
('king_lear_act1_scene1',29,29,'KING LEAR','In three our kingdom: and ’tis our fast intent'),
('king_lear_act1_scene1',30,30,'KING LEAR','To shake all cares and business from our age;'),
('king_lear_act1_scene1',31,31,'KING LEAR','Conferring them on younger strengths, while we'),
('king_lear_act1_scene1',32,32,'KING LEAR','Unburthen’d crawl toward death. Our son of Cornwall,'),
('king_lear_act1_scene1',33,33,'KING LEAR','And you, our no less loving son of Albany,'),
('king_lear_act1_scene1',34,34,'KING LEAR','We have this hour a constant will to publish'),
('king_lear_act1_scene1',35,35,'KING LEAR','Our daughters’ several dowers, that future strife'),
('king_lear_act1_scene1',36,36,'KING LEAR','May be prevented now. The princes, France and Burgundy,'),
('king_lear_act1_scene1',37,37,'KING LEAR','Great rivals in our youngest daughter’s love,'),
('king_lear_act1_scene1',38,38,'KING LEAR','Long in our court have made their amorous sojourn,'),
('king_lear_act1_scene1',39,39,'KING LEAR','And here are to be answer’d. Tell me, my daughters—'),
('king_lear_act1_scene1',40,40,'KING LEAR','Since now we will divest us both of rule,'),
('king_lear_act1_scene1',41,41,'KING LEAR','Interest of territory, cares of state—'),
('king_lear_act1_scene1',42,42,'KING LEAR','Which of you shall we say doth love us most?'),
('king_lear_act1_scene1',43,43,'KING LEAR','That we our largest bounty may extend'),
('king_lear_act1_scene1',44,44,'KING LEAR','Where nature doth with merit challenge. Goneril,'),
('king_lear_act1_scene1',45,45,'KING LEAR','Our eldest-born, speak first.'),
('king_lear_act1_scene1',46,46,'GONERIL','Sir, I love you more than words can wield the matter;'),
('king_lear_act1_scene1',47,47,'GONERIL','Dearer than eye-sight, space, and liberty;'),
('king_lear_act1_scene1',48,48,'GONERIL','Beyond what can be valued, rich or rare;'),
('king_lear_act1_scene1',49,49,'GONERIL','No less than life, with grace, health, beauty, honour;'),
('king_lear_act1_scene1',50,50,'GONERIL','As much as child e’er loved, or father found;'),
('king_lear_act1_scene1',51,51,'GONERIL','A love that makes breath poor, and speech unable;'),
('king_lear_act1_scene1',52,52,'GONERIL','Beyond all manner of so much I love you.'),
('king_lear_act1_scene1',53,53,'CORDELIA','What shall Cordelia do? Love, and be silent.'),
('king_lear_act1_scene1',54,54,'LEAR','Of all these bounds, even from this line to this,'),
('king_lear_act1_scene1',55,55,'LEAR','With shadowy forests and with champains rich’d,'),
('king_lear_act1_scene1',56,56,'LEAR','With plenteous rivers and wide-skirted meads,'),
('king_lear_act1_scene1',57,57,'LEAR','We make thee lady: to thine and Albany’s issue'),
('king_lear_act1_scene1',58,58,'LEAR','Be this perpetual. What says our second daughter,'),
('king_lear_act1_scene1',59,59,'LEAR','Our dearest Regan, wife to Cornwall? Speak.'),
('king_lear_act1_scene1',60,60,'REGAN','Sir, I am made'),
('king_lear_act1_scene1',61,61,'REGAN','Of the self-same metal that my sister is,'),
('king_lear_act1_scene1',62,62,'REGAN','And prize me at her worth. In my true heart'),
('king_lear_act1_scene1',63,63,'REGAN','I find she names my very deed of love;'),
('king_lear_act1_scene1',64,64,'REGAN','Only she comes too short: that I profess'),
('king_lear_act1_scene1',65,65,'REGAN','Myself an enemy to all other joys,'),
('king_lear_act1_scene1',66,66,'REGAN','Which the most precious square of sense possesses;'),
('king_lear_act1_scene1',67,67,'REGAN','And find I am alone felicitate'),
('king_lear_act1_scene1',68,68,'REGAN','In your dear highness’ love.'),
('king_lear_act1_scene1',68,69,'CORDELIA','Then poor Cordelia!'),
('king_lear_act1_scene1',69,70,'CORDELIA','And yet not so; since, I am sure, my love’s'),
('king_lear_act1_scene1',70,71,'CORDELIA','More richer than my tongue.'),
('king_lear_act1_scene1',70,72,'KING LEAR','To thee and thine hereditary ever'),
('king_lear_act1_scene1',71,73,'KING LEAR','Remain this ample third of our fair kingdom;'),
('king_lear_act1_scene1',72,74,'KING LEAR','No less in space, validity, and pleasure,'),
('king_lear_act1_scene1',73,75,'KING LEAR','Than that conferr’d on Goneril. Now, our joy,'),
('king_lear_act1_scene1',74,76,'KING LEAR','Although the last, not least; to whose young love'),
('king_lear_act1_scene1',75,77,'KING LEAR','The vines of France and milk of Burgundy'),
('king_lear_act1_scene1',76,78,'KING LEAR','Strive to be interess’d; what can you say to draw'),
('king_lear_act1_scene1',77,79,'KING LEAR','A third more opulent than your sisters? Speak.'),
('king_lear_act1_scene1',78,80,'CORDELIA','Nothing, my lord.'),
('king_lear_act1_scene1',78,81,'KING LEAR','Nothing!'),
('king_lear_act1_scene1',79,82,'CORDELIA','Nothing.'),
('king_lear_act1_scene1',80,83,'KING LEAR','Nothing will come of nothing: speak again.'),
('king_lear_act1_scene1',81,84,'CORDELIA','Unhappy that I am, I cannot heave'),
('king_lear_act1_scene1',82,85,'CORDELIA','My heart into my mouth: I love your majesty'),
('king_lear_act1_scene1',83,86,'CORDELIA','According to my bond; nor more nor less.'),
('king_lear_act1_scene1',84,87,'KING LEAR','How, how, Cordelia! mend your speech a little,'),
('king_lear_act1_scene1',85,88,'KING LEAR','Lest it may mar your fortunes.'),
('king_lear_act1_scene1',85,89,'CORDELIA','Good my lord,'),
('king_lear_act1_scene1',86,90,'CORDELIA','You have begot me, bred me, loved me: I'),
('king_lear_act1_scene1',87,91,'CORDELIA','Return those duties back as are right fit,'),
('king_lear_act1_scene1',88,92,'CORDELIA','Obey you, love you, and most honour you.'),
('king_lear_act1_scene1',89,93,'CORDELIA','Why have my sisters husbands, if they say'),
('king_lear_act1_scene1',90,94,'CORDELIA','They love you all? Haply, when I shall wed,'),
('king_lear_act1_scene1',91,95,'CORDELIA','That lord whose hand must take my plight shall carry'),
('king_lear_act1_scene1',92,96,'CORDELIA','Half my love with him, half my care and duty:'),
('king_lear_act1_scene1',93,97,'CORDELIA','Sure, I shall never marry like my sisters,'),
('king_lear_act1_scene1',94,98,'CORDELIA','To love my father all.'),
('king_lear_act1_scene1',94,99,'KING LEAR','But goes thy heart with this?'),
('king_lear_act1_scene1',95,100,'CORDELIA','Ay, good my lord.'),
('king_lear_act1_scene1',95,101,'KING LEAR','So young, and so untender?'),
('king_lear_act1_scene1',96,102,'CORDELIA','So young, my lord, and true.'),
('king_lear_act1_scene1',97,103,'KING LEAR','Let it be so; thy truth, then, be thy dower:'),
('king_lear_act1_scene1',98,104,'KING LEAR','For, by the sacred radiance of the sun,'),
('king_lear_act1_scene1',99,105,'KING LEAR','The mysteries of Hecate, and the night;'),
('king_lear_act1_scene1',100,106,'KING LEAR','By all the operation of the orbs'),
('king_lear_act1_scene1',101,107,'KING LEAR','From whom we do exist, and cease to be;'),
('king_lear_act1_scene1',102,108,'KING LEAR','Here I disclaim all my paternal care,'),
('king_lear_act1_scene1',103,109,'KING LEAR','Propinquity and property of blood,'),
('king_lear_act1_scene1',104,110,'KING LEAR','And as a stranger to my heart and me'),
('king_lear_act1_scene1',105,111,'KING LEAR','Hold thee, from this, for ever. The barbarous Scythian,'),
('king_lear_act1_scene1',106,112,'KING LEAR','Or he that makes his generation messes'),
('king_lear_act1_scene1',107,113,'KING LEAR','To gorge his appetite, shall to my bosom'),
('king_lear_act1_scene1',108,114,'KING LEAR','Be as well neighbour’d, pitied, and relieved,'),
('king_lear_act1_scene1',109,115,'KING LEAR','As thou my sometime daughter.'),
('king_lear_act1_scene1',109,116,'KENT','Good my liege—'),
('king_lear_act1_scene1',110,117,'KING LEAR','Peace, Kent!'),
('king_lear_act1_scene1',111,118,'KING LEAR','Come not between the dragon and his wrath.'),
('king_lear_act1_scene1',112,119,'KING LEAR','I loved her most, and thought to set my rest'),
('king_lear_act1_scene1',113,120,'KING LEAR','On her kind nursery. Hence, and avoid my sight!'),
('king_lear_act1_scene1',114,121,'KING LEAR','So be my grave my peace, as here I give'),
('king_lear_act1_scene1',115,122,'KING LEAR','Her father’s heart from her! Call France; who stirs?'),
('king_lear_act1_scene1',116,123,'KING LEAR','Call Burgundy. Cornwall and Albany,'),
('king_lear_act1_scene1',117,124,'KING LEAR','With my two daughters’ dowers digest this third:'),
('king_lear_act1_scene1',118,125,'KING LEAR','Let pride, which she calls plainness, marry her.'),
('king_lear_act1_scene1',119,126,'KING LEAR','I do invest you jointly with my power,'),
('king_lear_act1_scene1',120,127,'KING LEAR','Pre-eminence, and all the large effects'),
('king_lear_act1_scene1',121,128,'KING LEAR','That troop with majesty. Ourself, by monthly course,'),
('king_lear_act1_scene1',122,129,'KING LEAR','With reservation of an hundred knights,'),
('king_lear_act1_scene1',123,130,'KING LEAR','By you to be sustain’d, shall our abode'),
('king_lear_act1_scene1',124,131,'KING LEAR','Make with you by due turns. Only we still retain'),
('king_lear_act1_scene1',125,132,'KING LEAR','The name, and all the additions to a king;'),
('king_lear_act1_scene1',126,133,'KING LEAR','The sway, revenue, execution of the rest,'),
('king_lear_act1_scene1',127,134,'KING LEAR','Beloved sons, be yours: which to confirm,'),
('king_lear_act1_scene1',128,135,'KING LEAR','This coronet part betwixt you.'),
('king_lear_act1_scene1',128,136,'KENT','Royal Lear,'),
('king_lear_act1_scene1',129,137,'KENT','Whom I have ever honour’d as my king,'),
('king_lear_act1_scene1',130,138,'KENT','Loved as my father, as my master follow’d,'),
('king_lear_act1_scene1',131,139,'KENT','As my great patron thought on in my prayers—'),
('king_lear_act1_scene1',132,140,'KING LEAR','The bow is bent and drawn, make from the shaft.'),
('king_lear_act1_scene1',133,141,'KENT','Let it fall rather, though the fork invade'),
('king_lear_act1_scene1',134,142,'KENT','The region of my heart: be Kent unmannerly,'),
('king_lear_act1_scene1',135,143,'KENT','When Lear is mad. What wilt thou do, old man?'),
('king_lear_act1_scene1',136,144,'KENT','Think’st thou that duty shall have dread to speak,'),
('king_lear_act1_scene1',137,145,'KENT','When power to flattery bows? To plainness honour’s bound,'),
('king_lear_act1_scene1',138,146,'KENT','When majesty stoops to folly. Reverse thy doom;'),
('king_lear_act1_scene1',139,147,'KENT','And, in thy best consideration, cheque'),
('king_lear_act1_scene1',140,148,'KENT','This hideous rashness: answer my life my judgment,'),
('king_lear_act1_scene1',141,149,'KENT','Thy youngest daughter does not love thee least;'),
('king_lear_act1_scene1',142,150,'KENT','Nor are those empty-hearted whose low sound'),
('king_lear_act1_scene1',143,151,'KENT','Reverbs no hollowness.'),
('king_lear_act1_scene1',143,152,'KING LEAR','Kent, on thy life, no more.'),
('king_lear_act1_scene1',144,153,'KENT','My life I never held but as a pawn'),
('king_lear_act1_scene1',145,154,'KENT','To wage against thy enemies; nor fear to lose it,'),
('king_lear_act1_scene1',146,155,'KENT','Thy safety being the motive.'),
('king_lear_act1_scene1',146,156,'KING LEAR','Out of my sight!'),
('king_lear_act1_scene1',147,157,'KENT','See better, Lear; and let me still remain'),
('king_lear_act1_scene1',148,158,'KENT','The true blank of thine eye.'),
('king_lear_act1_scene1',148,159,'KING LEAR','Now, by Apollo—'),
('king_lear_act1_scene1',149,160,'KENT','Now, by Apollo, king,'),
('king_lear_act1_scene1',150,161,'KENT','Thou swear’st thy gods in vain.'),
('king_lear_act1_scene1',151,162,'KING LEAR','O, vassal! miscreant! Laying his hand on his sword.'),
('king_lear_act1_scene1',152,163,'ALBANY CORNWALL','Dear sir, forbear.'),
('king_lear_act1_scene1',152,164,'KENT','Do:'),
('king_lear_act1_scene1',153,165,'KENT','Kill thy physician, and the fee bestow'),
('king_lear_act1_scene1',154,166,'KENT','Upon thy foul disease. Revoke thy doom;'),
('king_lear_act1_scene1',155,167,'KENT','Or, whilst I can vent clamour from my throat,'),
('king_lear_act1_scene1',156,168,'KENT','I’ll tell thee thou dost evil.'),
('king_lear_act1_scene1',156,169,'KING LEAR','Hear me, recreant!'),
('king_lear_act1_scene1',157,170,'KING LEAR','On thine allegiance, hear me!'),
('king_lear_act1_scene1',158,171,'KING LEAR','Since thou hast sought to make us break our vow,'),
('king_lear_act1_scene1',159,172,'KING LEAR','Which we durst never yet, and with strain’d pride'),
('king_lear_act1_scene1',160,173,'KING LEAR','To come between our sentence and our power,'),
('king_lear_act1_scene1',161,174,'KING LEAR','Which nor our nature nor our place can bear,'),
('king_lear_act1_scene1',162,175,'KING LEAR','Our potency made good, take thy reward.'),
('king_lear_act1_scene1',163,176,'KING LEAR','Five days we do allot thee, for provision'),
('king_lear_act1_scene1',164,177,'KING LEAR','To shield thee from diseases of the world;'),
('king_lear_act1_scene1',165,178,'KING LEAR','And on the sixth to turn thy hated back'),
('king_lear_act1_scene1',166,179,'KING LEAR','Upon our kingdom: if, on the tenth day following,'),
('king_lear_act1_scene1',167,180,'KING LEAR','Thy banish’d trunk be found in our dominions,'),
('king_lear_act1_scene1',168,181,'KING LEAR','The moment is thy death. Away! by Jupiter,'),
('king_lear_act1_scene1',169,182,'KING LEAR','This shall not be revoked.'),
('king_lear_act1_scene1',170,183,'KENT','Fare thee well, king: sith thus thou wilt appear,'),
('king_lear_act1_scene1',171,184,'KENT','Freedom lives hence, and banishment is here.'),
('king_lear_act1_scene1',172,185,'KENT','To Cordelia. The gods to their dear shelter take thee, maid,'),
('king_lear_act1_scene1',173,186,'KENT','That justly think’st, and hast most rightly said!'),
('king_lear_act1_scene1',174,187,'KENT','To Regan and Goneril. And your large speeches may your deeds approve,'),
('king_lear_act1_scene1',175,188,'KENT','That good effects may spring from words of love.'),
('king_lear_act1_scene1',176,189,'KENT','Thus Kent, O princes, bids you all adieu;'),
('king_lear_act1_scene1',177,190,'KENT','He’ll shape his old course in a country new.'),
('king_lear_act1_scene1',178,191,'GLOUCESTER','Here’s France and Burgundy, my noble lord.'),
('king_lear_act1_scene1',179,192,'KING LEAR','My lord of Burgundy.'),
('king_lear_act1_scene1',180,193,'KING LEAR','We first address towards you, who with this king'),
('king_lear_act1_scene1',181,194,'KING LEAR','Hath rivall’d for our daughter: what, in the least,'),
('king_lear_act1_scene1',182,195,'KING LEAR','Will you require in present dower with her,'),
('king_lear_act1_scene1',183,196,'KING LEAR','Or cease your quest of love?'),
('king_lear_act1_scene1',183,197,'BURGUNDY','Most royal majesty,'),
('king_lear_act1_scene1',184,198,'BURGUNDY','I crave no more than what your highness offer’d,'),
('king_lear_act1_scene1',185,199,'BURGUNDY','Nor will you tender less.'),
('king_lear_act1_scene1',185,200,'KING LEAR','Right noble Burgundy,'),
('king_lear_act1_scene1',186,201,'KING LEAR','When she was dear to us, we did hold her so;'),
('king_lear_act1_scene1',187,202,'KING LEAR','But now her price is fall’n. Sir, there she stands:'),
('king_lear_act1_scene1',188,203,'KING LEAR','If aught within that little seeming substance,'),
('king_lear_act1_scene1',189,204,'KING LEAR','Or all of it, with our displeasure pieced,'),
('king_lear_act1_scene1',190,205,'KING LEAR','And nothing more, may fitly like your grace,'),
('king_lear_act1_scene1',191,206,'KING LEAR','She’s there, and she is yours.'),
('king_lear_act1_scene1',191,207,'BURGUNDY','I know no answer.'),
('king_lear_act1_scene1',192,208,'KING LEAR','Will you, with those infirmities she owes,'),
('king_lear_act1_scene1',193,209,'KING LEAR','Unfriended, new-adopted to our hate,'),
('king_lear_act1_scene1',194,210,'KING LEAR','Dower’d with our curse, and stranger’d with our oath,'),
('king_lear_act1_scene1',195,211,'KING LEAR','Take her, or leave her?'),
('king_lear_act1_scene1',195,212,'BURGUNDY','Pardon me, royal sir;'),
('king_lear_act1_scene1',196,213,'BURGUNDY','Election makes not up on such conditions.'),
('king_lear_act1_scene1',197,214,'KING LEAR','Then leave her, sir; for, by the power that made me,'),
('king_lear_act1_scene1',198,215,'KING LEAR','I tell you all her wealth. To King of France. For you, great king,'),
('king_lear_act1_scene1',199,216,'KING LEAR','I would not from your love make such a stray,'),
('king_lear_act1_scene1',200,217,'KING LEAR','To match you where I hate; therefore beseech you'),
('king_lear_act1_scene1',201,218,'KING LEAR','To avert your liking a more worthier way'),
('king_lear_act1_scene1',202,219,'KING LEAR','Than on a wretch whom nature is ashamed'),
('king_lear_act1_scene1',203,220,'KING LEAR','Almost to acknowledge hers.'),
('king_lear_act1_scene1',203,221,'KING OF FRANCE','This is most strange,'),
('king_lear_act1_scene1',204,222,'KING OF FRANCE','That she, that even but now was your best object,'),
('king_lear_act1_scene1',205,223,'KING OF FRANCE','The argument of your praise, balm of your age,'),
('king_lear_act1_scene1',206,224,'KING OF FRANCE','Most best, most dearest, should in this trice of time'),
('king_lear_act1_scene1',207,225,'KING OF FRANCE','Commit a thing so monstrous, to dismantle'),
('king_lear_act1_scene1',208,226,'KING OF FRANCE','So many folds of favour. Sure, her offence'),
('king_lear_act1_scene1',209,227,'KING OF FRANCE','Must be of such unnatural degree,'),
('king_lear_act1_scene1',210,228,'KING OF FRANCE','That monsters it, or your fore-vouch’d affection'),
('king_lear_act1_scene1',211,229,'KING OF FRANCE','Fall’n into taint: which to believe of her,'),
('king_lear_act1_scene1',212,230,'KING OF FRANCE','Must be a faith that reason without miracle'),
('king_lear_act1_scene1',213,231,'KING OF FRANCE','Could never plant in me.'),
('king_lear_act1_scene1',213,232,'CORDELIA','I yet beseech your majesty—'),
('king_lear_act1_scene1',214,233,'CORDELIA','If for I want that glib and oily art,'),
('king_lear_act1_scene1',215,234,'CORDELIA','To speak and purpose not; since what I well intend,'),
('king_lear_act1_scene1',216,235,'CORDELIA','I’ll do’t before I speak—that you make known'),
('king_lear_act1_scene1',217,236,'CORDELIA','It is no vicious blot, murder, or foulness,'),
('king_lear_act1_scene1',218,237,'CORDELIA','No unchaste action, or dishonour’d step,'),
('king_lear_act1_scene1',219,238,'CORDELIA','That hath deprived me of your grace and favour;'),
('king_lear_act1_scene1',220,239,'CORDELIA','But even for want of that for which I am richer,'),
('king_lear_act1_scene1',221,240,'CORDELIA','A still-soliciting eye, and such a tongue'),
('king_lear_act1_scene1',222,241,'CORDELIA','As I am glad I have not, though not to have it'),
('king_lear_act1_scene1',223,242,'CORDELIA','Hath lost me in your liking.'),
('king_lear_act1_scene1',223,243,'KING LEAR','Better thou'),
('king_lear_act1_scene1',224,244,'KING LEAR','Hadst not been born than not to have pleased me better.'),
('king_lear_act1_scene1',225,245,'KING OF FRANCE','Is it but this—a tardiness in nature'),
('king_lear_act1_scene1',226,246,'KING OF FRANCE','Which often leaves the history unspoke'),
('king_lear_act1_scene1',227,247,'KING OF FRANCE','That it intends to do? My lord of Burgundy,'),
('king_lear_act1_scene1',228,248,'KING OF FRANCE','What say you to the lady? Love’s not love'),
('king_lear_act1_scene1',229,249,'KING OF FRANCE','When it is mingled with regards that stand'),
('king_lear_act1_scene1',230,250,'KING OF FRANCE','Aloof from the entire point. Will you have her?'),
('king_lear_act1_scene1',231,251,'KING OF FRANCE','She is herself a dowry.'),
('king_lear_act1_scene1',231,252,'BURGUNDY','Royal Lear,'),
('king_lear_act1_scene1',232,253,'BURGUNDY','Give but that portion which yourself proposed,'),
('king_lear_act1_scene1',233,254,'BURGUNDY','And here I take Cordelia by the hand,'),
('king_lear_act1_scene1',234,255,'BURGUNDY','Duchess of Burgundy.'),
('king_lear_act1_scene1',235,256,'KING LEAR','Nothing: I have sworn; I am firm.'),
('king_lear_act1_scene1',236,257,'BURGUNDY','I am sorry, then, you have so lost a father'),
('king_lear_act1_scene1',237,258,'BURGUNDY','That you must lose a husband.'),
('king_lear_act1_scene1',237,259,'CORDELIA','Peace be with Burgundy!'),
('king_lear_act1_scene1',238,260,'CORDELIA','Since that respects of fortune are his love,'),
('king_lear_act1_scene1',239,261,'CORDELIA','I shall not be his wife.'),
('king_lear_act1_scene1',240,262,'KING OF FRANCE','Fairest Cordelia, that art most rich, being poor;'),
('king_lear_act1_scene1',241,263,'KING OF FRANCE','Most choice, forsaken; and most loved, despised!'),
('king_lear_act1_scene1',242,264,'KING OF FRANCE','Thee and thy virtues here I seize upon:'),
('king_lear_act1_scene1',243,265,'KING OF FRANCE','Be it lawful I take up what’s cast away.'),
('king_lear_act1_scene1',244,266,'KING OF FRANCE','Gods, gods! ’tis strange that from their cold’st neglect'),
('king_lear_act1_scene1',245,267,'KING OF FRANCE','My love should kindle to inflamed respect.'),
('king_lear_act1_scene1',246,268,'KING OF FRANCE','Thy dowerless daughter, king, thrown to my chance,'),
('king_lear_act1_scene1',247,269,'KING OF FRANCE','Is queen of us, of ours, and our fair France:'),
('king_lear_act1_scene1',248,270,'KING OF FRANCE','Not all the dukes of waterish Burgundy'),
('king_lear_act1_scene1',249,271,'KING OF FRANCE','Can buy this unprized precious maid of me.'),
('king_lear_act1_scene1',250,272,'KING OF FRANCE','Bid them farewell, Cordelia, though unkind:'),
('king_lear_act1_scene1',251,273,'KING OF FRANCE','Thou losest here, a better where to find.'),
('king_lear_act1_scene1',252,274,'KING LEAR','Thou hast her, France: let her be thine; for we'),
('king_lear_act1_scene1',253,275,'KING LEAR','Have no such daughter, nor shall ever see'),
('king_lear_act1_scene1',254,276,'KING LEAR','That face of hers again. Therefore be gone'),
('king_lear_act1_scene1',255,277,'KING LEAR','Without our grace, our love, our benison.'),
('king_lear_act1_scene1',256,278,'KING LEAR','Come, noble Burgundy.'),
('king_lear_act1_scene1',256,279,'KING OF FRANCE','Bid farewell to your sisters.'),
('king_lear_act1_scene1',257,280,'CORDELIA','The jewels of our father, with wash’d eyes'),
('king_lear_act1_scene1',258,281,'CORDELIA','Cordelia leaves you: I know you what you are;'),
('king_lear_act1_scene1',259,282,'CORDELIA','And like a sister am most loath to call'),
('king_lear_act1_scene1',260,283,'CORDELIA','Your faults as they are named. Use well our father:'),
('king_lear_act1_scene1',261,284,'CORDELIA','To your professed bosoms I commit him'),
('king_lear_act1_scene1',262,285,'CORDELIA','But yet, alas, stood I within his grace,'),
('king_lear_act1_scene1',263,286,'CORDELIA','I would prefer him to a better place.'),
('king_lear_act1_scene1',264,287,'CORDELIA','So, farewell to you both.'),
('king_lear_act1_scene1',264,288,'REGAN','Prescribe not us our duties.'),
('king_lear_act1_scene1',265,289,'GONERIL','Let your study'),
('king_lear_act1_scene1',266,290,'GONERIL','Be to content your lord, who hath received you'),
('king_lear_act1_scene1',267,291,'GONERIL','At fortune’s alms. You have obedience scanted,'),
('king_lear_act1_scene1',268,292,'GONERIL','And well are worth the want that you have wanted.'),
('king_lear_act1_scene1',269,293,'CORDELIA','Time shall unfold what plaited cunning hides:'),
('king_lear_act1_scene1',270,294,'CORDELIA','Who cover faults, at last shame them derides.'),
('king_lear_act1_scene1',271,295,'CORDELIA','Well may you prosper!'),
('king_lear_act1_scene1',271,296,'KING OF FRANCE','Come, my fair Cordelia.'),
('king_lear_act1_scene1',272,297,'GONERIL','Sister, it is not a little I have to say of what'),
('king_lear_act1_scene1',273,298,'GONERIL','most nearly appertains to us both. I think our father will hence'),
('king_lear_act1_scene1',274,299,'GONERIL','to-night.'),
('king_lear_act1_scene1',275,300,'REGAN','That’s most certain, and with you; next month with us.'),
('king_lear_act1_scene1',276,301,'GONERIL','You see how full of changes his age is; the observation we'),
('king_lear_act1_scene1',277,302,'GONERIL','have made of it hath not been little: he always loved our'),
('king_lear_act1_scene1',278,303,'GONERIL','sister most; and with what poor judgment he hath now cast her'),
('king_lear_act1_scene1',279,304,'GONERIL','off appears too grossly.'),
('king_lear_act1_scene1',280,305,'REGAN','’Tis the infirmity of his age: yet he hath ever but slenderly known himself.'),
('king_lear_act1_scene1',281,306,'GONERIL','The best and soundest of his time hath been but rash; then'),
('king_lear_act1_scene1',282,307,'GONERIL','must we look to receive from his age, not alone the imperfections'),
('king_lear_act1_scene1',283,308,'GONERIL','of long-engraffed condition, but therewithal the unruly waywardness that infirm and choleric'),
('king_lear_act1_scene1',284,309,'GONERIL','years bring with them.'),
('king_lear_act1_scene1',285,310,'REGAN','Such unconstant starts are we like to have from him as this of Kent’s banishment.'),
('king_lear_act1_scene1',286,311,'GONERIL','There is further compliment of leavetaking between France and him. Pray you,'),
('king_lear_act1_scene1',287,312,'GONERIL','let’s hit together: if our father carry authority with such dispositions as'),
('king_lear_act1_scene1',288,313,'GONERIL','he bears, this last surrender of his will but offend us.'),
('king_lear_act1_scene1',289,314,'REGAN','We shall further think on’t.'),
('king_lear_act1_scene1',290,315,'GONERIL','We must do something, and i’ the heat.'),
('king_lear_act1_scene2',1,0,'EDMUND','Thou, nature, art my goddess; to thy law'),
('king_lear_act1_scene2',2,1,'EDMUND','My services are bound. Wherefore should I'),
('king_lear_act1_scene2',3,2,'EDMUND','Stand in the plague of custom, and permit'),
('king_lear_act1_scene2',4,3,'EDMUND','The curiosity of nations to deprive me,'),
('king_lear_act1_scene2',5,4,'EDMUND','For that I am some twelve or fourteen moon-shines'),
('king_lear_act1_scene2',6,5,'EDMUND','Lag of a brother? Why bastard? wherefore base?'),
('king_lear_act1_scene2',7,6,'EDMUND','When my dimensions are as well compact,'),
('king_lear_act1_scene2',8,7,'EDMUND','My mind as generous, and my shape as true,'),
('king_lear_act1_scene2',9,8,'EDMUND','As honest madam’s issue? Why brand they us'),
('king_lear_act1_scene2',10,9,'EDMUND','With base? with baseness? bastardy? base, base?'),
('king_lear_act1_scene2',11,10,'EDMUND','Who, in the lusty stealth of nature, take'),
('king_lear_act1_scene2',12,11,'EDMUND','More composition and fierce quality'),
('king_lear_act1_scene2',13,12,'EDMUND','Than doth, within a dull, stale, tired bed,'),
('king_lear_act1_scene2',14,13,'EDMUND','Go to the creating a whole tribe of fops,'),
('king_lear_act1_scene2',15,14,'EDMUND','Got ’tween asleep and wake? Well, then,'),
('king_lear_act1_scene2',16,15,'EDMUND','Legitimate Edgar, I must have your land:'),
('king_lear_act1_scene2',17,16,'EDMUND','Our father’s love is to the bastard Edmund'),
('king_lear_act1_scene2',18,17,'EDMUND','As to the legitimate: fine word—legitimate!'),
('king_lear_act1_scene2',19,18,'EDMUND','Well, my legitimate, if this letter speed,'),
('king_lear_act1_scene2',20,19,'EDMUND','And my invention thrive, Edmund the base'),
('king_lear_act1_scene2',21,20,'EDMUND','Shall top the legitimate. I grow; I prosper:'),
('king_lear_act1_scene2',22,21,'EDMUND','Now, gods, stand up for bastards!'),
('king_lear_act1_scene2',23,22,'GLOUCESTER','Kent banish’d thus! and France in choler parted!'),
('king_lear_act1_scene2',24,23,'GLOUCESTER','And the king gone to-night! subscribed his power!'),
('king_lear_act1_scene2',25,24,'GLOUCESTER','Confined to exhibition! All this done'),
('king_lear_act1_scene2',26,25,'GLOUCESTER','Upon the gad! Edmund, how now! what news?'),
('king_lear_act1_scene2',27,26,'EDMUND','So please your lordship, none. Putting up the letter.'),
('king_lear_act1_scene2',28,27,'GLOUCESTER','Why so earnestly seek you to put up that letter?'),
('king_lear_act1_scene2',29,28,'EDMUND','I know no news, my lord.'),
('king_lear_act1_scene2',29,29,'GLOUCESTER','What paper were you reading?'),
('king_lear_act1_scene2',30,30,'EDMUND','Nothing, my lord.'),
('king_lear_act1_scene2',31,31,'GLOUCESTER','No? What needed, then, that terrible dispatch of it into your pocket?'),
('king_lear_act1_scene2',32,32,'GLOUCESTER','the quality of nothing hath not such need to hide itself. Let’s'),
('king_lear_act1_scene2',33,33,'GLOUCESTER','see: come, if it be nothing, I shall not need spectacles.'),
('king_lear_act1_scene2',34,34,'EDMUND','I beseech you, sir, pardon me: it is a letter from my'),
('king_lear_act1_scene2',35,35,'EDMUND','brother, that I have not all o’er-read; and for so much as'),
('king_lear_act1_scene2',36,36,'EDMUND','I have perused, I find it not fit for your o’er-looking.'),
('king_lear_act1_scene2',37,37,'GLOUCESTER','Give me the letter, sir.'),
('king_lear_act1_scene2',38,38,'EDMUND','I shall offend, either to detain or give it. The contents, as'),
('king_lear_act1_scene2',39,39,'EDMUND','in part I understand them, are to blame.'),
('king_lear_act1_scene2',40,40,'GLOUCESTER','Let’s see, let’s see.'),
('king_lear_act1_scene2',41,41,'EDMUND','I hope, for my brother’s justification, he wrote this but as an'),
('king_lear_act1_scene2',42,42,'EDMUND','essay or taste of my virtue.'),
('king_lear_act1_scene2',43,43,'GLOUCESTER','“This policy and reverence of age makes the world bitter to the'),
('king_lear_act1_scene2',44,44,'GLOUCESTER','best of our times; keeps our fortunes from us till our oldness'),
('king_lear_act1_scene2',45,45,'GLOUCESTER','cannot relish them. I begin to find an idle and fond bondage'),
('king_lear_act1_scene2',46,46,'GLOUCESTER','in the oppression of aged tyranny; who sways, not as it hath'),
('king_lear_act1_scene2',47,47,'GLOUCESTER','power, but as it is suffered. Come to me, that of this'),
('king_lear_act1_scene2',48,48,'GLOUCESTER','I may speak more. If our father would sleep till I waked'),
('king_lear_act1_scene2',49,49,'GLOUCESTER','him, you should half his revenue for ever, and live the beloved'),
('king_lear_act1_scene2',50,50,'GLOUCESTER','of your brother, Edgar.”'),
('king_lear_act1_scene2',51,51,'EDMUND','It was not brought me, my lord; there’s the cunning of it;'),
('king_lear_act1_scene2',52,52,'EDMUND','I found it thrown in at the casement of my closet.'),
('king_lear_act1_scene2',53,53,'GLOUCESTER','You know the character to be your brother’s?'),
('king_lear_act1_scene2',54,54,'EDMUND','If the matter were good, my lord, I durst swear it were'),
('king_lear_act1_scene2',55,55,'EDMUND','his; but, in respect of that, I would fain think it were'),
('king_lear_act1_scene2',56,56,'EDMUND','not.'),
('king_lear_act1_scene2',56,57,'GLOUCESTER','It is his.'),
('king_lear_act1_scene2',57,58,'EDMUND','It is his hand, my lord; but I hope his heart is'),
('king_lear_act1_scene2',58,59,'EDMUND','not in the contents.'),
('king_lear_act1_scene2',59,60,'GLOUCESTER','Hath he never heretofore sounded you in this business?'),
('king_lear_act1_scene2',60,61,'EDMUND','Never, my lord: but I have heard him oft maintain it to'),
('king_lear_act1_scene2',61,62,'EDMUND','be fit, that, sons at perfect age, and fathers declining, the father'),
('king_lear_act1_scene2',62,63,'EDMUND','should be as ward to the son, and the son manage his'),
('king_lear_act1_scene2',63,64,'EDMUND','revenue.'),
('king_lear_act1_scene2',64,65,'GLOUCESTER','O villain, villain! His very opinion in the letter! Abhorred villain! Unnatural,'),
('king_lear_act1_scene2',65,66,'GLOUCESTER','detested, brutish villain! worse than brutish! Go, sirrah, seek him; I’ll apprehend'),
('king_lear_act1_scene2',66,67,'GLOUCESTER','him: abominable villain! Where is he?'),
('king_lear_act1_scene2',67,68,'EDMUND','I do not well know, my lord. If it shall please you'),
('king_lear_act1_scene2',68,69,'EDMUND','to suspend your indignation against my brother till you can derive from'),
('king_lear_act1_scene2',69,70,'EDMUND','him better testimony of his intent, you shall run a certain course;'),
('king_lear_act1_scene2',70,71,'EDMUND','where, if you violently proceed against him, mistaking his purpose, it would'),
('king_lear_act1_scene2',71,72,'EDMUND','make a great gap in your own honour, and shake in pieces'),
('king_lear_act1_scene2',72,73,'EDMUND','the heart of his obedience. I dare pawn down my life for'),
('king_lear_act1_scene2',73,74,'EDMUND','him, that he hath wrote this to feel my affection to your'),
('king_lear_act1_scene2',74,75,'EDMUND','honour, and to no further pretence of danger.'),
('king_lear_act1_scene2',75,76,'GLOUCESTER','Think you so?'),
('king_lear_act1_scene2',76,77,'EDMUND','If your honour judge it meet, I will place you where you'),
('king_lear_act1_scene2',77,78,'EDMUND','shall hear us confer of this, and by an auricular assurance have'),
('king_lear_act1_scene2',78,79,'EDMUND','your satisfaction; and that without any further delay than this very evening.'),
('king_lear_act1_scene2',79,80,'GLOUCESTER','He cannot be such a monster—'),
('king_lear_act1_scene2',79,81,'EDMUND','Nor is not, sure.'),
('king_lear_act1_scene2',80,82,'GLOUCESTER','To his father, that so tenderly and entirely loves him. Heaven and'),
('king_lear_act1_scene2',81,83,'GLOUCESTER','earth! Edmund, seek him out: wind me into him, I pray you:'),
('king_lear_act1_scene2',82,84,'GLOUCESTER','frame the business after your own wisdom. I would unstate myself, to'),
('king_lear_act1_scene2',83,85,'GLOUCESTER','be in a due resolution.'),
('king_lear_act1_scene2',84,86,'EDMUND','I will seek him, sir, presently: convey the business as I shall'),
('king_lear_act1_scene2',85,87,'EDMUND','find means and acquaint you withal.'),
('king_lear_act1_scene2',86,88,'GLOUCESTER','These late eclipses in the sun and moon portend no good to'),
('king_lear_act1_scene2',87,89,'GLOUCESTER','us: though the wisdom of nature can reason it thus and thus,'),
('king_lear_act1_scene2',88,90,'GLOUCESTER','yet nature finds itself scourged by the sequent effects: love cools, friendship'),
('king_lear_act1_scene2',89,91,'GLOUCESTER','falls off, brothers divide: in cities, mutinies; in countries, discord; in palaces,'),
('king_lear_act1_scene2',90,92,'GLOUCESTER','treason; and the bond cracked ’twixt son and father. This villain of'),
('king_lear_act1_scene2',91,93,'GLOUCESTER','mine comes under the prediction; there’s son against father: the king falls'),
('king_lear_act1_scene2',92,94,'GLOUCESTER','from bias of nature; there’s father against child. We have seen the'),
('king_lear_act1_scene2',93,95,'GLOUCESTER','best of our time: machinations, hollowness, treachery, and all ruinous disorders, follow'),
('king_lear_act1_scene2',94,96,'GLOUCESTER','us disquietly to our graves. Find out this villain, Edmund; it shall'),
('king_lear_act1_scene2',95,97,'GLOUCESTER','lose thee nothing; do it carefully. And the noble and true-hearted Kent'),
('king_lear_act1_scene2',96,98,'GLOUCESTER','banished! his offence, honesty! ’Tis strange.'),
('king_lear_act1_scene2',97,99,'EDMUND','This is the excellent foppery of the world, that, when we are'),
('king_lear_act1_scene2',98,100,'EDMUND','sick in fortune—often the surfeit of our own behavior—we make guilty of'),
('king_lear_act1_scene2',99,101,'EDMUND','our disasters the sun, the moon, and the stars: as if we'),
('king_lear_act1_scene2',100,102,'EDMUND','were villains by necessity; fools by heavenly compulsion; knaves, thieves, and treachers,'),
('king_lear_act1_scene2',101,103,'EDMUND','by spherical predominance; drunkards, liars, and adulterers, by an enforced obedience of'),
('king_lear_act1_scene2',102,104,'EDMUND','planetary influence; and all that we are evil in, by a divine'),
('king_lear_act1_scene2',103,105,'EDMUND','thrusting on: an admirable evasion of whoremaster man, to lay his goatish'),
('king_lear_act1_scene2',104,106,'EDMUND','disposition to the charge of a star! My father compounded with my'),
('king_lear_act1_scene2',105,107,'EDMUND','mother under the dragon’s tail; and my nativity was under Ursa major;'),
('king_lear_act1_scene2',106,108,'EDMUND','so that it follows, I am rough and lecherous. Tut, I should'),
('king_lear_act1_scene2',107,109,'EDMUND','have been that I am, had the maidenliest star in the firmament'),
('king_lear_act1_scene2',108,110,'EDMUND','twinkled on my bastardizing. Edgar—'),
('king_lear_act1_scene2',109,111,'EDGAR','How now, brother Edmund! what serious contemplation are you in?'),
('king_lear_act1_scene2',110,112,'EDMUND','I am thinking, brother, of a prediction I read this other day,'),
('king_lear_act1_scene2',111,113,'EDMUND','what should follow these eclipses.'),
('king_lear_act1_scene2',111,114,'EDGAR','Do you busy yourself about that?'),
('king_lear_act1_scene2',112,115,'EDMUND','I promise you, the effects he writes of succeed unhappily; as of'),
('king_lear_act1_scene2',113,116,'EDMUND','unnaturalness between the child and the parent; death, dearth, dissolutions of ancient'),
('king_lear_act1_scene2',114,117,'EDMUND','amities; divisions in state, menaces and maledictions against king and nobles; needless'),
('king_lear_act1_scene2',115,118,'EDMUND','diffidences, banishment of friends, dissipation of cohorts, nuptial breaches, and I know'),
('king_lear_act1_scene2',116,119,'EDMUND','not what.'),
('king_lear_act1_scene2',117,120,'EDGAR','How long have you been a sectary astronomical?'),
('king_lear_act1_scene2',118,121,'EDMUND','Come, come; when saw you my father last?'),
('king_lear_act1_scene2',119,122,'EDGAR','Why, the night gone by.'),
('king_lear_act1_scene2',119,123,'EDMUND','Spake you with him?'),
('king_lear_act1_scene2',120,124,'EDGAR','Ay, two hours together.'),
('king_lear_act1_scene2',121,125,'EDMUND','Parted you in good terms? Found you no displeasure in him by word or countenance?'),
('king_lear_act1_scene2',122,126,'EDGAR','None at all.'),
('king_lear_act1_scene2',123,127,'EDMUND','Bethink yourself wherein you may have offended him: and at my entreaty'),
('king_lear_act1_scene2',124,128,'EDMUND','forbear his presence till some little time hath qualified the heat of'),
('king_lear_act1_scene2',125,129,'EDMUND','his displeasure; which at this instant so rageth in him, that with'),
('king_lear_act1_scene2',126,130,'EDMUND','the mischief of your person it would scarcely allay.'),
('king_lear_act1_scene2',127,131,'EDGAR','Some villain hath done me wrong.'),
('king_lear_act1_scene2',128,132,'EDMUND','That’s my fear. I pray you, have a continent forbearance till the'),
('king_lear_act1_scene2',129,133,'EDMUND','spied of his rage goes slower; and, as I say, retire with'),
('king_lear_act1_scene2',130,134,'EDMUND','me to my lodging, from whence I will fitly bring you to'),
('king_lear_act1_scene2',131,135,'EDMUND','hear my lord speak: pray ye, go; there’s my key: if you'),
('king_lear_act1_scene2',132,136,'EDMUND','do stir abroad, go armed.'),
('king_lear_act1_scene2',132,137,'EDGAR','Armed, brother!'),
('king_lear_act1_scene2',133,138,'EDMUND','Brother, I advise you to the best; go armed: I am no'),
('king_lear_act1_scene2',134,139,'EDMUND','honest man if there be any good meaning towards you: I have'),
('king_lear_act1_scene2',135,140,'EDMUND','told you what I have seen and heard; but faintly, nothing like'),
('king_lear_act1_scene2',136,141,'EDMUND','the image and horror of it: pray you, away.'),
('king_lear_act1_scene2',137,142,'EDGAR','Shall I hear from you anon?'),
('king_lear_act1_scene2',138,143,'EDMUND','I do serve you in this business.'),
('king_lear_act1_scene3',1,0,'GONERIL','Did my father strike my gentleman for chiding of his fool?'),
('king_lear_act1_scene3',2,1,'OSWALD','Yes, madam.'),
('king_lear_act1_scene3',3,2,'GONERIL','By day and night he wrongs me; every hour'),
('king_lear_act1_scene3',4,3,'GONERIL','He flashes into one gross crime or other,'),
('king_lear_act1_scene3',5,4,'GONERIL','That sets us all at odds: I’ll not endure it:'),
('king_lear_act1_scene3',6,5,'GONERIL','His knights grow riotous, and himself upbraids us'),
('king_lear_act1_scene3',7,6,'GONERIL','On every trifle. When he returns from hunting,'),
('king_lear_act1_scene3',8,7,'GONERIL','I will not speak with him; say I am sick:'),
('king_lear_act1_scene3',9,8,'GONERIL','If you come slack of former services,'),
('king_lear_act1_scene3',10,9,'GONERIL','You shall do well; the fault of it I’ll answer.'),
('king_lear_act1_scene3',11,10,'OSWALD','He’s coming, madam; I hear him. Horns within.'),
('king_lear_act1_scene3',12,11,'GONERIL','Put on what weary negligence you please,'),
('king_lear_act1_scene3',13,12,'GONERIL','You and your fellows; I’ll have it come to question:'),
('king_lear_act1_scene3',14,13,'GONERIL','If he dislike it, let him to our sister,'),
('king_lear_act1_scene3',15,14,'GONERIL','Whose mind and mine, I know, in that are one,'),
('king_lear_act1_scene3',16,15,'GONERIL','Not to be over-ruled. Idle old man,'),
('king_lear_act1_scene3',17,16,'GONERIL','That still would manage those authorities'),
('king_lear_act1_scene3',18,17,'GONERIL','That he hath given away! Now, by my life,'),
('king_lear_act1_scene3',19,18,'GONERIL','Old fools are babes again; and must be used'),
('king_lear_act1_scene3',20,19,'GONERIL','With cheques as flatteries—when they are seen abused.'),
('king_lear_act1_scene3',21,20,'GONERIL','Remember what I tell you.'),
('king_lear_act1_scene3',21,21,'OSWALD','Well, madam.'),
('king_lear_act1_scene3',22,22,'GONERIL','And let his knights have colder looks among you;'),
('king_lear_act1_scene3',23,23,'GONERIL','What grows of it, no matter; advise your fellows so:'),
('king_lear_act1_scene3',24,24,'GONERIL','I would breed from hence occasions, and I shall,'),
('king_lear_act1_scene3',25,25,'GONERIL','That I may speak: I’ll write straight to my sister,'),
('king_lear_act1_scene3',26,26,'GONERIL','To hold my very course. Prepare for dinner.'),
('king_lear_act1_scene4',1,0,'KENT','If but as well I other accents borrow,'),
('king_lear_act1_scene4',2,1,'KENT','That can my speech defuse, my good intent'),
('king_lear_act1_scene4',3,2,'KENT','May carry through itself to that full issue'),
('king_lear_act1_scene4',4,3,'KENT','For which I razed my likeness. Now, banish’d Kent,'),
('king_lear_act1_scene4',5,4,'KENT','If thou canst serve where thou dost stand condemn’d,'),
('king_lear_act1_scene4',6,5,'KENT','So may it come, thy master, whom thou lovest,'),
('king_lear_act1_scene4',7,6,'KENT','Shall find thee full of labours.'),
('king_lear_act1_scene4',8,7,'KING LEAR','Let me not stay a jot for dinner; go get it ready.'),
('king_lear_act1_scene4',9,8,'KENT','A man, sir.'),
('king_lear_act1_scene4',10,9,'KING LEAR','What dost thou profess? what wouldst thou with us?'),
('king_lear_act1_scene4',11,10,'KENT','I do profess to be no less than I seem; to serve'),
('king_lear_act1_scene4',12,11,'KENT','him truly that will put me in trust: to love him that'),
('king_lear_act1_scene4',13,12,'KENT','is honest; to converse with him that is wise, and says little;'),
('king_lear_act1_scene4',14,13,'KENT','to fear judgment; to fight when I cannot choose; and to eat'),
('king_lear_act1_scene4',15,14,'KENT','no fish.'),
('king_lear_act1_scene4',15,15,'KING LEAR','What art thou?'),
('king_lear_act1_scene4',16,16,'KENT','A very honest-hearted fellow, and as poor as the king.'),
('king_lear_act1_scene4',17,17,'KING LEAR','If thou be as poor for a subject as he is for'),
('king_lear_act1_scene4',18,18,'KING LEAR','a king, thou art poor enough. What wouldst thou?'),
('king_lear_act1_scene4',19,19,'KENT','Service.'),
('king_lear_act1_scene4',19,20,'KING LEAR','Who wouldst thou serve?'),
('king_lear_act1_scene4',20,21,'KENT','You.'),
('king_lear_act1_scene4',20,22,'KING LEAR','Dost thou know me, fellow?'),
('king_lear_act1_scene4',21,23,'KENT','No, sir; but you have that in your countenance which I would fain call master.'),
('king_lear_act1_scene4',22,24,'KING LEAR','What’s that?'),
('king_lear_act1_scene4',22,25,'KENT','Authority.'),
('king_lear_act1_scene4',23,26,'KING LEAR','What services canst thou do?'),
('king_lear_act1_scene4',24,27,'KENT','I can keep honest counsel, ride, run, mar a curious tale in'),
('king_lear_act1_scene4',25,28,'KENT','telling it, and deliver a plain message bluntly: that which ordinary men'),
('king_lear_act1_scene4',26,29,'KENT','are fit for, I am qualified in; and the best of me'),
('king_lear_act1_scene4',27,30,'KENT','is diligence.'),
('king_lear_act1_scene4',27,31,'KING LEAR','How old art thou?'),
('king_lear_act1_scene4',28,32,'KENT','Not so young, sir, to love a woman for singing, nor so'),
('king_lear_act1_scene4',29,33,'KENT','old to dote on her for any thing: I have years on'),
('king_lear_act1_scene4',30,34,'KENT','my back forty eight.'),
('king_lear_act1_scene4',31,35,'KING LEAR','Follow me; thou shalt serve me: if I like thee no worse'),
('king_lear_act1_scene4',32,36,'KING LEAR','after dinner, I will not part from thee yet. Dinner, ho, dinner!'),
('king_lear_act1_scene4',33,37,'KING LEAR','Where’s my knave? my fool? Go you, and call my fool hither.'),
('king_lear_act1_scene4',34,38,'OSWALD','So please you—'),
('king_lear_act1_scene4',35,39,'KING LEAR','What says the fellow there? Call the clotpoll back.'),
('king_lear_act1_scene4',36,40,'KNIGHT','He says, my lord, your daughter is not well.'),
('king_lear_act1_scene4',37,41,'KING LEAR','Why came not the slave back to me when I called him.'),
('king_lear_act1_scene4',38,42,'KNIGHT','Sir, he answered me in the roundest manner, he would not.'),
('king_lear_act1_scene4',39,43,'KING LEAR','He would not!'),
('king_lear_act1_scene4',40,44,'KNIGHT','My lord, I know not what the matter is; but, to my'),
('king_lear_act1_scene4',41,45,'KNIGHT','judgment, your highness is not entertained with that ceremonious affection as you'),
('king_lear_act1_scene4',42,46,'KNIGHT','were wont; there’s a great abatement of kindness appears as well in'),
('king_lear_act1_scene4',43,47,'KNIGHT','the general dependants as in the duke himself also and your daughter.'),
('king_lear_act1_scene4',44,48,'KING LEAR','Ha! sayest thou so?'),
('king_lear_act1_scene4',45,49,'KNIGHT','I beseech you, pardon me, my lord, if I be mistaken; for'),
('king_lear_act1_scene4',46,50,'KNIGHT','my duty cannot be silent when I think your highness wronged.'),
('king_lear_act1_scene4',47,51,'KING LEAR','Thou but rememberest me of mine own conception: I have perceived a'),
('king_lear_act1_scene4',48,52,'KING LEAR','most faint neglect of late; which I have rather blamed as mine'),
('king_lear_act1_scene4',49,53,'KING LEAR','own jealous curiosity than as a very pretence and purpose of unkindness:'),
('king_lear_act1_scene4',50,54,'KING LEAR','I will look further into’t. But where’s my fool? I have not'),
('king_lear_act1_scene4',51,55,'KING LEAR','seen him this two days.'),
('king_lear_act1_scene4',52,56,'KNIGHT','Since my young lady’s going into France, sir, the fool hath much pined away.'),
('king_lear_act1_scene4',53,57,'KING LEAR','No more of that; I have noted it well. Go you, and'),
('king_lear_act1_scene4',54,58,'KING LEAR','tell my daughter I would speak with her. Go you, call hither'),
('king_lear_act1_scene4',55,59,'KING LEAR','my fool.'),
('king_lear_act1_scene4',55,60,'OSWALD','My lady’s father.'),
('king_lear_act1_scene4',56,61,'KING LEAR','“My lady’s father”! my lord’s knave: your whoreson dog! you slave! you cur!'),
('king_lear_act1_scene4',57,62,'OSWALD','I am none of these, my lord; I beseech your pardon.'),
('king_lear_act1_scene4',58,63,'KING LEAR','Do you bandy looks with me, you rascal? Striking him.'),
('king_lear_act1_scene4',59,64,'OSWALD','I’ll not be struck, my lord.'),
('king_lear_act1_scene4',60,65,'KENT','Nor tripped neither, you base football player. Tripping up his heels.'),
('king_lear_act1_scene4',61,66,'KING LEAR','I thank thee, fellow; thou servest me, and I’ll love thee.'),
('king_lear_act1_scene4',62,67,'KENT','Come, sir, arise, away! I’ll teach you differences: away, away! if you'),
('king_lear_act1_scene4',63,68,'KENT','will measure your lubber’s length again, tarry: but away! go to; have'),
('king_lear_act1_scene4',64,69,'KENT','you wisdom? so. Pushes Oswald out.'),
('king_lear_act1_scene4',65,70,'KING LEAR','Now, my friendly knave, I thank thee: there’s earnest of thy service.'),
('king_lear_act1_scene4',66,71,'FOOL','Let me hire him too: here’s my coxcomb.'),
('king_lear_act1_scene4',67,72,'KING LEAR','How now, my pretty knave! how dost thou?'),
('king_lear_act1_scene4',68,73,'FOOL','Sirrah, you were best take my coxcomb.'),
('king_lear_act1_scene4',69,74,'KENT','Why, fool?'),
('king_lear_act1_scene4',70,75,'FOOL','Why, for taking one’s part that’s out of favour: nay, an thou'),
('king_lear_act1_scene4',71,76,'FOOL','canst not smile as the wind sits, thou’lt catch cold shortly: there,'),
('king_lear_act1_scene4',72,77,'FOOL','take my coxcomb: why, this fellow has banished two on’s daughters, and'),
('king_lear_act1_scene4',73,78,'FOOL','did the third a blessing against his will; if thou follow him,'),
('king_lear_act1_scene4',74,79,'FOOL','thou must needs wear my coxcomb. How now, nuncle! Would I had'),
('king_lear_act1_scene4',75,80,'FOOL','two coxcombs and two daughters!'),
('king_lear_act1_scene4',75,81,'KING LEAR','Why, my boy?'),
('king_lear_act1_scene4',76,82,'FOOL','If I gave them all my living, I’ld keep my coxcombs myself.'),
('king_lear_act1_scene4',77,83,'FOOL','There’s mine; beg another of thy daughters.'),
('king_lear_act1_scene4',78,84,'KING LEAR','Take heed, sirrah; the whip.'),
('king_lear_act1_scene4',79,85,'FOOL','Truth’s a dog must to kennel; he must be whipped out, when'),
('king_lear_act1_scene4',80,86,'FOOL','Lady the brach may stand by the fire and stink.'),
('king_lear_act1_scene4',81,87,'KING LEAR','A pestilent gall to me!'),
('king_lear_act1_scene4',81,88,'FOOL','Sirrah, I’ll teach thee a speech.'),
('king_lear_act1_scene4',82,89,'KING LEAR','Do.'),
('king_lear_act1_scene4',82,90,'FOOL','Mark it, nuncle:'),
('king_lear_act1_scene4',83,91,'FOOL','Have more than thou showest,'),
('king_lear_act1_scene4',84,92,'FOOL','Speak less than thou knowest,'),
('king_lear_act1_scene4',85,93,'FOOL','Lend less than thou owest,'),
('king_lear_act1_scene4',86,94,'FOOL','Ride more than thou goest,'),
('king_lear_act1_scene4',87,95,'FOOL','Learn more than thou trowest,'),
('king_lear_act1_scene4',88,96,'FOOL','Set less than thou throwest;'),
('king_lear_act1_scene4',89,97,'FOOL','Leave thy drink and thy whore,'),
('king_lear_act1_scene4',90,98,'FOOL','And keep in-a-door,'),
('king_lear_act1_scene4',91,99,'FOOL','And thou shalt have more'),
('king_lear_act1_scene4',92,100,'FOOL','Than two tens to a score.'),
('king_lear_act1_scene4',92,101,'KENT','This is nothing, fool.'),
('king_lear_act1_scene4',93,102,'FOOL','Then ’tis like the breath of an unfee’d lawyer; you gave me'),
('king_lear_act1_scene4',94,103,'FOOL','nothing for’t. Can you make no use of nothing, nuncle?'),
('king_lear_act1_scene4',95,104,'KING LEAR','Why, no, boy; nothing can be made out of nothing.'),
('king_lear_act1_scene4',96,105,'FOOL','To Kent. Prithee, tell him, so much the rent of his land'),
('king_lear_act1_scene4',97,106,'FOOL','comes to: he will not believe a fool.'),
('king_lear_act1_scene4',98,107,'KING LEAR','A bitter fool!'),
('king_lear_act1_scene4',99,108,'FOOL','Dost thou know the difference, my boy, between a bitter fool and a sweet fool?'),
('king_lear_act1_scene4',100,109,'KING LEAR','No, lad; teach me.'),
('king_lear_act1_scene4',100,110,'FOOL','That lord that counsell’d thee'),
('king_lear_act1_scene4',101,111,'FOOL','To give away thy land,'),
('king_lear_act1_scene4',102,112,'FOOL','Come place him here by me,'),
('king_lear_act1_scene4',103,113,'FOOL','Do thou for him stand:'),
('king_lear_act1_scene4',104,114,'FOOL','The sweet and bitter fool'),
('king_lear_act1_scene4',105,115,'FOOL','Will presently appear;'),
('king_lear_act1_scene4',106,116,'FOOL','The one in motley here,'),
('king_lear_act1_scene4',107,117,'FOOL','The other found out there.'),
('king_lear_act1_scene4',107,118,'KING LEAR','Dost thou call me fool, boy?'),
('king_lear_act1_scene4',108,119,'FOOL','All thy other titles thou hast given away; that thou wast born with.'),
('king_lear_act1_scene4',109,120,'KENT','This is not altogether fool, my lord.'),
('king_lear_act1_scene4',110,121,'FOOL','No, faith, lords and great men will not let me; if I'),
('king_lear_act1_scene4',111,122,'FOOL','had a monopoly out, they would have part on’t: and ladies too,'),
('king_lear_act1_scene4',112,123,'FOOL','they will not let me have all fool to myself; they’ll be'),
('king_lear_act1_scene4',113,124,'FOOL','snatching. Give me an egg, nuncle, and I’ll give thee two crowns.'),
('king_lear_act1_scene4',114,125,'KING LEAR','What two crowns shall they be?'),
('king_lear_act1_scene4',115,126,'FOOL','Why, after I have cut the egg i’ the middle, and eat'),
('king_lear_act1_scene4',116,127,'FOOL','up the meat, the two crowns of the egg. When thou clovest'),
('king_lear_act1_scene4',117,128,'FOOL','thy crown i’ the middle, and gavest away both parts, thou borest'),
('king_lear_act1_scene4',118,129,'FOOL','thy ass on thy back o’er the dirt: thou hadst little wit'),
('king_lear_act1_scene4',119,130,'FOOL','in thy bald crown, when thou gavest thy golden one away. If'),
('king_lear_act1_scene4',120,131,'FOOL','I speak like myself in this, let him be whipped that first'),
('king_lear_act1_scene4',121,132,'FOOL','finds it so.'),
('king_lear_act1_scene4',122,133,'KING LEAR','When were you wont to be so full of songs, sirrah?'),
('king_lear_act1_scene4',123,134,'FOOL','I have used it, nuncle, ever since thou madest thy daughters thy'),
('king_lear_act1_scene4',124,135,'FOOL','mothers: for when thou gavest them the rod, and put’st down thine'),
('king_lear_act1_scene4',125,136,'FOOL','own breeches,'),
('king_lear_act1_scene4',126,137,'KING LEAR','An you lie, sirrah, we’ll have you whipped.'),
('king_lear_act1_scene4',127,138,'FOOL','I marvel what kin thou and thy daughters are: they’ll have me'),
('king_lear_act1_scene4',128,139,'FOOL','whipped for speaking true, thou’lt have me whipped for lying; and sometimes'),
('king_lear_act1_scene4',129,140,'FOOL','I am whipped for holding my peace. I had rather be any'),
('king_lear_act1_scene4',130,141,'FOOL','kind o’ thing than a fool: and yet I would not be'),
('king_lear_act1_scene4',131,142,'FOOL','thee, nuncle; thou hast pared thy wit o’ both sides, and left'),
('king_lear_act1_scene4',132,143,'FOOL','nothing i’ the middle: here comes one o’ the parings.'),
('king_lear_act1_scene4',133,144,'KING LEAR','How now, daughter! what makes that frontlet on? Methinks you are too'),
('king_lear_act1_scene4',134,145,'KING LEAR','much of late i’ the frown.'),
('king_lear_act1_scene4',135,146,'FOOL','Thou wast a pretty fellow when thou hadst no need to care'),
('king_lear_act1_scene4',136,147,'FOOL','for her frowning; now thou art an O without a figure: I'),
('king_lear_act1_scene4',137,148,'FOOL','am better than thou art now; I am a fool, thou art'),
('king_lear_act1_scene4',138,149,'FOOL','nothing. To Goneril. Yes, forsooth, I will hold my tongue; so your'),
('king_lear_act1_scene4',139,150,'FOOL','face bids me, though you say nothing.'),
('king_lear_act1_scene4',140,151,'GONERIL','Not only, sir, this your all-licensed fool,'),
('king_lear_act1_scene4',141,152,'GONERIL','But other of your insolent retinue'),
('king_lear_act1_scene4',142,153,'GONERIL','Do hourly carp and quarrel; breaking forth'),
('king_lear_act1_scene4',143,154,'GONERIL','In rank and not-to-be endured riots. Sir,'),
('king_lear_act1_scene4',144,155,'GONERIL','I had thought, by making this well known unto you,'),
('king_lear_act1_scene4',145,156,'GONERIL','To have found a safe redress; but now grow fearful,'),
('king_lear_act1_scene4',146,157,'GONERIL','By what yourself too late have spoke and done.'),
('king_lear_act1_scene4',147,158,'GONERIL','That you protect this course, and put it on'),
('king_lear_act1_scene4',148,159,'GONERIL','By your allowance; which if you should, the fault'),
('king_lear_act1_scene4',149,160,'GONERIL','Would not ’scape censure, nor the redresses sleep,'),
('king_lear_act1_scene4',150,161,'GONERIL','Which, in the tender of a wholesome weal,'),
('king_lear_act1_scene4',151,162,'GONERIL','Might in their working do you that offence,'),
('king_lear_act1_scene4',152,163,'GONERIL','Which else were shame, that then necessity'),
('king_lear_act1_scene4',153,164,'GONERIL','Will call discreet proceeding.'),
('king_lear_act1_scene4',153,165,'FOOL','For, you trow, nuncle,'),
('king_lear_act1_scene4',154,166,'FOOL','The hedge-sparrow fed the cuckoo so long,'),
('king_lear_act1_scene4',155,167,'FOOL','That it’s had it head bit off by it young.'),
('king_lear_act1_scene4',156,168,'FOOL','So, out went the candle, and we were left darkling.'),
('king_lear_act1_scene4',157,169,'KING LEAR','Are you our daughter?'),
('king_lear_act1_scene4',157,170,'GONERIL','Come, sir,'),
('king_lear_act1_scene4',158,171,'GONERIL','I would you would make use of that good wisdom,'),
('king_lear_act1_scene4',159,172,'GONERIL','Whereof I know you are fraught; and put away'),
('king_lear_act1_scene4',160,173,'GONERIL','These dispositions, that of late transform you'),
('king_lear_act1_scene4',161,174,'GONERIL','From what you rightly are.'),
('king_lear_act1_scene4',162,175,'FOOL','May not an ass know when the cart draws the horse? Whoop,'),
('king_lear_act1_scene4',163,176,'FOOL','Jug! I love thee.'),
('king_lear_act1_scene4',164,177,'KING LEAR','Doth any here know me? This is not Lear:'),
('king_lear_act1_scene4',165,178,'KING LEAR','Doth Lear walk thus? speak thus? Where are his eyes?'),
('king_lear_act1_scene4',166,179,'KING LEAR','Either his notion weakens, his discernings'),
('king_lear_act1_scene4',167,180,'KING LEAR','Are lethargied—Ha! waking? ’tis not so.'),
('king_lear_act1_scene4',168,181,'KING LEAR','Who is it that can tell me who I am?'),
('king_lear_act1_scene4',169,182,'FOOL','Lear’s shadow.'),
('king_lear_act1_scene4',170,183,'KING LEAR','I would learn that; for, by the marks of sovereignty, knowledge, and'),
('king_lear_act1_scene4',171,184,'KING LEAR','reason, I should be false persuaded I had daughters.'),
('king_lear_act1_scene4',172,185,'FOOL','Which they will make an obedient father.'),
('king_lear_act1_scene4',173,186,'KING LEAR','Your name, fair gentlewoman?'),
('king_lear_act1_scene4',174,187,'GONERIL','This admiration, sir, is much o’ the savour'),
('king_lear_act1_scene4',175,188,'GONERIL','Of other your new pranks. I do beseech you'),
('king_lear_act1_scene4',176,189,'GONERIL','To understand my purposes aright:'),
('king_lear_act1_scene4',177,190,'GONERIL','As you are old and reverend, you should be wise.'),
('king_lear_act1_scene4',178,191,'GONERIL','Here do you keep a hundred knights and squires;'),
('king_lear_act1_scene4',179,192,'GONERIL','Men so disorder’d, so debosh’d and bold,'),
('king_lear_act1_scene4',180,193,'GONERIL','That this our court, infected with their manners,'),
('king_lear_act1_scene4',181,194,'GONERIL','Shows like a riotous inn: epicurism and lust'),
('king_lear_act1_scene4',182,195,'GONERIL','Make it more like a tavern or a brothel'),
('king_lear_act1_scene4',183,196,'GONERIL','Than a graced palace. The shame itself doth speak'),
('king_lear_act1_scene4',184,197,'GONERIL','For instant remedy: be then desired'),
('king_lear_act1_scene4',185,198,'GONERIL','By her, that else will take the thing she begs,'),
('king_lear_act1_scene4',186,199,'GONERIL','A little to disquantity your train;'),
('king_lear_act1_scene4',187,200,'GONERIL','And the remainder, that shall still depend,'),
('king_lear_act1_scene4',188,201,'GONERIL','To be such men as may besort your age,'),
('king_lear_act1_scene4',189,202,'GONERIL','And know themselves and you.'),
('king_lear_act1_scene4',189,203,'KING LEAR','Darkness and devils!'),
('king_lear_act1_scene4',190,204,'KING LEAR','Saddle my horses; call my train together:'),
('king_lear_act1_scene4',191,205,'KING LEAR','Degenerate bastard! I’ll not trouble thee.'),
('king_lear_act1_scene4',192,206,'KING LEAR','Yet have I left a daughter.'),
('king_lear_act1_scene4',193,207,'GONERIL','You strike my people; and your disorder’d rabble'),
('king_lear_act1_scene4',194,208,'GONERIL','Make servants of their betters.'),
('king_lear_act1_scene4',194,209,'KING LEAR','Woe, that too late repents—'),
('king_lear_act1_scene4',195,210,'KING LEAR','To Albany. O, sir, are you come?'),
('king_lear_act1_scene4',196,211,'KING LEAR','Is it your will? Speak, sir. Prepare my horses.'),
('king_lear_act1_scene4',197,212,'KING LEAR','Ingratitude, thou marble-hearted fiend,'),
('king_lear_act1_scene4',198,213,'KING LEAR','More hideous when thou show’st thee in a child'),
('king_lear_act1_scene4',199,214,'KING LEAR','Than the sea-monster!'),
('king_lear_act1_scene4',199,215,'ALBANY','Pray, sir, be patient.'),
('king_lear_act1_scene4',200,216,'KING LEAR','To Goneril. Detested kite! thou liest.'),
('king_lear_act1_scene4',201,217,'KING LEAR','My train are men of choice and rarest parts,'),
('king_lear_act1_scene4',202,218,'KING LEAR','That all particulars of duty know,'),
('king_lear_act1_scene4',203,219,'KING LEAR','And in the most exact regard support'),
('king_lear_act1_scene4',204,220,'KING LEAR','The worships of their name. O most small fault,'),
('king_lear_act1_scene4',205,221,'KING LEAR','How ugly didst thou in Cordelia show!'),
('king_lear_act1_scene4',206,222,'KING LEAR','That, like an engine, wrench’d my frame of nature'),
('king_lear_act1_scene4',207,223,'KING LEAR','From the fix’d place; drew from heart all love,'),
('king_lear_act1_scene4',208,224,'KING LEAR','And added to the gall. O Lear, Lear, Lear!'),
('king_lear_act1_scene4',209,225,'KING LEAR','Beat at this gate, that let thy folly in, Striking his head.'),
('king_lear_act1_scene4',210,226,'KING LEAR','And thy dear judgment out! Go, go, my people.'),
('king_lear_act1_scene4',211,227,'ALBANY','My lord, I am guiltless, as I am ignorant'),
('king_lear_act1_scene4',212,228,'ALBANY','Of what hath moved you.'),
('king_lear_act1_scene4',212,229,'KING LEAR','It may be so, my lord.'),
('king_lear_act1_scene4',213,230,'KING LEAR','Hear, nature, hear; dear goddess, hear!'),
('king_lear_act1_scene4',214,231,'KING LEAR','Suspend thy purpose, if thou didst intend'),
('king_lear_act1_scene4',215,232,'KING LEAR','To make this creature fruitful!'),
('king_lear_act1_scene4',216,233,'KING LEAR','Into her womb convey sterility!'),
('king_lear_act1_scene4',217,234,'KING LEAR','Dry up in her the organs of increase;'),
('king_lear_act1_scene4',218,235,'KING LEAR','And from her derogate body never spring'),
('king_lear_act1_scene4',219,236,'KING LEAR','A babe to honour her! If she must teem,'),
('king_lear_act1_scene4',220,237,'KING LEAR','Create her child of spleen; that it may live,'),
('king_lear_act1_scene4',221,238,'KING LEAR','And be a thwart disnatured torment to her!'),
('king_lear_act1_scene4',222,239,'KING LEAR','Let it stamp wrinkles in her brow of youth;'),
('king_lear_act1_scene4',223,240,'KING LEAR','With cadent tears fret channels in her cheeks;'),
('king_lear_act1_scene4',224,241,'KING LEAR','Turn all her mother’s pains and benefits'),
('king_lear_act1_scene4',225,242,'KING LEAR','To laughter and contempt; that she may feel'),
('king_lear_act1_scene4',226,243,'KING LEAR','How sharper than a serpent’s tooth it is'),
('king_lear_act1_scene4',227,244,'KING LEAR','To have a thankless child! Away, away!'),
('king_lear_act1_scene4',228,245,'ALBANY','Now, gods that we adore, whereof comes this?'),
('king_lear_act1_scene4',229,246,'GONERIL','Never afflict yourself to know the cause;'),
('king_lear_act1_scene4',230,247,'GONERIL','But let his disposition have that scope'),
('king_lear_act1_scene4',231,248,'GONERIL','That dotage gives it.'),
('king_lear_act1_scene4',232,249,'KING LEAR','What, fifty of my followers at a clap!'),
('king_lear_act1_scene4',233,250,'KING LEAR','Within a fortnight!'),
('king_lear_act1_scene4',233,251,'ALBANY','What’s the matter, sir?'),
('king_lear_act1_scene4',234,252,'KING LEAR','I’ll tell thee: To Goneril.'),
('king_lear_act1_scene4',235,253,'KING LEAR','Life and death! I am ashamed'),
('king_lear_act1_scene4',236,254,'KING LEAR','That thou hast power to shake my manhood thus;'),
('king_lear_act1_scene4',237,255,'KING LEAR','That these hot tears, which break from me perforce,'),
('king_lear_act1_scene4',238,256,'KING LEAR','Should make thee worth them. Blasts and fogs upon thee!'),
('king_lear_act1_scene4',239,257,'KING LEAR','The untented woundings of a father’s curse'),
('king_lear_act1_scene4',240,258,'KING LEAR','Pierce every sense about thee! Old fond eyes,'),
('king_lear_act1_scene4',241,259,'KING LEAR','Beweep this cause again, I’ll pluck ye out,'),
('king_lear_act1_scene4',242,260,'KING LEAR','And cast you, with the waters that you lose,'),
('king_lear_act1_scene4',243,261,'KING LEAR','To temper clay. Yea, it is come to this?'),
('king_lear_act1_scene4',244,262,'KING LEAR','Let it be so: yet have I left a daughter,'),
('king_lear_act1_scene4',245,263,'KING LEAR','Who, I am sure, is kind and comfortable:'),
('king_lear_act1_scene4',246,264,'KING LEAR','When she shall hear this of thee, with her nails'),
('king_lear_act1_scene4',247,265,'KING LEAR','She’ll flay thy wolvish visage. Thou shalt find'),
('king_lear_act1_scene4',248,266,'KING LEAR','That I’ll resume the shape which thou dost think'),
('king_lear_act1_scene4',249,267,'KING LEAR','I have cast off for ever: thou shalt,'),
('king_lear_act1_scene4',250,268,'KING LEAR','I warrant thee.'),
('king_lear_act1_scene4',250,269,'GONERIL','Do you mark that, my lord?'),
('king_lear_act1_scene4',251,270,'ALBANY','I cannot be so partial, Goneril,'),
('king_lear_act1_scene4',252,271,'ALBANY','To the great love I bear you—'),
('king_lear_act1_scene4',253,272,'GONERIL','Pray you, content. What, Oswald, ho! To the Fool. You, sir, more'),
('king_lear_act1_scene4',254,273,'GONERIL','knave than fool, after your master.'),
('king_lear_act1_scene4',255,274,'FOOL','Nuncle Lear, nuncle Lear, tarry and take the fool'),
('king_lear_act1_scene4',256,275,'FOOL','with thee.'),
('king_lear_act1_scene4',257,276,'FOOL','A fox, when one has caught her,'),
('king_lear_act1_scene4',258,277,'FOOL','And such a daughter,'),
('king_lear_act1_scene4',259,278,'FOOL','Should sure to the slaughter,'),
('king_lear_act1_scene4',260,279,'FOOL','If my cap would buy a halter:'),
('king_lear_act1_scene4',261,280,'FOOL','So the fool follows after.'),
('king_lear_act1_scene4',262,281,'GONERIL','This man hath had good counsel:—a hundred knights!'),
('king_lear_act1_scene4',263,282,'GONERIL','’Tis politic and safe to let him keep'),
('king_lear_act1_scene4',264,283,'GONERIL','At point a hundred knights: yes, that, on every dream,'),
('king_lear_act1_scene4',265,284,'GONERIL','Each buzz, each fancy, each complaint, dislike,'),
('king_lear_act1_scene4',266,285,'GONERIL','He may enguard his dotage with their powers,'),
('king_lear_act1_scene4',267,286,'GONERIL','And hold our lives in mercy. Oswald, I say!'),
('king_lear_act1_scene4',268,287,'ALBANY','Well, you may fear too far.'),
('king_lear_act1_scene4',268,288,'GONERIL','Safer than trust too far:'),
('king_lear_act1_scene4',269,289,'GONERIL','Let me still take away the harms I fear,'),
('king_lear_act1_scene4',270,290,'GONERIL','Not fear still to be taken: I know his heart.'),
('king_lear_act1_scene4',271,291,'GONERIL','What he hath utter’d I have writ my sister'),
('king_lear_act1_scene4',272,292,'GONERIL','If she sustain him and his hundred knights'),
('king_lear_act1_scene4',273,293,'GONERIL','When I have show’d the unfitness—'),
('king_lear_act1_scene4',273,294,'OSWALD','Yes, madam.'),
('king_lear_act1_scene4',274,295,'GONERIL','Take you some company, and away to horse:'),
('king_lear_act1_scene4',275,296,'GONERIL','Inform her full of my particular fear;'),
('king_lear_act1_scene4',276,297,'GONERIL','And thereto add such reasons of your own'),
('king_lear_act1_scene4',277,298,'GONERIL','As may compact it more. Get you gone;'),
('king_lear_act1_scene4',278,299,'GONERIL','And hasten your return.'),
('king_lear_act1_scene4',279,300,'ALBANY','How far your eyes may pierce I can not tell:'),
('king_lear_act1_scene4',280,301,'ALBANY','Striving to better, oft we mar what’s well.'),
('king_lear_act1_scene4',281,302,'GONERIL','Nay, then—'),
('king_lear_act1_scene4',281,303,'ALBANY','Well, well; the event.'),
('king_lear_act1_scene5',1,0,'KING LEAR','Go you before to Gloucester with these letters.'),
('king_lear_act1_scene5',2,1,'KING LEAR','Acquaint my daughter no further with any thing you'),
('king_lear_act1_scene5',3,2,'KING LEAR','know than comes from her demand out of the letter.'),
('king_lear_act1_scene5',4,3,'KING LEAR','If your diligence be not speedy, I shall be there afore you.'),
('king_lear_act1_scene5',5,4,'KENT','I will not sleep, my lord, till I have delivered your letter.'),
('king_lear_act1_scene5',6,5,'FOOL','If a man’s brains were in’s heels, were’t not in danger of kibes?'),
('king_lear_act1_scene5',7,6,'KING LEAR','Ay, boy.'),
('king_lear_act1_scene5',8,7,'FOOL','Then, I prithee, be merry; thy wit shall ne’er go slip-shod.'),
('king_lear_act1_scene5',9,8,'KING LEAR','Ha, ha, ha!');
INSERT INTO lines (section_id,number,array_index,speaker,text) VALUES
('king_lear_act1_scene5',10,9,'FOOL','Shalt see thy other daughter will use thee kindly; for though she’s'),
('king_lear_act1_scene5',11,10,'FOOL','as like this as a crab’s like an apple, yet I can'),
('king_lear_act1_scene5',12,11,'FOOL','tell what I can tell.'),
('king_lear_act1_scene5',13,12,'KING LEAR','Why, what canst thou tell, my boy?'),
('king_lear_act1_scene5',14,13,'FOOL','She will taste as like this as a crab does to a'),
('king_lear_act1_scene5',15,14,'FOOL','crab. Thou canst tell why one’s nose stands i’ the middle on’s'),
('king_lear_act1_scene5',16,15,'FOOL','face?'),
('king_lear_act1_scene5',16,16,'KING LEAR','No.'),
('king_lear_act1_scene5',17,17,'FOOL','Why, to keep one’s eyes of either side’s nose; that what a'),
('king_lear_act1_scene5',18,18,'FOOL','man cannot smell out, he may spy into.'),
('king_lear_act1_scene5',19,19,'KING LEAR','I did her wrong—'),
('king_lear_act1_scene5',20,20,'FOOL','Canst tell how an oyster makes his shell?'),
('king_lear_act1_scene5',21,21,'KING LEAR','No.'),
('king_lear_act1_scene5',22,22,'FOOL','Nor I neither; but I can tell why a snail has a house.'),
('king_lear_act1_scene5',23,23,'KING LEAR','Why?'),
('king_lear_act1_scene5',24,24,'FOOL','Why, to put his head in; not to give it away to'),
('king_lear_act1_scene5',25,25,'FOOL','his daughters, and leave his horns without a case.'),
('king_lear_act1_scene5',26,26,'KING LEAR','I will forget my nature. So kind a father! Be my horses ready?'),
('king_lear_act1_scene5',27,27,'FOOL','Thy asses are gone about ’em. The reason why the seven stars'),
('king_lear_act1_scene5',28,28,'FOOL','are no more than seven is a pretty reason.'),
('king_lear_act1_scene5',29,29,'KING LEAR','Because they are not eight?'),
('king_lear_act1_scene5',30,30,'FOOL','Yes, indeed: thou wouldst make a good fool.'),
('king_lear_act1_scene5',31,31,'KING LEAR','To take ’t again perforce! Monster ingratitude!'),
('king_lear_act1_scene5',32,32,'FOOL','If thou wert my fool, nuncle, I’ld have thee beaten for being'),
('king_lear_act1_scene5',33,33,'FOOL','old before thy time.'),
('king_lear_act1_scene5',33,34,'KING LEAR','How’s that?'),
('king_lear_act1_scene5',34,35,'FOOL','Thou shouldst not have been old till thou hadst been wise.'),
('king_lear_act1_scene5',35,36,'KING LEAR','O, let me not be mad, not mad, sweet heaven!'),
('king_lear_act1_scene5',36,37,'KING LEAR','Keep me in temper: I would not be mad!'),
('king_lear_act1_scene5',37,38,'GENTLEMAN','Ready, my lord.'),
('king_lear_act1_scene5',37,39,'KING LEAR','Come, boy.'),
('king_lear_act1_scene5',38,40,'FOOL','She that’s a maid now, and laughs at my departure,'),
('king_lear_act1_scene5',39,41,'FOOL','Shall not be a maid long, unless things be cut shorter.'),
('king_lear_act2_scene1',1,0,'EDMUND','Save thee, Curan.'),
('king_lear_act2_scene1',2,1,'CURAN','And you, sir. I have been with your father, and given him'),
('king_lear_act2_scene1',3,2,'CURAN','notice that the Duke of Cornwall and Regan his duchess will be'),
('king_lear_act2_scene1',4,3,'CURAN','here with him this night.'),
('king_lear_act2_scene1',4,4,'EDMUND','How comes that?'),
('king_lear_act2_scene1',5,5,'CURAN','Nay, I know not. You have heard of the news abroad; I'),
('king_lear_act2_scene1',6,6,'CURAN','mean the whispered ones, for they are yet but ear-kissing arguments?'),
('king_lear_act2_scene1',7,7,'EDMUND','Not I: pray you, what are they?'),
('king_lear_act2_scene1',8,8,'CURAN','Have you heard of no likely wars toward, ’twixt the Dukes of Cornwall and Albany?'),
('king_lear_act2_scene1',9,9,'EDMUND','Not a word.'),
('king_lear_act2_scene1',10,10,'CURAN','You may do, then, in time. Fare you well, sir.'),
('king_lear_act2_scene1',11,11,'EDMUND','The duke be here to-night? The better! best!'),
('king_lear_act2_scene1',12,12,'EDMUND','This weaves itself perforce into my business.'),
('king_lear_act2_scene1',13,13,'EDMUND','My father hath set guard to take my brother;'),
('king_lear_act2_scene1',14,14,'EDMUND','And I have one thing, of a queasy question,'),
('king_lear_act2_scene1',15,15,'EDMUND','Which I must act: briefness and fortune, work!'),
('king_lear_act2_scene1',16,16,'EDMUND','Brother, a word; descend: brother, I say!'),
('king_lear_act2_scene1',17,17,'EDGAR','I am sure on’t, not a word.'),
('king_lear_act2_scene1',18,18,'EDMUND','I hear my father coming: pardon me:'),
('king_lear_act2_scene1',19,19,'EDMUND','In cunning I must draw my sword upon you'),
('king_lear_act2_scene1',20,20,'EDMUND','Draw; seem to defend yourself; now quit you well.'),
('king_lear_act2_scene1',21,21,'EDMUND','Yield: come before my father. Light, ho, here!'),
('king_lear_act2_scene1',22,22,'EDMUND','Fly, brother. Torches, torches! So, farewell.'),
('king_lear_act2_scene1',23,23,'EDMUND','Some blood drawn on me would beget opinion. Wounds his arm.'),
('king_lear_act2_scene1',24,24,'EDMUND','Of my more fierce endeavour: I have seen drunkards'),
('king_lear_act2_scene1',25,25,'EDMUND','Do more than this in sport. Father, father!'),
('king_lear_act2_scene1',26,26,'EDMUND','Stop, stop! No help?'),
('king_lear_act2_scene1',26,27,'GLOUCESTER','Now, Edmund, where’s the villain?'),
('king_lear_act2_scene1',27,28,'EDMUND','Here stood he in the dark, his sharp sword out,'),
('king_lear_act2_scene1',28,29,'EDMUND','Mumbling of wicked charms, conjuring the moon'),
('king_lear_act2_scene1',29,30,'EDMUND','To stand auspicious mistress—'),
('king_lear_act2_scene1',29,31,'GLOUCESTER','But where is he?'),
('king_lear_act2_scene1',30,32,'EDMUND','Look, sir, I bleed.'),
('king_lear_act2_scene1',30,33,'GLOUCESTER','Where is the villain, Edmund?'),
('king_lear_act2_scene1',31,34,'EDMUND','Fled this way, sir. When by no means he could—'),
('king_lear_act2_scene1',32,35,'GLOUCESTER','Pursue him, ho! Go after. By no means what?'),
('king_lear_act2_scene1',33,36,'EDMUND','Persuade me to the murder of your lordship;'),
('king_lear_act2_scene1',34,37,'EDMUND','But that I told him, the revenging gods'),
('king_lear_act2_scene1',35,38,'EDMUND','’Gainst parricides did all their thunders bend;'),
('king_lear_act2_scene1',36,39,'EDMUND','Spoke, with how manifold and strong a bond'),
('king_lear_act2_scene1',37,40,'EDMUND','The child was bound to the father; sir, in fine,'),
('king_lear_act2_scene1',38,41,'EDMUND','Seeing how loathly opposite I stood'),
('king_lear_act2_scene1',39,42,'EDMUND','To his unnatural purpose, in fell motion,'),
('king_lear_act2_scene1',40,43,'EDMUND','With his prepared sword, he charges home'),
('king_lear_act2_scene1',41,44,'EDMUND','My unprovided body, lanced mine arm:'),
('king_lear_act2_scene1',42,45,'EDMUND','But when he saw my best alarum’d spirits,'),
('king_lear_act2_scene1',43,46,'EDMUND','Bold in the quarrel’s right, roused to the encounter,'),
('king_lear_act2_scene1',44,47,'EDMUND','Or whether gasted by the noise I made,'),
('king_lear_act2_scene1',45,48,'EDMUND','Full suddenly he fled.'),
('king_lear_act2_scene1',45,49,'GLOUCESTER','Let him fly far:'),
('king_lear_act2_scene1',46,50,'GLOUCESTER','Not in this land shall he remain uncaught;'),
('king_lear_act2_scene1',47,51,'GLOUCESTER','And found—dispatch. The noble duke my master,'),
('king_lear_act2_scene1',48,52,'GLOUCESTER','My worthy arch and patron, comes to-night:'),
('king_lear_act2_scene1',49,53,'GLOUCESTER','By his authority I will proclaim it,'),
('king_lear_act2_scene1',50,54,'GLOUCESTER','That he which finds him shall deserve our thanks,'),
('king_lear_act2_scene1',51,55,'GLOUCESTER','Bringing the murderous coward to the stake;'),
('king_lear_act2_scene1',52,56,'GLOUCESTER','He that conceals him, death.'),
('king_lear_act2_scene1',53,57,'EDMUND','When I dissuaded him from his intent,'),
('king_lear_act2_scene1',54,58,'EDMUND','And found him pight to do it, with curst speech'),
('king_lear_act2_scene1',55,59,'EDMUND','I threaten’d to discover him: he replied,'),
('king_lear_act2_scene1',56,60,'EDMUND','“Thou unpossessing bastard! dost thou think,'),
('king_lear_act2_scene1',57,61,'EDMUND','If I would stand against thee, would the reposal'),
('king_lear_act2_scene1',58,62,'EDMUND','Of any trust, virtue, or worth in thee'),
('king_lear_act2_scene1',59,63,'EDMUND','Make thy words faith’d? No: what I should deny—'),
('king_lear_act2_scene1',60,64,'EDMUND','As this I would: ay, though thou didst produce'),
('king_lear_act2_scene1',61,65,'EDMUND','My very character—I’ld turn it all'),
('king_lear_act2_scene1',62,66,'EDMUND','To thy suggestion, plot, and damned practise:'),
('king_lear_act2_scene1',63,67,'EDMUND','And thou must make a dullard of the world,'),
('king_lear_act2_scene1',64,68,'EDMUND','If they not thought the profits of my death'),
('king_lear_act2_scene1',65,69,'EDMUND','Were very pregnant and potential spurs'),
('king_lear_act2_scene1',66,70,'EDMUND','To make thee seek it.”'),
('king_lear_act2_scene1',66,71,'GLOUCESTER','Strong and fasten’d villain'),
('king_lear_act2_scene1',67,72,'GLOUCESTER','Would he deny his letter? I never got him. Tucket within.'),
('king_lear_act2_scene1',68,73,'GLOUCESTER','Hark, the duke’s trumpets! I know not why he comes.'),
('king_lear_act2_scene1',69,74,'GLOUCESTER','All ports I’ll bar; the villain shall not ’scape;'),
('king_lear_act2_scene1',70,75,'GLOUCESTER','The duke must grant me that: besides, his picture'),
('king_lear_act2_scene1',71,76,'GLOUCESTER','I will send far and near, that all the kingdom'),
('king_lear_act2_scene1',72,77,'GLOUCESTER','May have the due note of him; and of my land,'),
('king_lear_act2_scene1',73,78,'GLOUCESTER','Loyal and natural boy, I’ll work the means'),
('king_lear_act2_scene1',74,79,'GLOUCESTER','To make thee capable.'),
('king_lear_act2_scene1',75,80,'CORNWALL','How now, my noble friend! since I came hither,'),
('king_lear_act2_scene1',76,81,'CORNWALL','Which I can call but now, I have heard strange news.'),
('king_lear_act2_scene1',77,82,'REGAN','If it be true, all vengeance comes too short'),
('king_lear_act2_scene1',78,83,'REGAN','Which can pursue the offender. How dost, my lord?'),
('king_lear_act2_scene1',79,84,'GLOUCESTER','O, madam, my old heart is crack’d, it’s crack’d!'),
('king_lear_act2_scene1',80,85,'REGAN','What, did my father’s godson seek your life?'),
('king_lear_act2_scene1',81,86,'REGAN','He whom my father named? your Edgar?'),
('king_lear_act2_scene1',82,87,'GLOUCESTER','O, lady, lady, shame would have it hid!'),
('king_lear_act2_scene1',83,88,'REGAN','Was he not companion with the riotous knights'),
('king_lear_act2_scene1',84,89,'REGAN','That tend upon my father?'),
('king_lear_act2_scene1',85,90,'GLOUCESTER','I know not, madam: ’tis too bad, too bad.'),
('king_lear_act2_scene1',86,91,'EDMUND','Yes, madam, he was of that consort.'),
('king_lear_act2_scene1',87,92,'REGAN','No marvel, then, though he were ill affected:'),
('king_lear_act2_scene1',88,93,'REGAN','’Tis they have put him on the old man’s death,'),
('king_lear_act2_scene1',89,94,'REGAN','To have the expense and waste of his revenues.'),
('king_lear_act2_scene1',90,95,'REGAN','I have this present evening from my sister'),
('king_lear_act2_scene1',91,96,'REGAN','Been well inform’d of them; and with such cautions,'),
('king_lear_act2_scene1',92,97,'REGAN','That if they come to sojourn at my house,'),
('king_lear_act2_scene1',93,98,'REGAN','I’ll not be there.'),
('king_lear_act2_scene1',93,99,'CORNWALL','Nor I, assure thee, Regan.'),
('king_lear_act2_scene1',94,100,'CORNWALL','Edmund, I hear that you have shown your father'),
('king_lear_act2_scene1',95,101,'CORNWALL','A child-like office.'),
('king_lear_act2_scene1',95,102,'EDMUND','’Twas my duty, sir.'),
('king_lear_act2_scene1',96,103,'GLOUCESTER','He did bewray his practise; and received'),
('king_lear_act2_scene1',97,104,'GLOUCESTER','This hurt you see, striving to apprehend him.'),
('king_lear_act2_scene1',98,105,'CORNWALL','Is he pursued?'),
('king_lear_act2_scene1',98,106,'GLOUCESTER','Ay, my good lord.'),
('king_lear_act2_scene1',99,107,'CORNWALL','If he be taken, he shall never more'),
('king_lear_act2_scene1',100,108,'CORNWALL','Be fear’d of doing harm: make your own purpose,'),
('king_lear_act2_scene1',101,109,'CORNWALL','How in my strength you please. For you, Edmund,'),
('king_lear_act2_scene1',102,110,'CORNWALL','Whose virtue and obedience doth this instant'),
('king_lear_act2_scene1',103,111,'CORNWALL','So much commend itself, you shall be ours:'),
('king_lear_act2_scene1',104,112,'CORNWALL','Natures of such deep trust we shall much need;'),
('king_lear_act2_scene1',105,113,'CORNWALL','You we first seize on.'),
('king_lear_act2_scene1',105,114,'EDMUND','I shall serve you, sir,'),
('king_lear_act2_scene1',106,115,'EDMUND','Truly, however else.'),
('king_lear_act2_scene1',106,116,'GLOUCESTER','For him I thank your grace.'),
('king_lear_act2_scene1',107,117,'CORNWALL','You know not why we came to visit you—'),
('king_lear_act2_scene1',108,118,'REGAN','Thus out of season, threading dark-eyed night:'),
('king_lear_act2_scene1',109,119,'REGAN','Occasions, noble Gloucester, of some poise,'),
('king_lear_act2_scene1',110,120,'REGAN','Wherein we must have use of your advice:'),
('king_lear_act2_scene1',111,121,'REGAN','Our father he hath writ, so hath our sister,'),
('king_lear_act2_scene1',112,122,'REGAN','Of differences, which I least thought it fit'),
('king_lear_act2_scene1',113,123,'REGAN','To answer from our home; the several messengers'),
('king_lear_act2_scene1',114,124,'REGAN','From hence attend dispatch. Our good old friend,'),
('king_lear_act2_scene1',115,125,'REGAN','Lay comforts to your bosom; and bestow'),
('king_lear_act2_scene1',116,126,'REGAN','Your needful counsel to our business,'),
('king_lear_act2_scene1',117,127,'REGAN','Which craves the instant use.'),
('king_lear_act2_scene1',117,128,'GLOUCESTER','I serve you, madam:'),
('king_lear_act2_scene1',118,129,'GLOUCESTER','Your graces are right welcome.'),
('king_lear_act2_scene2',1,0,'OSWALD','Good dawning to thee, friend: art of this house?'),
('king_lear_act2_scene2',2,1,'KENT','Ay.'),
('king_lear_act2_scene2',2,2,'OSWALD','Where may we set our horses?'),
('king_lear_act2_scene2',3,3,'KENT','I’ the mire.'),
('king_lear_act2_scene2',4,4,'OSWALD','Prithee, if thou lovest me, tell me.'),
('king_lear_act2_scene2',5,5,'KENT','I love thee not.'),
('king_lear_act2_scene2',6,6,'OSWALD','Why, then, I care not for thee.'),
('king_lear_act2_scene2',7,7,'KENT','If I had thee in Lipsbury pinfold, I would make thee care for me.'),
('king_lear_act2_scene2',8,8,'OSWALD','Why dost thou use me thus? I know thee not.'),
('king_lear_act2_scene2',9,9,'KENT','Fellow, I know thee.'),
('king_lear_act2_scene2',9,10,'OSWALD','What dost thou know me for?'),
('king_lear_act2_scene2',10,11,'KENT','A knave; a rascal; an eater of broken meats; a base, proud,'),
('king_lear_act2_scene2',11,12,'KENT','shallow, beggarly, three-suited, hundred-pound, filthy, worsted-stocking knave; a lily-livered, action-taking knave, a'),
('king_lear_act2_scene2',12,13,'KENT','whoreson, glass-gazing, super-serviceable finical rogue; one-trunk-inheriting slave; one that wouldst be a'),
('king_lear_act2_scene2',13,14,'KENT','bawd, in way of good service, and art nothing but the composition'),
('king_lear_act2_scene2',14,15,'KENT','of a knave, beggar, coward, pandar, and the son and heir of'),
('king_lear_act2_scene2',15,16,'KENT','a mongrel bitch: one whom I will beat into clamorous whining, if'),
('king_lear_act2_scene2',16,17,'KENT','thou deniest the least syllable of thy addition.'),
('king_lear_act2_scene2',17,18,'OSWALD','Why, what a monstrous fellow art thou, thus to rail on one'),
('king_lear_act2_scene2',18,19,'OSWALD','that is neither known of thee nor knows thee!'),
('king_lear_act2_scene2',19,20,'KENT','What a brazen-faced varlet art thou, to deny thou knowest me! Is'),
('king_lear_act2_scene2',20,21,'KENT','it two days ago since I tripped up thy heels, and beat'),
('king_lear_act2_scene2',21,22,'KENT','thee before the king? Draw, you rogue: for, though it be night,'),
('king_lear_act2_scene2',22,23,'KENT','yet the moon shines; I’ll make a sop o’ the moonshine of'),
('king_lear_act2_scene2',23,24,'KENT','you: draw, you whoreson cullionly barber-monger, draw.'),
('king_lear_act2_scene2',24,25,'OSWALD','Away! I have nothing to do with thee.'),
('king_lear_act2_scene2',25,26,'KENT','Draw, you rascal: you come with letters against the king; and take'),
('king_lear_act2_scene2',26,27,'KENT','vanity the puppet’s part against the royalty of her father: draw, you'),
('king_lear_act2_scene2',27,28,'KENT','rogue, or I’ll so carbonado your shanks: draw, you rascal; come your'),
('king_lear_act2_scene2',28,29,'KENT','ways.'),
('king_lear_act2_scene2',28,30,'OSWALD','Help, ho! murder! help!'),
('king_lear_act2_scene2',29,31,'KENT','Strike, you slave; stand, rogue, stand; you neat slave, strike. Beating him.'),
('king_lear_act2_scene2',30,32,'OSWALD','Help, ho! murder! murder!'),
('king_lear_act2_scene2',30,33,'EDMUND','How now! What’s the matter?'),
('king_lear_act2_scene2',31,34,'KENT','With you, goodman boy, an you please: come, I’ll flesh ye; come on, young master.'),
('king_lear_act2_scene2',32,35,'GLOUCESTER','Weapons! arms! What’s the matter here?'),
('king_lear_act2_scene2',33,36,'CORNWALL','Keep peace, upon your lives: He dies that strikes again. What is the matter?'),
('king_lear_act2_scene2',34,37,'REGAN','The messengers from our sister and the king.'),
('king_lear_act2_scene2',35,38,'CORNWALL','What is your difference? speak.'),
('king_lear_act2_scene2',36,39,'OSWALD','I am scarce in breath, my lord.'),
('king_lear_act2_scene2',37,40,'KENT','No marvel, you have so bestirred your valour. You cowardly rascal, nature'),
('king_lear_act2_scene2',38,41,'KENT','disclaims in thee: a tailor made thee.'),
('king_lear_act2_scene2',39,42,'CORNWALL','Thou art a strange fellow: a tailor make a man?'),
('king_lear_act2_scene2',40,43,'KENT','Ay, a tailor, sir: a stone-cutter or painter could not have made'),
('king_lear_act2_scene2',41,44,'KENT','him so ill, though he had been but two hours at the'),
('king_lear_act2_scene2',42,45,'KENT','trade.'),
('king_lear_act2_scene2',42,46,'CORNWALL','Speak yet, how grew your quarrel?'),
('king_lear_act2_scene2',43,47,'OSWALD','This ancient ruffian, sir, whose life I have spared at suit of his gray beard—'),
('king_lear_act2_scene2',44,48,'KENT','Thou whoreson zed! thou unnecessary letter! My lord, if you will give'),
('king_lear_act2_scene2',45,49,'KENT','me leave, I will tread this unbolted villain into mortar, and daub'),
('king_lear_act2_scene2',46,50,'KENT','the wall of a jakes with him. Spare my gray beard, you'),
('king_lear_act2_scene2',47,51,'KENT','wagtail?'),
('king_lear_act2_scene2',47,52,'CORNWALL','Peace, sirrah!'),
('king_lear_act2_scene2',48,53,'CORNWALL','You beastly knave, know you no reverence?'),
('king_lear_act2_scene2',49,54,'KENT','Yes, sir; but anger hath a privilege.'),
('king_lear_act2_scene2',50,55,'CORNWALL','Why art thou angry?'),
('king_lear_act2_scene2',51,56,'KENT','That such a slave as this should wear a sword,'),
('king_lear_act2_scene2',52,57,'KENT','Who wears no honesty. Such smiling rogues as these,'),
('king_lear_act2_scene2',53,58,'KENT','Like rats, oft bite the holy cords a-twain'),
('king_lear_act2_scene2',54,59,'KENT','Which are too intrinse t’ unloose; smooth every passion'),
('king_lear_act2_scene2',55,60,'KENT','That in the natures of their lords rebel;'),
('king_lear_act2_scene2',56,61,'KENT','Bring oil to fire, snow to their colder moods;'),
('king_lear_act2_scene2',57,62,'KENT','Renege, affirm, and turn their halcyon beaks'),
('king_lear_act2_scene2',58,63,'KENT','With every gale and vary of their masters,'),
('king_lear_act2_scene2',59,64,'KENT','Knowing nought, like dogs, but following.'),
('king_lear_act2_scene2',60,65,'KENT','A plague upon your epileptic visage!'),
('king_lear_act2_scene2',61,66,'KENT','Smile you my speeches, as I were a fool?'),
('king_lear_act2_scene2',62,67,'KENT','Goose, if I had you upon Sarum plain,'),
('king_lear_act2_scene2',63,68,'KENT','I’ld drive ye cackling home to Camelot.'),
('king_lear_act2_scene2',64,69,'CORNWALL','Why, art thou mad, old fellow?'),
('king_lear_act2_scene2',64,70,'GLOUCESTER','How fell you out? say that.'),
('king_lear_act2_scene2',65,71,'KENT','No contraries hold more antipathy'),
('king_lear_act2_scene2',66,72,'KENT','Than I and such a knave.'),
('king_lear_act2_scene2',67,73,'CORNWALL','Why dost thou call him a knave? What’s his offence?'),
('king_lear_act2_scene2',68,74,'KENT','His countenance likes me not.'),
('king_lear_act2_scene2',69,75,'CORNWALL','No more, perchance, does mine, nor his, nor hers.'),
('king_lear_act2_scene2',70,76,'KENT','Sir, ’tis my occupation to be plain:'),
('king_lear_act2_scene2',71,77,'KENT','I have seen better faces in my time'),
('king_lear_act2_scene2',72,78,'KENT','Than stands on any shoulder that I see'),
('king_lear_act2_scene2',73,79,'KENT','Before me at this instant.'),
('king_lear_act2_scene2',73,80,'CORNWALL','This is some fellow,'),
('king_lear_act2_scene2',74,81,'CORNWALL','Who, having been praised for bluntness, doth affect'),
('king_lear_act2_scene2',75,82,'CORNWALL','A saucy roughness, and constrains the garb'),
('king_lear_act2_scene2',76,83,'CORNWALL','Quite from his nature: he cannot flatter, he,'),
('king_lear_act2_scene2',77,84,'CORNWALL','An honest mind and plain, he must speak truth!'),
('king_lear_act2_scene2',78,85,'CORNWALL','An they will take it, so; if not, he’s plain.'),
('king_lear_act2_scene2',79,86,'CORNWALL','These kind of knaves I know, which in this plainness'),
('king_lear_act2_scene2',80,87,'CORNWALL','Harbour more craft and more corrupter ends'),
('king_lear_act2_scene2',81,88,'CORNWALL','Than twenty silly ducking observants'),
('king_lear_act2_scene2',82,89,'CORNWALL','That stretch their duties nicely.'),
('king_lear_act2_scene2',83,90,'KENT','Sir, in good sooth, in sincere verity,'),
('king_lear_act2_scene2',84,91,'KENT','Under the allowance of your great aspect,'),
('king_lear_act2_scene2',85,92,'KENT','Whose influence, like the wreath of radiant fire'),
('king_lear_act2_scene2',86,93,'KENT','On flickering Phoebus’ front—'),
('king_lear_act2_scene2',86,94,'CORNWALL','What mean’st by this?'),
('king_lear_act2_scene2',87,95,'KENT','To go out of my dialect, which you discommend so much. I'),
('king_lear_act2_scene2',88,96,'KENT','know, sir, I am no flatterer: he that beguiled you in a'),
('king_lear_act2_scene2',89,97,'KENT','plain accent was a plain knave; which for my part I will'),
('king_lear_act2_scene2',90,98,'KENT','not be, though I should win your displeasure to entreat me to'),
('king_lear_act2_scene2',91,99,'KENT','’t.'),
('king_lear_act2_scene2',92,100,'CORNWALL','What was the offence you gave him?'),
('king_lear_act2_scene2',93,101,'OSWALD','I never gave him any:'),
('king_lear_act2_scene2',94,102,'OSWALD','It pleased the king his master very late'),
('king_lear_act2_scene2',95,103,'OSWALD','To strike at me, upon his misconstruction;'),
('king_lear_act2_scene2',96,104,'OSWALD','When he, conjunct and flattering his displeasure,'),
('king_lear_act2_scene2',97,105,'OSWALD','Tripp’d me behind; being down, insulted, rail’d,'),
('king_lear_act2_scene2',98,106,'OSWALD','And put upon him such a deal of man,'),
('king_lear_act2_scene2',99,107,'OSWALD','That worthied him, got praises of the king'),
('king_lear_act2_scene2',100,108,'OSWALD','For him attempting who was self-subdued;'),
('king_lear_act2_scene2',101,109,'OSWALD','And, in the fleshment of this dread exploit,'),
('king_lear_act2_scene2',102,110,'OSWALD','Drew on me here again.'),
('king_lear_act2_scene2',102,111,'KENT','None of these rogues and cowards'),
('king_lear_act2_scene2',103,112,'KENT','But Ajax is their fool.'),
('king_lear_act2_scene2',103,113,'CORNWALL','Fetch forth the stocks!'),
('king_lear_act2_scene2',104,114,'CORNWALL','You stubborn ancient knave, you reverend braggart,'),
('king_lear_act2_scene2',105,115,'CORNWALL','We’ll teach you—'),
('king_lear_act2_scene2',106,116,'KENT','Sir, I am too old to learn:'),
('king_lear_act2_scene2',107,117,'KENT','Call not your stocks for me: I serve the king;'),
('king_lear_act2_scene2',108,118,'KENT','On whose employment I was sent to you:'),
('king_lear_act2_scene2',109,119,'KENT','You shall do small respect, show too bold malice'),
('king_lear_act2_scene2',110,120,'KENT','Against the grace and person of my master,'),
('king_lear_act2_scene2',111,121,'KENT','Stocking his messenger.'),
('king_lear_act2_scene2',112,122,'CORNWALL','Fetch forth the stocks! As I have life and honour,'),
('king_lear_act2_scene2',113,123,'CORNWALL','There shall he sit till noon.'),
('king_lear_act2_scene2',114,124,'REGAN','Till noon! till night, my lord; and all night too.'),
('king_lear_act2_scene2',115,125,'KENT','Why, madam, if I were your father’s dog,'),
('king_lear_act2_scene2',116,126,'KENT','You should not use me so.'),
('king_lear_act2_scene2',116,127,'REGAN','Sir, being his knave, I will.'),
('king_lear_act2_scene2',117,128,'CORNWALL','This is a fellow of the self-same colour'),
('king_lear_act2_scene2',118,129,'CORNWALL','Our sister speaks of. Come, bring away the stocks! Stocks brought out.'),
('king_lear_act2_scene2',119,130,'GLOUCESTER','Let me beseech your grace not to do so:'),
('king_lear_act2_scene2',120,131,'GLOUCESTER','His fault is much, and the good king his master'),
('king_lear_act2_scene2',121,132,'GLOUCESTER','Will cheque him for ’t: your purposed low correction'),
('king_lear_act2_scene2',122,133,'GLOUCESTER','Is such as basest and contemned’st wretches'),
('king_lear_act2_scene2',123,134,'GLOUCESTER','For pilferings and most common trespasses'),
('king_lear_act2_scene2',124,135,'GLOUCESTER','Are punish’d with: the king must take it ill,'),
('king_lear_act2_scene2',125,136,'GLOUCESTER','That he’s so slightly valued in his messenger,'),
('king_lear_act2_scene2',126,137,'GLOUCESTER','Should have him thus restrain’d.'),
('king_lear_act2_scene2',126,138,'CORNWALL','I’ll answer that.'),
('king_lear_act2_scene2',127,139,'REGAN','My sister may receive it much more worse,'),
('king_lear_act2_scene2',128,140,'REGAN','To have her gentleman abused, assaulted,'),
('king_lear_act2_scene2',129,141,'REGAN','For following her affairs. Put in his legs. Kent is put in the stocks.'),
('king_lear_act2_scene2',130,142,'REGAN','Come, my good lord, away.'),
('king_lear_act2_scene2',131,143,'GLOUCESTER','I am sorry for thee, friend; ’tis the duke’s pleasure,'),
('king_lear_act2_scene2',132,144,'GLOUCESTER','Whose disposition, all the world well knows,'),
('king_lear_act2_scene2',133,145,'GLOUCESTER','Will not be rubb’d nor stopp’d: I’ll entreat for thee.'),
('king_lear_act2_scene2',134,146,'KENT','Pray, do not, sir: I have watched and travell’d hard;'),
('king_lear_act2_scene2',135,147,'KENT','Some time I shall sleep out, the rest I’ll whistle.'),
('king_lear_act2_scene2',136,148,'KENT','A good man’s fortune may grow out at heels:'),
('king_lear_act2_scene2',137,149,'KENT','Give you good morrow!'),
('king_lear_act2_scene2',138,150,'GLOUCESTER','The duke’s to blame in this; ’twill be ill taken.'),
('king_lear_act2_scene2',139,151,'KENT','Good king, that must approve the common saw,'),
('king_lear_act2_scene2',140,152,'KENT','Thou out of heaven’s benediction comest'),
('king_lear_act2_scene2',141,153,'KENT','To the warm sun!'),
('king_lear_act2_scene2',142,154,'KENT','Approach, thou beacon to this under globe,'),
('king_lear_act2_scene2',143,155,'KENT','That by thy comfortable beams I may'),
('king_lear_act2_scene2',144,156,'KENT','Peruse this letter! Nothing almost sees miracles'),
('king_lear_act2_scene2',145,157,'KENT','But misery: I know ’tis from Cordelia,'),
('king_lear_act2_scene2',146,158,'KENT','Who hath most fortunately been inform’d'),
('king_lear_act2_scene2',147,159,'KENT','Of my obscured course; and shall find time'),
('king_lear_act2_scene2',148,160,'KENT','From this enormous state, seeking to give'),
('king_lear_act2_scene2',149,161,'KENT','Losses their remedies. All weary and o’erwatch’d,'),
('king_lear_act2_scene2',150,162,'KENT','Take vantage, heavy eyes, not to behold'),
('king_lear_act2_scene2',151,163,'KENT','This shameful lodging.'),
('king_lear_act2_scene2',152,164,'KENT','Fortune, good night: smile once more: turn thy wheel! Sleeps.'),
('king_lear_act2_scene3',1,0,'EDGAR','I heard myself proclaim’d;'),
('king_lear_act2_scene3',2,1,'EDGAR','And by the happy hollow of a tree'),
('king_lear_act2_scene3',3,2,'EDGAR','Escaped the hunt. No port is free; no place,'),
('king_lear_act2_scene3',4,3,'EDGAR','That guard, and most unusual vigilance,'),
('king_lear_act2_scene3',5,4,'EDGAR','Does not attend my taking. Whiles I may ’scape,'),
('king_lear_act2_scene3',6,5,'EDGAR','I will preserve myself: and am bethought'),
('king_lear_act2_scene3',7,6,'EDGAR','To take the basest and most poorest shape'),
('king_lear_act2_scene3',8,7,'EDGAR','That ever penury, in contempt of man,'),
('king_lear_act2_scene3',9,8,'EDGAR','Brought near to beast: my face I’ll grime with filth;'),
('king_lear_act2_scene3',10,9,'EDGAR','Blanket my loins: elf all my hair in knots;'),
('king_lear_act2_scene3',11,10,'EDGAR','And with presented nakedness out-face'),
('king_lear_act2_scene3',12,11,'EDGAR','The winds and persecutions of the sky.'),
('king_lear_act2_scene3',13,12,'EDGAR','The country gives me proof and precedent'),
('king_lear_act2_scene3',14,13,'EDGAR','Of Bedlam beggars, who, with roaring voices,'),
('king_lear_act2_scene3',15,14,'EDGAR','Strike in their numb’d and mortified bare arms'),
('king_lear_act2_scene3',16,15,'EDGAR','Pins, wooden pricks, nails, sprigs of rosemary;'),
('king_lear_act2_scene3',17,16,'EDGAR','And with this horrible object, from low farms,'),
('king_lear_act2_scene3',18,17,'EDGAR','Poor pelting villages, sheep-cotes, and mills,'),
('king_lear_act2_scene3',19,18,'EDGAR','Sometime with lunatic bans, sometime with prayers,'),
('king_lear_act2_scene3',20,19,'EDGAR','Enforce their charity. Poor Turlygod! poor Tom!'),
('king_lear_act2_scene3',21,20,'EDGAR','That’s something yet: Edgar I nothing am.'),
('king_lear_act2_scene4',1,0,'KING LEAR','’Tis strange that they should so depart from home,'),
('king_lear_act2_scene4',2,1,'KING LEAR','And not send back my messenger.'),
('king_lear_act2_scene4',2,2,'GENTLEMAN','As I learn’d,'),
('king_lear_act2_scene4',3,3,'GENTLEMAN','The night before there was no purpose in them'),
('king_lear_act2_scene4',4,4,'GENTLEMAN','Of this remove.'),
('king_lear_act2_scene4',4,5,'KENT','Hail to thee, noble master!'),
('king_lear_act2_scene4',5,6,'KING LEAR','Ha!'),
('king_lear_act2_scene4',6,7,'KING LEAR','Makest thou this shame thy pastime?'),
('king_lear_act2_scene4',6,8,'KENT','No, my lord.'),
('king_lear_act2_scene4',7,9,'FOOL','Ha, ha! he wears cruel garters. Horses are tied by the heads,'),
('king_lear_act2_scene4',8,10,'FOOL','dogs and bears by the neck, monkeys by the loins, and men'),
('king_lear_act2_scene4',9,11,'FOOL','by the legs: when a man’s over-lusty at legs, then he wears'),
('king_lear_act2_scene4',10,12,'FOOL','wooden nether-stocks.'),
('king_lear_act2_scene4',11,13,'KING LEAR','What’s he that hath so much thy place mistook'),
('king_lear_act2_scene4',12,14,'KING LEAR','To set thee here?'),
('king_lear_act2_scene4',12,15,'KENT','It is both he and she;'),
('king_lear_act2_scene4',13,16,'KENT','Your son and daughter.'),
('king_lear_act2_scene4',13,17,'KING LEAR','No.'),
('king_lear_act2_scene4',14,18,'KENT','Yes.'),
('king_lear_act2_scene4',14,19,'KING LEAR','No, I say.'),
('king_lear_act2_scene4',15,20,'KENT','I say, yea.'),
('king_lear_act2_scene4',15,21,'KING LEAR','No, no, they would not.'),
('king_lear_act2_scene4',16,22,'KENT','Yes, they have.'),
('king_lear_act2_scene4',16,23,'KING LEAR','By Jupiter, I swear, no.'),
('king_lear_act2_scene4',17,24,'KENT','By Juno, I swear, ay.'),
('king_lear_act2_scene4',17,25,'KING LEAR','They durst not do ’t;'),
('king_lear_act2_scene4',18,26,'KING LEAR','They could not, would not do ’t; ’tis worse than murder,'),
('king_lear_act2_scene4',19,27,'KING LEAR','To do upon respect such violent outrage:'),
('king_lear_act2_scene4',20,28,'KING LEAR','Resolve me, with all modest haste, which way'),
('king_lear_act2_scene4',21,29,'KING LEAR','Thou mightst deserve, or they impose, this usage,'),
('king_lear_act2_scene4',22,30,'KING LEAR','Coming from us.'),
('king_lear_act2_scene4',22,31,'KENT','My lord, when at their home'),
('king_lear_act2_scene4',23,32,'KENT','I did commend your highness’ letters to them,'),
('king_lear_act2_scene4',24,33,'KENT','Ere I was risen from the place that show’d'),
('king_lear_act2_scene4',25,34,'KENT','My duty kneeling, came there a reeking post,'),
('king_lear_act2_scene4',26,35,'KENT','Stew’d in his haste, half breathless, panting forth'),
('king_lear_act2_scene4',27,36,'KENT','From Goneril his mistress salutations;'),
('king_lear_act2_scene4',28,37,'KENT','Deliver’d letters, spite of intermission,'),
('king_lear_act2_scene4',29,38,'KENT','Which presently they read: on whose contents,'),
('king_lear_act2_scene4',30,39,'KENT','They summon’d up their meiny, straight took horse;'),
('king_lear_act2_scene4',31,40,'KENT','Commanded me to follow, and attend'),
('king_lear_act2_scene4',32,41,'KENT','The leisure of their answer; gave me cold looks:'),
('king_lear_act2_scene4',33,42,'KENT','And meeting here the other messenger,'),
('king_lear_act2_scene4',34,43,'KENT','Whose welcome, I perceived, had poison’d mine—'),
('king_lear_act2_scene4',35,44,'KENT','Being the very fellow that of late'),
('king_lear_act2_scene4',36,45,'KENT','Display’d so saucily against your highness—'),
('king_lear_act2_scene4',37,46,'KENT','Having more man than wit about me, drew:'),
('king_lear_act2_scene4',38,47,'KENT','He raised the house with loud and coward cries.'),
('king_lear_act2_scene4',39,48,'KENT','Your son and daughter found this trespass worth'),
('king_lear_act2_scene4',40,49,'KENT','The shame which here it suffers.'),
('king_lear_act2_scene4',41,50,'FOOL','Winter’s not gone yet, if the wild-geese fly that way.'),
('king_lear_act2_scene4',42,51,'FOOL','Fathers that wear rags'),
('king_lear_act2_scene4',43,52,'FOOL','Do make their children blind;'),
('king_lear_act2_scene4',44,53,'FOOL','But fathers that bear bags'),
('king_lear_act2_scene4',45,54,'FOOL','Shall see their children kind.'),
('king_lear_act2_scene4',46,55,'FOOL','Fortune, that arrant whore,'),
('king_lear_act2_scene4',47,56,'FOOL','Ne’er turns the key to the poor.'),
('king_lear_act2_scene4',48,57,'FOOL','But, for all this, thou shalt have as many dolours'),
('king_lear_act2_scene4',49,58,'FOOL','for thy daughters as thou canst tell in a year.'),
('king_lear_act2_scene4',50,59,'KING LEAR','O, how this mother swells up toward my heart!'),
('king_lear_act2_scene4',51,60,'KING LEAR','Hysterica passio, down, thou climbing sorrow,'),
('king_lear_act2_scene4',52,61,'KING LEAR','Thy element’s below! Where is this daughter?'),
('king_lear_act2_scene4',53,62,'KENT','With the earl, sir, here within.'),
('king_lear_act2_scene4',53,63,'KING LEAR','Follow me not;'),
('king_lear_act2_scene4',54,64,'KING LEAR','Stay here.'),
('king_lear_act2_scene4',55,65,'GENTLEMAN','Made you no more offence but what you speak of?'),
('king_lear_act2_scene4',56,66,'KENT','None.'),
('king_lear_act2_scene4',57,67,'KENT','How chance the king comes with so small a train?'),
('king_lear_act2_scene4',58,68,'FOOL','And thou hadst been set i’ the stocks for that question, thou'),
('king_lear_act2_scene4',59,69,'FOOL','hadst well deserved it.'),
('king_lear_act2_scene4',59,70,'KENT','Why, fool?'),
('king_lear_act2_scene4',60,71,'FOOL','We’ll set thee to school to an ant, to teach thee there’s'),
('king_lear_act2_scene4',61,72,'FOOL','no labouring i’ the winter. All that follow their noses are led'),
('king_lear_act2_scene4',62,73,'FOOL','by their eyes but blind men; and there’s not a nose among'),
('king_lear_act2_scene4',63,74,'FOOL','twenty but can smell him that’s stinking. Let go thy hold when'),
('king_lear_act2_scene4',64,75,'FOOL','a great wheel runs down a hill, lest it break thy neck'),
('king_lear_act2_scene4',65,76,'FOOL','with following it: but the great one that goes up the hill,'),
('king_lear_act2_scene4',66,77,'FOOL','let him draw thee after. When a wise man gives thee better'),
('king_lear_act2_scene4',67,78,'FOOL','counsel, give me mine again: I would have none but knaves follow'),
('king_lear_act2_scene4',68,79,'FOOL','it, since a fool gives it.'),
('king_lear_act2_scene4',68,80,'KENT','Where learned you this, fool?'),
('king_lear_act2_scene4',69,81,'FOOL','Not i’ the stocks, fool.'),
('king_lear_act2_scene4',70,82,'KING LEAR','Deny to speak with me? They are sick? they are weary?'),
('king_lear_act2_scene4',71,83,'KING LEAR','They have travell’d all the night? Mere fetches;'),
('king_lear_act2_scene4',72,84,'KING LEAR','The images of revolt and flying off.'),
('king_lear_act2_scene4',73,85,'KING LEAR','Fetch me a better answer.'),
('king_lear_act2_scene4',73,86,'GLOUCESTER','My dear lord,'),
('king_lear_act2_scene4',74,87,'GLOUCESTER','You know the fiery quality of the duke;'),
('king_lear_act2_scene4',75,88,'GLOUCESTER','How unremoveable and fix’d he is'),
('king_lear_act2_scene4',76,89,'GLOUCESTER','In his own course.'),
('king_lear_act2_scene4',76,90,'KING LEAR','Vengeance! plague! death! confusion!'),
('king_lear_act2_scene4',77,91,'KING LEAR','Fiery? what quality? Why, Gloucester, Gloucester,'),
('king_lear_act2_scene4',78,92,'KING LEAR','I’ld speak with the Duke of Cornwall and his wife.'),
('king_lear_act2_scene4',79,93,'GLOUCESTER','Well, my good lord, I have inform’d them so.'),
('king_lear_act2_scene4',80,94,'KING LEAR','Inform’d them! Dost thou understand me, man?'),
('king_lear_act2_scene4',81,95,'GLOUCESTER','Ay, my good lord.'),
('king_lear_act2_scene4',82,96,'KING LEAR','The king would speak with Cornwall; the dear father'),
('king_lear_act2_scene4',83,97,'KING LEAR','Would with his daughter speak, commands her service:'),
('king_lear_act2_scene4',84,98,'KING LEAR','Are they inform’d of this? My breath and blood!'),
('king_lear_act2_scene4',85,99,'KING LEAR','Fiery? the fiery duke? Tell the hot duke that—'),
('king_lear_act2_scene4',86,100,'KING LEAR','No, but not yet: may be he is not well:'),
('king_lear_act2_scene4',87,101,'KING LEAR','Infirmity doth still neglect all office'),
('king_lear_act2_scene4',88,102,'KING LEAR','Whereto our health is bound; we are not ourselves'),
('king_lear_act2_scene4',89,103,'KING LEAR','When nature, being oppress’d, commands the mind'),
('king_lear_act2_scene4',90,104,'KING LEAR','To suffer with the body: I’ll forbear;'),
('king_lear_act2_scene4',91,105,'KING LEAR','And am fall’n out with my more headier will,'),
('king_lear_act2_scene4',92,106,'KING LEAR','To take the indisposed and sickly fit'),
('king_lear_act2_scene4',93,107,'KING LEAR','For the sound man. Death on my state! wherefore Looking on Kent.'),
('king_lear_act2_scene4',94,108,'KING LEAR','Should he sit here? This act persuades me'),
('king_lear_act2_scene4',95,109,'KING LEAR','That this remotion of the duke and her'),
('king_lear_act2_scene4',96,110,'KING LEAR','Is practise only. Give me my servant forth.'),
('king_lear_act2_scene4',97,111,'KING LEAR','Go tell the duke and ’s wife I’ld speak with them,'),
('king_lear_act2_scene4',98,112,'KING LEAR','Now, presently: bid them come forth and hear me,'),
('king_lear_act2_scene4',99,113,'KING LEAR','Or at their chamber-door I’ll beat the drum'),
('king_lear_act2_scene4',100,114,'KING LEAR','Till it cry sleep to death.'),
('king_lear_act2_scene4',101,115,'GLOUCESTER','I would have all well betwixt you.'),
('king_lear_act2_scene4',102,116,'KING LEAR','O me, my heart, my rising heart! but, down!'),
('king_lear_act2_scene4',103,117,'FOOL','Cry to it, nuncle, as the cockney did to the eels when'),
('king_lear_act2_scene4',104,118,'FOOL','she put ’em i’ the paste alive; she knapped ’em o’ the'),
('king_lear_act2_scene4',105,119,'FOOL','coxcombs with a stick, and cried ‘Down, wantons, down!’ ’Twas her brother'),
('king_lear_act2_scene4',106,120,'FOOL','that, in pure kindness to his horse, buttered his hay.'),
('king_lear_act2_scene4',107,121,'KING LEAR','Good morrow to you both.'),
('king_lear_act2_scene4',108,122,'CORNWALL','Hail to your grace! Kent is set at liberty.'),
('king_lear_act2_scene4',109,123,'REGAN','I am glad to see your highness.'),
('king_lear_act2_scene4',110,124,'KING LEAR','Regan, I think you are; I know what reason'),
('king_lear_act2_scene4',111,125,'KING LEAR','I have to think so: if thou shouldst not be glad,'),
('king_lear_act2_scene4',112,126,'KING LEAR','I would divorce me from thy mother’s tomb,'),
('king_lear_act2_scene4',113,127,'KING LEAR','Sepulchring an adultress.'),
('king_lear_act2_scene4',114,128,'KING LEAR','To Kent. O, are you free?'),
('king_lear_act2_scene4',115,129,'KING LEAR','Some other time for that. Beloved Regan,'),
('king_lear_act2_scene4',116,130,'KING LEAR','Thy sister’s naught: O Regan, she hath tied'),
('king_lear_act2_scene4',117,131,'KING LEAR','Sharp-tooth’d unkindness, like a vulture, here:'),
('king_lear_act2_scene4',118,132,'KING LEAR','I can scarce speak to thee; thou’lt not believe'),
('king_lear_act2_scene4',119,133,'KING LEAR','With how depraved a quality—O Regan!'),
('king_lear_act2_scene4',120,134,'REGAN','I pray you, sir, take patience: I have hope.'),
('king_lear_act2_scene4',121,135,'REGAN','You less know how to value her desert'),
('king_lear_act2_scene4',122,136,'REGAN','Than she to scant her duty.'),
('king_lear_act2_scene4',122,137,'KING LEAR','Say, how is that?'),
('king_lear_act2_scene4',123,138,'REGAN','I cannot think my sister in the least'),
('king_lear_act2_scene4',124,139,'REGAN','Would fail her obligation: if, sir, perchance'),
('king_lear_act2_scene4',125,140,'REGAN','She have restrain’d the riots of your followers,'),
('king_lear_act2_scene4',126,141,'REGAN','’Tis on such ground, and to such wholesome end,'),
('king_lear_act2_scene4',127,142,'REGAN','As clears her from all blame.'),
('king_lear_act2_scene4',127,143,'KING LEAR','My curses on her!'),
('king_lear_act2_scene4',128,144,'REGAN','O, sir, you are old.'),
('king_lear_act2_scene4',129,145,'REGAN','Nature in you stands on the very verge'),
('king_lear_act2_scene4',130,146,'REGAN','Of her confine: you should be ruled and led'),
('king_lear_act2_scene4',131,147,'REGAN','By some discretion, that discerns your state'),
('king_lear_act2_scene4',132,148,'REGAN','Better than you yourself. Therefore, I pray you,'),
('king_lear_act2_scene4',133,149,'REGAN','That to our sister you do make return;'),
('king_lear_act2_scene4',134,150,'REGAN','Say you have wrong’d her, sir.'),
('king_lear_act2_scene4',134,151,'KING LEAR','Ask her forgiveness?'),
('king_lear_act2_scene4',135,152,'KING LEAR','Do you but mark how this becomes the house:'),
('king_lear_act2_scene4',136,153,'KING LEAR','“Dear daughter, I confess that I am old;'),
('king_lear_act2_scene4',137,154,'KING LEAR','Age is unnecessary: on my knees I beg'),
('king_lear_act2_scene4',138,155,'KING LEAR','That you’ll vouchsafe me raiment, bed, and food.”'),
('king_lear_act2_scene4',139,156,'REGAN','Good sir, no more; these are unsightly tricks:'),
('king_lear_act2_scene4',140,157,'REGAN','Return you to my sister.'),
('king_lear_act2_scene4',140,158,'KING LEAR','Never, Regan:'),
('king_lear_act2_scene4',141,159,'KING LEAR','She hath abated me of half my train;'),
('king_lear_act2_scene4',142,160,'KING LEAR','Look’d black upon me; struck me with her tongue,'),
('king_lear_act2_scene4',143,161,'KING LEAR','Most serpent-like, upon the very heart:'),
('king_lear_act2_scene4',144,162,'KING LEAR','All the stored vengeances of heaven fall'),
('king_lear_act2_scene4',145,163,'KING LEAR','On her ingrateful top! Strike her young bones,'),
('king_lear_act2_scene4',146,164,'KING LEAR','You taking airs, with lameness!'),
('king_lear_act2_scene4',146,165,'CORNWALL','Fie, sir, fie!'),
('king_lear_act2_scene4',147,166,'KING LEAR','You nimble lightnings, dart your blinding flames'),
('king_lear_act2_scene4',148,167,'KING LEAR','Into her scornful eyes! Infect her beauty,'),
('king_lear_act2_scene4',149,168,'KING LEAR','You fen-suck’d fogs, drawn by the powerful sun,'),
('king_lear_act2_scene4',150,169,'KING LEAR','To fall and blast her pride!'),
('king_lear_act2_scene4',151,170,'REGAN','O the blest gods! so will you wish on me,'),
('king_lear_act2_scene4',152,171,'REGAN','When the rash mood is on.'),
('king_lear_act2_scene4',153,172,'KING LEAR','No, Regan, thou shalt never have my curse:'),
('king_lear_act2_scene4',154,173,'KING LEAR','Thy tender-hefted nature shall not give'),
('king_lear_act2_scene4',155,174,'KING LEAR','Thee o’er to harshness: her eyes are fierce; but thine'),
('king_lear_act2_scene4',156,175,'KING LEAR','Do comfort and not burn. ’Tis not in thee'),
('king_lear_act2_scene4',157,176,'KING LEAR','To grudge my pleasures, to cut off my train,'),
('king_lear_act2_scene4',158,177,'KING LEAR','To bandy hasty words, to scant my sizes,'),
('king_lear_act2_scene4',159,178,'KING LEAR','And in conclusion to oppose the bolt'),
('king_lear_act2_scene4',160,179,'KING LEAR','Against my coming in: thou better know’st'),
('king_lear_act2_scene4',161,180,'KING LEAR','The offices of nature, bond of childhood,'),
('king_lear_act2_scene4',162,181,'KING LEAR','Effects of courtesy, dues of gratitude;'),
('king_lear_act2_scene4',163,182,'KING LEAR','Thy half o’ the kingdom hast thou not forgot,'),
('king_lear_act2_scene4',164,183,'KING LEAR','Wherein I thee endow’d.'),
('king_lear_act2_scene4',164,184,'REGAN','Good sir, to the purpose.'),
('king_lear_act2_scene4',165,185,'KING LEAR','Who put my man i’ the stocks? Tucket within.'),
('king_lear_act2_scene4',166,186,'CORNWALL','What trumpet’s that?'),
('king_lear_act2_scene4',167,187,'REGAN','I know’t, my sister’s: this approves her letter,'),
('king_lear_act2_scene4',168,188,'REGAN','That she would soon be here.'),
('king_lear_act2_scene4',169,189,'KING LEAR','This is a slave, whose easy-borrow’d pride'),
('king_lear_act2_scene4',170,190,'KING LEAR','Dwells in the fickle grace of her he follows.'),
('king_lear_act2_scene4',171,191,'KING LEAR','Out, varlet, from my sight!'),
('king_lear_act2_scene4',171,192,'CORNWALL','What means your grace?'),
('king_lear_act2_scene4',172,193,'KING LEAR','Who stock’d my servant? Regan, I have good hope'),
('king_lear_act2_scene4',173,194,'KING LEAR','Thou didst not know on’t. Who comes here? O heavens,'),
('king_lear_act2_scene4',174,195,'GONERIL','Why not by the hand, sir? How have I offended?'),
('king_lear_act2_scene4',175,196,'GONERIL','All’s not offence that indiscretion finds'),
('king_lear_act2_scene4',176,197,'GONERIL','And dotage terms so.'),
('king_lear_act2_scene4',176,198,'KING LEAR','O sides, you are too tough;'),
('king_lear_act2_scene4',177,199,'KING LEAR','Will you yet hold? How came my man i’ the stocks?'),
('king_lear_act2_scene4',178,200,'CORNWALL','I set him there, sir: but his own disorders'),
('king_lear_act2_scene4',179,201,'CORNWALL','Deserved much less advancement.'),
('king_lear_act2_scene4',179,202,'KING LEAR','You! did you?'),
('king_lear_act2_scene4',180,203,'REGAN','I pray you, father, being weak, seem so.'),
('king_lear_act2_scene4',181,204,'REGAN','If, till the expiration of your month,'),
('king_lear_act2_scene4',182,205,'REGAN','You will return and sojourn with my sister,'),
('king_lear_act2_scene4',183,206,'REGAN','Dismissing half your train, come then to me:'),
('king_lear_act2_scene4',184,207,'REGAN','I am now from home, and out of that provision'),
('king_lear_act2_scene4',185,208,'REGAN','Which shall be needful for your entertainment.'),
('king_lear_act2_scene4',186,209,'KING LEAR','Return to her, and fifty men dismiss’d?'),
('king_lear_act2_scene4',187,210,'KING LEAR','No, rather I abjure all roofs, and choose'),
('king_lear_act2_scene4',188,211,'KING LEAR','To wage against the enmity o’ the air;'),
('king_lear_act2_scene4',189,212,'KING LEAR','To be a comrade with the wolf and owl—'),
('king_lear_act2_scene4',190,213,'KING LEAR','Necessity’s sharp pinch! Return with her?'),
('king_lear_act2_scene4',191,214,'KING LEAR','Why, the hot-blooded France, that dowerless took'),
('king_lear_act2_scene4',192,215,'KING LEAR','Our youngest born, I could as well be brought'),
('king_lear_act2_scene4',193,216,'KING LEAR','To knee his throne, and, squire-like; pension beg'),
('king_lear_act2_scene4',194,217,'KING LEAR','To keep base life afoot. Return with her?'),
('king_lear_act2_scene4',195,218,'KING LEAR','Persuade me rather to be slave and sumpter'),
('king_lear_act2_scene4',196,219,'KING LEAR','To this detested groom.'),
('king_lear_act2_scene4',196,220,'GONERIL','At your choice, sir.'),
('king_lear_act2_scene4',197,221,'KING LEAR','I prithee, daughter, do not make me mad:'),
('king_lear_act2_scene4',198,222,'KING LEAR','I will not trouble thee, my child; farewell:'),
('king_lear_act2_scene4',199,223,'KING LEAR','We’ll no more meet, no more see one another:'),
('king_lear_act2_scene4',200,224,'KING LEAR','But yet thou art my flesh, my blood, my daughter;'),
('king_lear_act2_scene4',201,225,'KING LEAR','Or rather a disease that’s in my flesh,'),
('king_lear_act2_scene4',202,226,'KING LEAR','Which I must needs call mine: thou art a boil,'),
('king_lear_act2_scene4',203,227,'KING LEAR','A plague-sore, an embossed carbuncle,'),
('king_lear_act2_scene4',204,228,'KING LEAR','In my corrupted blood. But I’ll not chide thee;'),
('king_lear_act2_scene4',205,229,'KING LEAR','Let shame come when it will, I do not call it:'),
('king_lear_act2_scene4',206,230,'KING LEAR','I do not bid the thunder-bearer shoot,'),
('king_lear_act2_scene4',207,231,'KING LEAR','Nor tell tales of thee to high-judging Jove:'),
('king_lear_act2_scene4',208,232,'KING LEAR','Mend when thou canst; be better at thy leisure:'),
('king_lear_act2_scene4',209,233,'KING LEAR','I can be patient; I can stay with Regan,'),
('king_lear_act2_scene4',210,234,'KING LEAR','I and my hundred knights.'),
('king_lear_act2_scene4',210,235,'REGAN','Not altogether so:'),
('king_lear_act2_scene4',211,236,'REGAN','I look’d not for you yet, nor am provided'),
('king_lear_act2_scene4',212,237,'REGAN','For your fit welcome. Give ear, sir, to my sister;'),
('king_lear_act2_scene4',213,238,'REGAN','For those that mingle reason with your passion'),
('king_lear_act2_scene4',214,239,'REGAN','Must be content to think you old, and so—'),
('king_lear_act2_scene4',215,240,'REGAN','But she knows what she does.'),
('king_lear_act2_scene4',215,241,'KING LEAR','Is this well spoken?'),
('king_lear_act2_scene4',216,242,'REGAN','I dare avouch it, sir: what, fifty followers?'),
('king_lear_act2_scene4',217,243,'REGAN','Is it not well? What should you need of more?'),
('king_lear_act2_scene4',218,244,'REGAN','Yea, or so many, sith that both charge and danger'),
('king_lear_act2_scene4',219,245,'REGAN','Speak ’gainst so great a number? How, in one house,'),
('king_lear_act2_scene4',220,246,'REGAN','Should many people, under two commands,'),
('king_lear_act2_scene4',221,247,'REGAN','Hold amity? ’Tis hard; almost impossible.'),
('king_lear_act2_scene4',222,248,'GONERIL','Why might not you, my lord, receive attendance'),
('king_lear_act2_scene4',223,249,'GONERIL','From those that she calls servants or from mine?'),
('king_lear_act2_scene4',224,250,'REGAN','Why not, my lord? If then they chanced to slack you,'),
('king_lear_act2_scene4',225,251,'REGAN','We could control them. If you will come to me—'),
('king_lear_act2_scene4',226,252,'REGAN','For now I spy a danger—I entreat you'),
('king_lear_act2_scene4',227,253,'REGAN','To bring but five and twenty: to no more'),
('king_lear_act2_scene4',228,254,'REGAN','Will I give place or notice.'),
('king_lear_act2_scene4',228,255,'KING LEAR','I gave you all—'),
('king_lear_act2_scene4',229,256,'REGAN','And in good time you gave it.'),
('king_lear_act2_scene4',230,257,'KING LEAR','Made you my guardians, my depositaries;'),
('king_lear_act2_scene4',231,258,'KING LEAR','But kept a reservation to be follow’d'),
('king_lear_act2_scene4',232,259,'KING LEAR','With such a number. What, must I come to you'),
('king_lear_act2_scene4',233,260,'KING LEAR','With five and twenty, Regan? said you so?'),
('king_lear_act2_scene4',234,261,'REGAN','And speak’t again, my lord; no more with me.'),
('king_lear_act2_scene4',235,262,'KING LEAR','Those wicked creatures yet do look well-favour’d,'),
('king_lear_act2_scene4',236,263,'KING LEAR','When others are more wicked: not being the worst'),
('king_lear_act2_scene4',237,264,'KING LEAR','Stands in some rank of praise.'),
('king_lear_act2_scene4',238,265,'KING LEAR','To Goneril. I’ll go with thee:'),
('king_lear_act2_scene4',239,266,'KING LEAR','Thy fifty yet doth double five and twenty,'),
('king_lear_act2_scene4',240,267,'KING LEAR','And thou art twice her love.'),
('king_lear_act2_scene4',240,268,'GONERIL','Hear me, my lord;'),
('king_lear_act2_scene4',241,269,'GONERIL','What need you five and twenty, ten, or five,'),
('king_lear_act2_scene4',242,270,'GONERIL','To follow in a house where twice so many'),
('king_lear_act2_scene4',243,271,'GONERIL','Have a command to tend you?'),
('king_lear_act2_scene4',243,272,'REGAN','What need one?'),
('king_lear_act2_scene4',244,273,'KING LEAR','O, reason not the need: our basest beggars'),
('king_lear_act2_scene4',245,274,'KING LEAR','Are in the poorest thing superfluous:'),
('king_lear_act2_scene4',246,275,'KING LEAR','Allow not nature more than nature needs,'),
('king_lear_act2_scene4',247,276,'KING LEAR','Man’s life’s as cheap as beast’s: thou art a lady;'),
('king_lear_act2_scene4',248,277,'KING LEAR','If only to go warm were gorgeous,'),
('king_lear_act2_scene4',249,278,'KING LEAR','Why, nature needs not what thou gorgeous wear’st,'),
('king_lear_act2_scene4',250,279,'KING LEAR','Which scarcely keeps thee warm. But, for true need—'),
('king_lear_act2_scene4',251,280,'KING LEAR','You heavens, give me that patience, patience I need!'),
('king_lear_act2_scene4',252,281,'KING LEAR','You see me here, you gods, a poor old man,'),
('king_lear_act2_scene4',253,282,'KING LEAR','As full of grief as age; wretched in both!'),
('king_lear_act2_scene4',254,283,'KING LEAR','If it be you that stir these daughters’ hearts'),
('king_lear_act2_scene4',255,284,'KING LEAR','Against their father, fool me not so much'),
('king_lear_act2_scene4',256,285,'KING LEAR','To bear it tamely; touch me with noble anger,'),
('king_lear_act2_scene4',257,286,'KING LEAR','And let not women’s weapons, water-drops,'),
('king_lear_act2_scene4',258,287,'KING LEAR','Stain my man’s cheeks! No, you unnatural hags,'),
('king_lear_act2_scene4',259,288,'KING LEAR','I will have such revenges on you both,'),
('king_lear_act2_scene4',260,289,'KING LEAR','That all the world shall—I will do such things—'),
('king_lear_act2_scene4',261,290,'KING LEAR','What they are, yet I know not: but they shall be'),
('king_lear_act2_scene4',262,291,'KING LEAR','The terrors of the earth. You think I’ll weep'),
('king_lear_act2_scene4',263,292,'KING LEAR','No, I’ll not weep:'),
('king_lear_act2_scene4',264,293,'KING LEAR','I have full cause of weeping; but this heart'),
('king_lear_act2_scene4',265,294,'KING LEAR','Shall break into a hundred thousand flaws,'),
('king_lear_act2_scene4',266,295,'KING LEAR','Or ere I’ll weep. O fool, I shall go mad!'),
('king_lear_act2_scene4',267,296,'CORNWALL','Let us withdraw; ’twill be a storm.'),
('king_lear_act2_scene4',268,297,'REGAN','This house is little: the old man and his people'),
('king_lear_act2_scene4',269,298,'REGAN','Cannot be well bestow’d.'),
('king_lear_act2_scene4',270,299,'GONERIL','’Tis his own blame; hath put himself from rest,'),
('king_lear_act2_scene4',271,300,'GONERIL','And must needs taste his folly.'),
('king_lear_act2_scene4',272,301,'REGAN','For his particular, I’ll receive him gladly,'),
('king_lear_act2_scene4',273,302,'REGAN','But not one follower.'),
('king_lear_act2_scene4',273,303,'GONERIL','So am I purposed.'),
('king_lear_act2_scene4',274,304,'GONERIL','Where is my lord of Gloucester?'),
('king_lear_act2_scene4',275,305,'CORNWALL','Follow’d the old man forth: he is return’d.'),
('king_lear_act2_scene4',276,306,'GLOUCESTER','The king is in high rage.'),
('king_lear_act2_scene4',276,307,'CORNWALL','Whither is he going?'),
('king_lear_act2_scene4',277,308,'GLOUCESTER','He calls to horse; but will I know not whither.'),
('king_lear_act2_scene4',278,309,'CORNWALL','’Tis best to give him way; he leads himself.'),
('king_lear_act2_scene4',279,310,'GONERIL','My lord, entreat him by no means to stay.'),
('king_lear_act2_scene4',280,311,'GLOUCESTER','Alack, the night comes on, and the bleak winds'),
('king_lear_act2_scene4',281,312,'GLOUCESTER','Do sorely ruffle; for many miles a bout'),
('king_lear_act2_scene4',282,313,'GLOUCESTER','There’s scarce a bush.'),
('king_lear_act2_scene4',282,314,'REGAN','O, sir, to wilful men,'),
('king_lear_act2_scene4',283,315,'REGAN','The injuries that they themselves procure'),
('king_lear_act2_scene4',284,316,'REGAN','Must be their schoolmasters. Shut up your doors:'),
('king_lear_act2_scene4',285,317,'REGAN','He is attended with a desperate train;'),
('king_lear_act2_scene4',286,318,'REGAN','And what they may incense him to, being apt'),
('king_lear_act2_scene4',287,319,'REGAN','To have his ear abused, wisdom bids fear.'),
('king_lear_act2_scene4',288,320,'CORNWALL','Shut up your doors, my lord; ’tis a wild night:'),
('king_lear_act2_scene4',289,321,'CORNWALL','My Regan counsels well; come out o’ the storm.'),
('king_lear_act3_scene1',1,0,'KENT','Who’s there, besides foul weather?'),
('king_lear_act3_scene1',2,1,'GENTLEMAN','One minded like the weather, most unquietly.'),
('king_lear_act3_scene1',3,2,'KENT','I know you. Where’s the king?'),
('king_lear_act3_scene1',3,3,'GENTLEMAN','Contending with the fretful element:'),
('king_lear_act3_scene1',4,4,'GENTLEMAN','Bids the winds blow the earth into the sea,'),
('king_lear_act3_scene1',5,5,'GENTLEMAN','Or swell the curled water ’bove the main,'),
('king_lear_act3_scene1',6,6,'GENTLEMAN','That things might change or cease; tears his white hair,'),
('king_lear_act3_scene1',7,7,'GENTLEMAN','Which the impetuous blasts, with eyeless rage,'),
('king_lear_act3_scene1',8,8,'GENTLEMAN','Catch in their fury, and make nothing of;'),
('king_lear_act3_scene1',9,9,'GENTLEMAN','Strives in his little world of man to out-scorn'),
('king_lear_act3_scene1',10,10,'GENTLEMAN','The to-and-fro-conflicting wind and rain.'),
('king_lear_act3_scene1',11,11,'GENTLEMAN','This night, wherein the cub-drawn bear would couch,'),
('king_lear_act3_scene1',12,12,'GENTLEMAN','The lion and the belly-pinched wolf'),
('king_lear_act3_scene1',13,13,'GENTLEMAN','Keep their fur dry, unbonneted he runs,'),
('king_lear_act3_scene1',14,14,'GENTLEMAN','And bids what will take all.'),
('king_lear_act3_scene1',14,15,'KENT','But who is with him?'),
('king_lear_act3_scene1',15,16,'GENTLEMAN','None but the fool; who labours to out-jest'),
('king_lear_act3_scene1',16,17,'GENTLEMAN','His heart-struck injuries.'),
('king_lear_act3_scene1',16,18,'KENT','Sir, I do know you;'),
('king_lear_act3_scene1',17,19,'KENT','And dare, upon the warrant of my note,'),
('king_lear_act3_scene1',18,20,'KENT','Commend a dear thing to you. There is division,'),
('king_lear_act3_scene1',19,21,'KENT','Although as yet the face of it be cover’d'),
('king_lear_act3_scene1',20,22,'KENT','With mutual cunning, ’twixt Albany and Cornwall;'),
('king_lear_act3_scene1',21,23,'KENT','Who have—as who have not, that their great stars'),
('king_lear_act3_scene1',22,24,'KENT','Throned and set high?—servants, who seem no less,'),
('king_lear_act3_scene1',23,25,'KENT','Which are to France the spies and speculations'),
('king_lear_act3_scene1',24,26,'KENT','Intelligent of our state; what hath been seen,'),
('king_lear_act3_scene1',25,27,'KENT','Either in snuffs and packings of the dukes,'),
('king_lear_act3_scene1',26,28,'KENT','Or the hard rein which both of them have borne'),
('king_lear_act3_scene1',27,29,'KENT','Against the old kind king; or something deeper,'),
('king_lear_act3_scene1',28,30,'KENT','Whereof perchance these are but furnishings;'),
('king_lear_act3_scene1',29,31,'KENT','But, true it is, from France there comes a power'),
('king_lear_act3_scene1',30,32,'KENT','Into this scatter’d kingdom; who already,'),
('king_lear_act3_scene1',31,33,'KENT','Wise in our negligence, have secret feet'),
('king_lear_act3_scene1',32,34,'KENT','In some of our best ports, and are at point'),
('king_lear_act3_scene1',33,35,'KENT','To show their open banner. Now to you:'),
('king_lear_act3_scene1',34,36,'KENT','If on my credit you dare build so far'),
('king_lear_act3_scene1',35,37,'KENT','To make your speed to Dover, you shall find'),
('king_lear_act3_scene1',36,38,'KENT','Some that will thank you, making just report'),
('king_lear_act3_scene1',37,39,'KENT','Of how unnatural and bemadding sorrow'),
('king_lear_act3_scene1',38,40,'KENT','The king hath cause to plain.'),
('king_lear_act3_scene1',39,41,'KENT','I am a gentleman of blood and breeding;'),
('king_lear_act3_scene1',40,42,'KENT','And, from some knowledge and assurance, offer'),
('king_lear_act3_scene1',41,43,'KENT','This office to you.'),
('king_lear_act3_scene1',41,44,'GENTLEMAN','I will talk further with you.'),
('king_lear_act3_scene1',42,45,'KENT','No, do not.'),
('king_lear_act3_scene1',43,46,'KENT','For confirmation that I am much more'),
('king_lear_act3_scene1',44,47,'KENT','Than my out-wall, open this purse, and take'),
('king_lear_act3_scene1',45,48,'KENT','What it contains. If you shall see Cordelia—'),
('king_lear_act3_scene1',46,49,'KENT','As fear not but you shall—show her this ring;'),
('king_lear_act3_scene1',47,50,'KENT','And she will tell you who your fellow is'),
('king_lear_act3_scene1',48,51,'KENT','That yet you do not know. Fie on this storm!'),
('king_lear_act3_scene1',49,52,'KENT','I will go seek the king.'),
('king_lear_act3_scene1',50,53,'GENTLEMAN','Give me your hand: have you no more to say?'),
('king_lear_act3_scene1',51,54,'KENT','Few words, but, to effect, more than all yet;'),
('king_lear_act3_scene1',52,55,'KENT','That, when we have found the king—in which your pain'),
('king_lear_act3_scene1',53,56,'KENT','That way, I’ll this—he that first lights on him'),
('king_lear_act3_scene1',54,57,'KENT','Holla the other.'),
('king_lear_act3_scene2',1,0,'KING LEAR','Blow, winds, and crack your cheeks! rage! blow!'),
('king_lear_act3_scene2',2,1,'KING LEAR','You cataracts and hurricanoes, spout'),
('king_lear_act3_scene2',3,2,'KING LEAR','Till you have drench’d our steeples, drown’d the cocks!'),
('king_lear_act3_scene2',4,3,'KING LEAR','You sulphurous and thought-executing fires,'),
('king_lear_act3_scene2',5,4,'KING LEAR','Vaunt-couriers to oak-cleaving thunderbolts,'),
('king_lear_act3_scene2',6,5,'KING LEAR','Singe my white head! And thou, all-shaking thunder,'),
('king_lear_act3_scene2',7,6,'KING LEAR','Smite flat the thick rotundity o’ the world!'),
('king_lear_act3_scene2',8,7,'KING LEAR','Crack nature’s moulds, an germens spill at once,'),
('king_lear_act3_scene2',9,8,'KING LEAR','That make ingrateful man!'),
('king_lear_act3_scene2',10,9,'FOOL','O nuncle, court holy-water in a dry house is better than this'),
('king_lear_act3_scene2',11,10,'FOOL','rain-water out o’ door. Good nuncle, in, and ask thy daughters’ blessing:'),
('king_lear_act3_scene2',12,11,'FOOL','here’s a night pities neither wise man nor fool.'),
('king_lear_act3_scene2',13,12,'KING LEAR','Rumble thy bellyful! Spit, fire! spout, rain!'),
('king_lear_act3_scene2',14,13,'KING LEAR','Nor rain, wind, thunder, fire, are my daughters:'),
('king_lear_act3_scene2',15,14,'KING LEAR','I tax not you, you elements, with unkindness;'),
('king_lear_act3_scene2',16,15,'KING LEAR','I never gave you kingdom, call’d you children,'),
('king_lear_act3_scene2',17,16,'KING LEAR','You owe me no subscription: then let fall'),
('king_lear_act3_scene2',18,17,'KING LEAR','Your horrible pleasure: here I stand, your slave,'),
('king_lear_act3_scene2',19,18,'KING LEAR','A poor, infirm, weak, and despised old man:'),
('king_lear_act3_scene2',20,19,'KING LEAR','But yet I call you servile ministers,'),
('king_lear_act3_scene2',21,20,'KING LEAR','That have with two pernicious daughters join’d'),
('king_lear_act3_scene2',22,21,'KING LEAR','Your high engender’d battles ’gainst a head'),
('king_lear_act3_scene2',23,22,'KING LEAR','So old and white as this. O! O! ’tis foul!'),
('king_lear_act3_scene2',24,23,'FOOL','He that has a house to put’s head in has a good head-piece.'),
('king_lear_act3_scene2',25,24,'KING LEAR','No, I will be the pattern of all patience;'),
('king_lear_act3_scene2',26,25,'KING LEAR','I will say nothing.'),
('king_lear_act3_scene2',26,26,'KENT','Who’s there?'),
('king_lear_act3_scene2',27,27,'FOOL','Marry, here’s grace and a cod-piece; that’s a wise man and a fool.'),
('king_lear_act3_scene2',28,28,'KENT','Alas, sir, are you here? things that love night'),
('king_lear_act3_scene2',29,29,'KENT','Love not such nights as these; the wrathful skies'),
('king_lear_act3_scene2',30,30,'KENT','Gallow the very wanderers of the dark,'),
('king_lear_act3_scene2',31,31,'KENT','And make them keep their caves: since I was man,'),
('king_lear_act3_scene2',32,32,'KENT','Such sheets of fire, such bursts of horrid thunder,'),
('king_lear_act3_scene2',33,33,'KENT','Such groans of roaring wind and rain, I never'),
('king_lear_act3_scene2',34,34,'KENT','Remember to have heard: man’s nature cannot carry'),
('king_lear_act3_scene2',35,35,'KENT','The affliction nor the fear.'),
('king_lear_act3_scene2',35,36,'KING LEAR','Let the great gods,'),
('king_lear_act3_scene2',36,37,'KING LEAR','That keep this dreadful pother o’er our heads,'),
('king_lear_act3_scene2',37,38,'KING LEAR','Find out their enemies now. Tremble, thou wretch,'),
('king_lear_act3_scene2',38,39,'KING LEAR','That hast within thee undivulged crimes,'),
('king_lear_act3_scene2',39,40,'KING LEAR','Unwhipp’d of justice: hide thee, thou bloody hand;'),
('king_lear_act3_scene2',40,41,'KING LEAR','Thou perjured, and thou simular man of virtue'),
('king_lear_act3_scene2',41,42,'KING LEAR','That art incestuous: caitiff, to pieces shake,'),
('king_lear_act3_scene2',42,43,'KING LEAR','That under covert and convenient seeming'),
('king_lear_act3_scene2',43,44,'KING LEAR','Hast practised on man’s life: close pent-up guilts,'),
('king_lear_act3_scene2',44,45,'KING LEAR','Rive your concealing continents, and cry'),
('king_lear_act3_scene2',45,46,'KING LEAR','These dreadful summoners grace. I am a man'),
('king_lear_act3_scene2',46,47,'KING LEAR','More sinn’d against than sinning.'),
('king_lear_act3_scene2',46,48,'KENT','Alack, bare-headed!'),
('king_lear_act3_scene2',47,49,'KENT','Gracious my lord, hard by here is a hovel;'),
('king_lear_act3_scene2',48,50,'KENT','Some friendship will it lend you ’gainst the tempest:'),
('king_lear_act3_scene2',49,51,'KENT','Repose you there; while I to this hard house—'),
('king_lear_act3_scene2',50,52,'KENT','More harder than the stones whereof ’tis raised;'),
('king_lear_act3_scene2',51,53,'KENT','Which even but now, demanding after you,'),
('king_lear_act3_scene2',52,54,'KENT','Denied me to come in—return, and force'),
('king_lear_act3_scene2',53,55,'KENT','Their scanted courtesy.'),
('king_lear_act3_scene2',53,56,'KING LEAR','My wits begin to turn.'),
('king_lear_act3_scene2',54,57,'KING LEAR','Come on, my boy: how dost, my boy? art cold?'),
('king_lear_act3_scene2',55,58,'KING LEAR','I am cold myself. Where is this straw, my fellow?'),
('king_lear_act3_scene2',56,59,'KING LEAR','The art of our necessities is strange,'),
('king_lear_act3_scene2',57,60,'KING LEAR','That can make vile things precious. Come, your hovel.'),
('king_lear_act3_scene2',58,61,'KING LEAR','Poor fool and knave, I have one part in my heart'),
('king_lear_act3_scene2',59,62,'KING LEAR','That’s sorry yet for thee.'),
('king_lear_act3_scene2',60,63,'FOOL','He that has and a little tiny wit—'),
('king_lear_act3_scene2',61,64,'FOOL','With hey, ho, the wind and the rain—'),
('king_lear_act3_scene2',62,65,'FOOL','Must make content with his fortunes fit,'),
('king_lear_act3_scene2',63,66,'FOOL','For the rain it raineth every day.'),
('king_lear_act3_scene2',64,67,'KING LEAR','True, my good boy. Come, bring us to this hovel.'),
('king_lear_act3_scene2',65,68,'FOOL','This is a brave night to cool a courtezan.'),
('king_lear_act3_scene2',66,69,'FOOL','I’ll speak a prophecy ere I go:'),
('king_lear_act3_scene2',67,70,'FOOL','When priests are more in word than matter;');
INSERT INTO lines (section_id,number,array_index,speaker,text) VALUES
('king_lear_act3_scene2',68,71,'FOOL','When brewers mar their malt with water;'),
('king_lear_act3_scene2',69,72,'FOOL','When nobles are their tailors’ tutors;'),
('king_lear_act3_scene2',70,73,'FOOL','No heretics burn’d, but wenches’ suitors;'),
('king_lear_act3_scene2',71,74,'FOOL','When every case in law is right;'),
('king_lear_act3_scene2',72,75,'FOOL','No squire in debt, nor no poor knight;'),
('king_lear_act3_scene2',73,76,'FOOL','When slanders do not live in tongues;'),
('king_lear_act3_scene2',74,77,'FOOL','Nor cutpurses come not to throngs;'),
('king_lear_act3_scene2',75,78,'FOOL','When usurers tell their gold i’ the field;'),
('king_lear_act3_scene2',76,79,'FOOL','And bawds and whores do churches build;'),
('king_lear_act3_scene2',77,80,'FOOL','Then shall the realm of Albion'),
('king_lear_act3_scene2',78,81,'FOOL','Come to great confusion:'),
('king_lear_act3_scene2',79,82,'FOOL','Then comes the time, who lives to see’t,'),
('king_lear_act3_scene2',80,83,'FOOL','That going shall be used with feet.'),
('king_lear_act3_scene2',81,84,'FOOL','This prophecy Merlin shall make; for I live before his time.'),
('king_lear_act3_scene3',1,0,'GLOUCESTER','Alack, alack, Edmund, I like not this unnatural dealing. When I desire'),
('king_lear_act3_scene3',2,1,'GLOUCESTER','their leave that I might pity him, they took from me the'),
('king_lear_act3_scene3',3,2,'GLOUCESTER','use of mine own house; charged me, on pain of their perpetual'),
('king_lear_act3_scene3',4,3,'GLOUCESTER','displeasure, neither to speak of him, entreat for him, nor any way'),
('king_lear_act3_scene3',5,4,'GLOUCESTER','sustain him.'),
('king_lear_act3_scene3',5,5,'EDMUND','Most savage and unnatural!'),
('king_lear_act3_scene3',6,6,'GLOUCESTER','Go to; say you nothing. There’s a division betwixt the dukes; and'),
('king_lear_act3_scene3',7,7,'GLOUCESTER','a worse matter than that: I have received a letter this night;'),
('king_lear_act3_scene3',8,8,'GLOUCESTER','’tis dangerous to be spoken; I have locked the letter in my'),
('king_lear_act3_scene3',9,9,'GLOUCESTER','closet: these injuries the king now bears will be revenged home; there’s'),
('king_lear_act3_scene3',10,10,'GLOUCESTER','part of a power already footed: we must incline to the king.'),
('king_lear_act3_scene3',11,11,'GLOUCESTER','I will seek him, and privily relieve him: go you and maintain'),
('king_lear_act3_scene3',12,12,'GLOUCESTER','talk with the duke, that my charity be not of him perceived:'),
('king_lear_act3_scene3',13,13,'GLOUCESTER','if he ask for me. I am ill, and gone to bed.'),
('king_lear_act3_scene3',14,14,'GLOUCESTER','Though I die for it, as no less is threatened me, the'),
('king_lear_act3_scene3',15,15,'GLOUCESTER','king my old master must be relieved. There is some strange thing'),
('king_lear_act3_scene3',16,16,'GLOUCESTER','toward, Edmund; pray you, be careful.'),
('king_lear_act3_scene3',17,17,'EDMUND','This courtesy, forbid thee, shall the duke'),
('king_lear_act3_scene3',18,18,'EDMUND','Instantly know; and of that letter too:'),
('king_lear_act3_scene3',19,19,'EDMUND','This seems a fair deserving, and must draw me'),
('king_lear_act3_scene3',20,20,'EDMUND','That which my father loses; no less than all:'),
('king_lear_act3_scene3',21,21,'EDMUND','The younger rises when the old doth fall.'),
('king_lear_act3_scene4',1,0,'KENT','Here is the place, my lord; good my lord, enter:'),
('king_lear_act3_scene4',2,1,'KENT','The tyranny of the open night’s too rough'),
('king_lear_act3_scene4',3,2,'KENT','For nature to endure.'),
('king_lear_act3_scene4',3,3,'KING LEAR','Let me alone.'),
('king_lear_act3_scene4',4,4,'KENT','Good my lord, enter here.'),
('king_lear_act3_scene4',4,5,'KING LEAR','Wilt break my heart?'),
('king_lear_act3_scene4',5,6,'KENT','I had rather break mine own. Good my lord, enter.'),
('king_lear_act3_scene4',6,7,'KING LEAR','Thou think’st ’tis much that this contentious storm'),
('king_lear_act3_scene4',7,8,'KING LEAR','Invades us to the skin: so ’tis to thee;'),
('king_lear_act3_scene4',8,9,'KING LEAR','But where the greater malady is fix’d,'),
('king_lear_act3_scene4',9,10,'KING LEAR','The lesser is scarce felt. Thou’ldst shun a bear;'),
('king_lear_act3_scene4',10,11,'KING LEAR','But if thy flight lay toward the raging sea,'),
('king_lear_act3_scene4',11,12,'KING LEAR','Thou’ldst meet the bear i’ the mouth. When the mind’s free,'),
('king_lear_act3_scene4',12,13,'KING LEAR','The body’s delicate: the tempest in my mind'),
('king_lear_act3_scene4',13,14,'KING LEAR','Doth from my senses take all feeling else'),
('king_lear_act3_scene4',14,15,'KING LEAR','Save what beats there. Filial ingratitude!'),
('king_lear_act3_scene4',15,16,'KING LEAR','Is it not as this mouth should tear this hand'),
('king_lear_act3_scene4',16,17,'KING LEAR','For lifting food to’t? But I will punish home:'),
('king_lear_act3_scene4',17,18,'KING LEAR','No, I will weep no more. In such a night'),
('king_lear_act3_scene4',18,19,'KING LEAR','To shut me out! Pour on; I will endure.'),
('king_lear_act3_scene4',19,20,'KING LEAR','In such a night as this! O Regan, Goneril!'),
('king_lear_act3_scene4',20,21,'KING LEAR','Your old kind father, whose frank heart gave all—'),
('king_lear_act3_scene4',21,22,'KING LEAR','O, that way madness lies; let me shun that;'),
('king_lear_act3_scene4',22,23,'KING LEAR','No more of that.'),
('king_lear_act3_scene4',22,24,'KENT','Good my lord, enter here.'),
('king_lear_act3_scene4',23,25,'KING LEAR','Prithee, go in thyself: seek thine own ease:'),
('king_lear_act3_scene4',24,26,'KING LEAR','This tempest will not give me leave to ponder'),
('king_lear_act3_scene4',25,27,'KING LEAR','On things would hurt me more. But I’ll go in.'),
('king_lear_act3_scene4',26,28,'KING LEAR','To the Fool. In, boy; go first. You houseless poverty—'),
('king_lear_act3_scene4',27,29,'KING LEAR','Nay, get thee in. I’ll pray, and then I’ll sleep. Fool goes in.'),
('king_lear_act3_scene4',28,30,'KING LEAR','Poor naked wretches, whereso’er you are,'),
('king_lear_act3_scene4',29,31,'KING LEAR','That bide the pelting of this pitiless storm,'),
('king_lear_act3_scene4',30,32,'KING LEAR','How shall your houseless heads and unfed sides,'),
('king_lear_act3_scene4',31,33,'KING LEAR','Your loop’d and window’d raggedness, defend you'),
('king_lear_act3_scene4',32,34,'KING LEAR','From seasons such as these? O, I have ta’en'),
('king_lear_act3_scene4',33,35,'KING LEAR','Too little care of this! Take physic, pomp;'),
('king_lear_act3_scene4',34,36,'KING LEAR','Expose thyself to feel what wretches feel,'),
('king_lear_act3_scene4',35,37,'KING LEAR','That thou mayst shake the superflux to them,'),
('king_lear_act3_scene4',36,38,'KING LEAR','And show the heavens more just.'),
('king_lear_act3_scene4',37,39,'EDGAR','Fathom and half, fathom and half! Poor Tom!'),
('king_lear_act3_scene4',38,40,'FOOL','Come not in here, nuncle, here’s a spirit. Help me, help me!'),
('king_lear_act3_scene4',39,41,'KENT','Give me thy hand. Who’s there?'),
('king_lear_act3_scene4',40,42,'FOOL','A spirit, a spirit: he says his name’s poor Tom.'),
('king_lear_act3_scene4',41,43,'KENT','What art thou that dost grumble there i’ the straw? Come forth.'),
('king_lear_act3_scene4',42,44,'EDGAR','Away! the foul fiend follows me!'),
('king_lear_act3_scene4',43,45,'EDGAR','Through the sharp hawthorn blows the cold wind.'),
('king_lear_act3_scene4',44,46,'EDGAR','Hum! go to thy cold bed, and warm thee.'),
('king_lear_act3_scene4',45,47,'KING LEAR','Hast thou given all to thy two daughters?'),
('king_lear_act3_scene4',46,48,'KING LEAR','And art thou come to this?'),
('king_lear_act3_scene4',47,49,'EDGAR','Who gives any thing to poor Tom? whom the foul fiend hath'),
('king_lear_act3_scene4',48,50,'EDGAR','led through fire and through flame, and through ford and whirlipool e’er'),
('king_lear_act3_scene4',49,51,'EDGAR','bog and quagmire; that hath laid knives under his pillow, and halters'),
('king_lear_act3_scene4',50,52,'EDGAR','in his pew; set ratsbane by his porridge; made him proud of'),
('king_lear_act3_scene4',51,53,'EDGAR','heart, to ride on a bay trotting-horse over four-inched bridges, to course'),
('king_lear_act3_scene4',52,54,'EDGAR','his own shadow for a traitor. Bless thy five wits! Tom’s a-cold—O,'),
('king_lear_act3_scene4',53,55,'EDGAR','do de, do de, do de. Bless thee from whirlwinds, star-blasting, and'),
('king_lear_act3_scene4',54,56,'EDGAR','taking! Do poor Tom some charity, whom the foul fiend vexes: there'),
('king_lear_act3_scene4',55,57,'EDGAR','could I have him now—and there—and there again, and there.'),
('king_lear_act3_scene4',56,58,'KING LEAR','What, have his daughters brought him to this pass?'),
('king_lear_act3_scene4',57,59,'KING LEAR','Couldst thou save nothing? Didst thou give them all?'),
('king_lear_act3_scene4',58,60,'FOOL','Nay, he reserved a blanket, else we had been all shamed.'),
('king_lear_act3_scene4',59,61,'KING LEAR','Now, all the plagues that in the pendulous air'),
('king_lear_act3_scene4',60,62,'KING LEAR','Hang fated o’er men’s faults light on thy daughters!'),
('king_lear_act3_scene4',61,63,'KENT','He hath no daughters, sir.'),
('king_lear_act3_scene4',62,64,'KING LEAR','Death, traitor! nothing could have subdued nature'),
('king_lear_act3_scene4',63,65,'KING LEAR','To such a lowness but his unkind daughters.'),
('king_lear_act3_scene4',64,66,'KING LEAR','Is it the fashion, that discarded fathers'),
('king_lear_act3_scene4',65,67,'KING LEAR','Should have thus little mercy on their flesh?'),
('king_lear_act3_scene4',66,68,'KING LEAR','Judicious punishment! ’twas this flesh begot'),
('king_lear_act3_scene4',67,69,'KING LEAR','Those pelican daughters.'),
('king_lear_act3_scene4',68,70,'EDGAR','Pillicock sat on Pillicock-hill: Halloo, halloo, loo, loo!'),
('king_lear_act3_scene4',69,71,'FOOL','This cold night will turn us all to fools and madmen.'),
('king_lear_act3_scene4',70,72,'EDGAR','Take heed o’ the foul fiend: obey thy parents; keep thy word'),
('king_lear_act3_scene4',71,73,'EDGAR','justly; swear not; commit not with man’s sworn spouse; set not thy'),
('king_lear_act3_scene4',72,74,'EDGAR','sweet heart on proud array. Tom’s a-cold.'),
('king_lear_act3_scene4',73,75,'KING LEAR','What hast thou been?'),
('king_lear_act3_scene4',74,76,'EDGAR','A serving-man, proud in heart and mind; that curled my hair; wore'),
('king_lear_act3_scene4',75,77,'EDGAR','gloves in my cap; served the lust of my mistress’ heart, and'),
('king_lear_act3_scene4',76,78,'EDGAR','did the act of darkness with her; swore as many oaths as'),
('king_lear_act3_scene4',77,79,'EDGAR','I spake words, and broke them in the sweet face of heaven:'),
('king_lear_act3_scene4',78,80,'EDGAR','one that slept in the contriving of lust, and waked to do'),
('king_lear_act3_scene4',79,81,'EDGAR','it: wine loved I deeply, dice dearly: and in woman out-paramoured the'),
('king_lear_act3_scene4',80,82,'EDGAR','Turk: false of heart, light of ear, bloody of hand; hog in'),
('king_lear_act3_scene4',81,83,'EDGAR','sloth, fox in stealth, wolf in greediness, dog in madness, lion in'),
('king_lear_act3_scene4',82,84,'EDGAR','prey. Let not the creaking of shoes nor the rustling of silks'),
('king_lear_act3_scene4',83,85,'EDGAR','betray thy poor heart to woman: keep thy foot out of brothels,'),
('king_lear_act3_scene4',84,86,'EDGAR','thy hand out of plackets, thy pen from lenders’ books, and defy'),
('king_lear_act3_scene4',85,87,'EDGAR','the foul fiend. Still through the hawthorn blows the cold wind: Says'),
('king_lear_act3_scene4',86,88,'EDGAR','suum, mun, ha, no, nonny. Dolphin my boy, my boy, sessa! let'),
('king_lear_act3_scene4',87,89,'EDGAR','him trot by.'),
('king_lear_act3_scene4',88,90,'KING LEAR','Why, thou wert better in thy grave than to answer with thy'),
('king_lear_act3_scene4',89,91,'KING LEAR','uncovered body this extremity of the skies. Is man no more than'),
('king_lear_act3_scene4',90,92,'KING LEAR','this? Consider him well. Thou owest the worm no silk, the beast'),
('king_lear_act3_scene4',91,93,'KING LEAR','no hide, the sheep no wool, the cat no perfume. Ha! here’s'),
('king_lear_act3_scene4',92,94,'KING LEAR','three on ’s are sophisticated! Thou art the thing itself: unaccommodated man'),
('king_lear_act3_scene4',93,95,'KING LEAR','is no more but such a poor bare, forked animal as thou'),
('king_lear_act3_scene4',94,96,'KING LEAR','art. Off, off, you lendings! come unbutton here. Tearing off his clothes.'),
('king_lear_act3_scene4',95,97,'FOOL','Prithee, nuncle, be contented; ’tis a naughty night to swim in. Now'),
('king_lear_act3_scene4',96,98,'FOOL','a little fire in a wild field were like an old lecher’s'),
('king_lear_act3_scene4',97,99,'FOOL','heart; a small spark, all the rest on’s body cold. Look, here'),
('king_lear_act3_scene4',98,100,'FOOL','comes a walking fire.'),
('king_lear_act3_scene4',99,101,'EDGAR','This is the foul fiend Flibbertigibbet: he begins at curfew, and walks'),
('king_lear_act3_scene4',100,102,'EDGAR','till the first cock; he gives the web and the pin, squints'),
('king_lear_act3_scene4',101,103,'EDGAR','the eye, and makes the hare-lip; mildews the white wheat, and hurts'),
('king_lear_act3_scene4',102,104,'EDGAR','the poor creature of earth.'),
('king_lear_act3_scene4',102,105,'KENT','How fares your grace?'),
('king_lear_act3_scene4',103,106,'KING LEAR','What’s he?'),
('king_lear_act3_scene4',103,107,'KENT','Who’s there? What is’t you seek?'),
('king_lear_act3_scene4',104,108,'GLOUCESTER','What are you there? Your names?'),
('king_lear_act3_scene4',105,109,'EDGAR','Poor Tom; that eats the swimming frog, the toad, the tadpole, the'),
('king_lear_act3_scene4',106,110,'EDGAR','wall-newt and the water; that in the fury of his heart, when'),
('king_lear_act3_scene4',107,111,'EDGAR','the foul fiend rages, eats cow-dung for sallets; swallows the old rat'),
('king_lear_act3_scene4',108,112,'EDGAR','and the ditch-dog; drinks the green mantle of the standing pool; who'),
('king_lear_act3_scene4',109,113,'EDGAR','is whipped from tithing to tithing, and stock-punished, and imprisoned; who hath'),
('king_lear_act3_scene4',110,114,'EDGAR','had three suits to his back, six shirts to his body, horse'),
('king_lear_act3_scene4',111,115,'EDGAR','to ride, and weapon to wear;'),
('king_lear_act3_scene4',112,116,'GLOUCESTER','What, hath your grace no better company?'),
('king_lear_act3_scene4',113,117,'EDGAR','The prince of darkness is a gentleman: Modo he’s call’d, and Mahu.'),
('king_lear_act3_scene4',114,118,'GLOUCESTER','Our flesh and blood is grown so vile, my lord,'),
('king_lear_act3_scene4',115,119,'GLOUCESTER','That it doth hate what gets it.'),
('king_lear_act3_scene4',116,120,'EDGAR','Poor Tom’s a-cold.'),
('king_lear_act3_scene4',117,121,'GLOUCESTER','Go in with me: my duty cannot suffer'),
('king_lear_act3_scene4',118,122,'GLOUCESTER','To obey in all your daughters’ hard commands:'),
('king_lear_act3_scene4',119,123,'GLOUCESTER','Though their injunction be to bar my doors,'),
('king_lear_act3_scene4',120,124,'GLOUCESTER','And let this tyrannous night take hold upon you,'),
('king_lear_act3_scene4',121,125,'GLOUCESTER','Yet have I ventured to come seek you out,'),
('king_lear_act3_scene4',122,126,'GLOUCESTER','And bring you where both fire and food is ready.'),
('king_lear_act3_scene4',123,127,'KING LEAR','First let me talk with this philosopher.'),
('king_lear_act3_scene4',124,128,'KING LEAR','What is the cause of thunder?'),
('king_lear_act3_scene4',125,129,'KENT','Good my lord, take his offer; go into the house.'),
('king_lear_act3_scene4',126,130,'KING LEAR','I’ll talk a word with this same learned Theban.'),
('king_lear_act3_scene4',127,131,'KING LEAR','What is your study?'),
('king_lear_act3_scene4',128,132,'EDGAR','How to prevent the fiend, and to kill vermin.'),
('king_lear_act3_scene4',129,133,'KING LEAR','Let me ask you one word in private.'),
('king_lear_act3_scene4',130,134,'KENT','Importune him once more to go, my lord;'),
('king_lear_act3_scene4',131,135,'KENT','His wits begin to unsettle.'),
('king_lear_act3_scene4',131,136,'GLOUCESTER','Canst thou blame him?'),
('king_lear_act3_scene4',132,137,'GLOUCESTER','His daughters seek his death: ah, that good Kent!'),
('king_lear_act3_scene4',133,138,'GLOUCESTER','He said it would be thus, poor banish’d man!'),
('king_lear_act3_scene4',134,139,'GLOUCESTER','Thou say’st the king grows mad; I’ll tell thee, friend,'),
('king_lear_act3_scene4',135,140,'GLOUCESTER','I am almost mad myself: I had a son,'),
('king_lear_act3_scene4',136,141,'GLOUCESTER','Now outlaw’d from my blood; he sought my life,'),
('king_lear_act3_scene4',137,142,'GLOUCESTER','But lately, very late: I loved him, friend;'),
('king_lear_act3_scene4',138,143,'GLOUCESTER','No father his son dearer: truth to tell thee,'),
('king_lear_act3_scene4',139,144,'GLOUCESTER','The grief hath crazed my wits. What a night’s this!'),
('king_lear_act3_scene4',140,145,'GLOUCESTER','I do beseech your grace—'),
('king_lear_act3_scene4',141,146,'KING LEAR','O, cry your mercy, sir. Noble philosopher, your company.'),
('king_lear_act3_scene4',142,147,'EDGAR','Tom’s a-cold.'),
('king_lear_act3_scene4',143,148,'GLOUCESTER','In, fellow, there, into the hovel: keep thee warm.'),
('king_lear_act3_scene4',144,149,'KING LEAR','Come let’s in all.'),
('king_lear_act3_scene4',144,150,'KENT','This way, my lord.'),
('king_lear_act3_scene4',145,151,'KING LEAR','With him; I will keep still with my philosopher.'),
('king_lear_act3_scene4',146,152,'KENT','Good my lord, soothe him; let him take the fellow.'),
('king_lear_act3_scene4',147,153,'GLOUCESTER','Take him you on.'),
('king_lear_act3_scene4',148,154,'KENT','Sirrah, come on; go along with us.'),
('king_lear_act3_scene4',149,155,'KING LEAR','Come, good Athenian.'),
('king_lear_act3_scene4',149,156,'GLOUCESTER','No words, no words: hush.'),
('king_lear_act3_scene4',150,157,'EDGAR','Child Rowland to the dark tower came,'),
('king_lear_act3_scene4',151,158,'EDGAR','His word was still—Fie, foh, and fum,'),
('king_lear_act3_scene4',152,159,'EDGAR','I smell the blood of a British man.'),
('king_lear_act3_scene5',1,0,'CORNWALL','I will have my revenge ere I depart his house.'),
('king_lear_act3_scene5',2,1,'EDMUND','How, my lord, I may be censured, that nature thus gives way'),
('king_lear_act3_scene5',3,2,'EDMUND','to loyalty, something fears me to think of.'),
('king_lear_act3_scene5',4,3,'CORNWALL','I now perceive, it was not altogether your brother’s evil disposition made'),
('king_lear_act3_scene5',5,4,'CORNWALL','him seek his death; but a provoking merit, set a-work by a'),
('king_lear_act3_scene5',6,5,'CORNWALL','reprovable badness in himself.'),
('king_lear_act3_scene5',7,6,'EDMUND','How malicious is my fortune, that I must repent to be just!'),
('king_lear_act3_scene5',8,7,'EDMUND','This is the letter he spoke of, which approves him an intelligent'),
('king_lear_act3_scene5',9,8,'EDMUND','party to the advantages of France: O heavens! that this treason were'),
('king_lear_act3_scene5',10,9,'EDMUND','not, or not I the detector!'),
('king_lear_act3_scene5',10,10,'CORNWALL','Go with me to the duchess.'),
('king_lear_act3_scene5',11,11,'EDMUND','If the matter of this paper be certain, you have mighty business in hand.'),
('king_lear_act3_scene5',12,12,'CORNWALL','True or false, it hath made thee earl of Gloucester. Seek out'),
('king_lear_act3_scene5',13,13,'CORNWALL','where thy father is, that he may be ready for our apprehension.'),
('king_lear_act3_scene5',14,14,'EDMUND','If I find him comforting the king, it will stuff his suspicion'),
('king_lear_act3_scene5',15,15,'EDMUND','more fully.—I will persevere in my course of loyalty, though the conflict'),
('king_lear_act3_scene5',16,16,'EDMUND','be sore between that and my blood.'),
('king_lear_act3_scene5',17,17,'CORNWALL','I will lay trust upon thee; and thou shalt find a dearer'),
('king_lear_act3_scene5',18,18,'CORNWALL','father in my love.'),
('king_lear_act3_scene6',1,0,'GLOUCESTER','Here is better than the open air; take it thankfully. I will'),
('king_lear_act3_scene6',2,1,'GLOUCESTER','piece out the comfort with what addition I can: I will not'),
('king_lear_act3_scene6',3,2,'GLOUCESTER','be long from you.'),
('king_lear_act3_scene6',4,3,'KENT','All the power of his wits have given way to his impatience:'),
('king_lear_act3_scene6',5,4,'KENT','the gods reward your kindness!'),
('king_lear_act3_scene6',5,5,'EDGAR','Frateretto calls me; and tells me'),
('king_lear_act3_scene6',6,6,'EDGAR','Nero is an angler in the lake of darkness.'),
('king_lear_act3_scene6',7,7,'EDGAR','Pray, innocent, and beware the foul fiend.'),
('king_lear_act3_scene6',8,8,'FOOL','Prithee, nuncle, tell me whether a madman be a gentleman or a yeoman?'),
('king_lear_act3_scene6',9,9,'KING LEAR','A king, a king!'),
('king_lear_act3_scene6',10,10,'FOOL','No, he’s a yeoman that has a gentleman to his son; for'),
('king_lear_act3_scene6',11,11,'FOOL','he’s a mad yeoman that sees his son a gentleman before him.'),
('king_lear_act3_scene6',12,12,'KING LEAR','To have a thousand with red burning spits'),
('king_lear_act3_scene6',13,13,'KING LEAR','Come hissing in upon ’em—'),
('king_lear_act3_scene6',13,14,'EDGAR','The foul fiend bites my back.'),
('king_lear_act3_scene6',14,15,'FOOL','He’s mad that trusts in the tameness of a wolf, a horse’s'),
('king_lear_act3_scene6',15,16,'FOOL','health, a boy’s love, or a whore’s oath.'),
('king_lear_act3_scene6',16,17,'KING LEAR','It shall be done; I will arraign them straight.'),
('king_lear_act3_scene6',17,18,'KING LEAR','To Edgar. Come, sit thou here, most learned justicer;'),
('king_lear_act3_scene6',18,19,'KING LEAR','To the Fool. Thou, sapient sir, sit here. Now, you she foxes!'),
('king_lear_act3_scene6',19,20,'EDGAR','Look, where he stands and glares!'),
('king_lear_act3_scene6',20,21,'EDGAR','Wantest thou eyes at trial, madam?'),
('king_lear_act3_scene6',21,22,'EDGAR','Come o’er the bourn, Bessy, to me—'),
('king_lear_act3_scene6',22,23,'FOOL','Her boat hath a leak,'),
('king_lear_act3_scene6',23,24,'FOOL','And she must not speak'),
('king_lear_act3_scene6',24,25,'FOOL','Why she dares not come over to thee.'),
('king_lear_act3_scene6',25,26,'EDGAR','The foul fiend haunts poor Tom in the voice of a nightingale.'),
('king_lear_act3_scene6',26,27,'EDGAR','Hopdance cries in Tom’s belly for two white herring. Croak not, black'),
('king_lear_act3_scene6',27,28,'EDGAR','angel; I have no food for thee.'),
('king_lear_act3_scene6',28,29,'KENT','How do you, sir? Stand you not so amazed:'),
('king_lear_act3_scene6',29,30,'KENT','Will you lie down and rest upon the cushions?'),
('king_lear_act3_scene6',30,31,'KING LEAR','I’ll see their trial first. Bring in the evidence.'),
('king_lear_act3_scene6',31,32,'KING LEAR','To Edgar. Thou robed man of justice, take thy place;'),
('king_lear_act3_scene6',32,33,'KING LEAR','To the Fool. And thou, his yoke-fellow of equity,'),
('king_lear_act3_scene6',33,34,'KING LEAR','Bench by his side: To Kent. you are o’ the commission,'),
('king_lear_act3_scene6',34,35,'KING LEAR','Sit you too.'),
('king_lear_act3_scene6',34,36,'EDGAR','Let us deal justly.'),
('king_lear_act3_scene6',35,37,'EDGAR','Sleepest or wakest thou, jolly shepherd?'),
('king_lear_act3_scene6',36,38,'EDGAR','Thy sheep be in the corn;'),
('king_lear_act3_scene6',37,39,'EDGAR','And for one blast of thy minikin mouth,'),
('king_lear_act3_scene6',38,40,'EDGAR','Thy sheep shall take no harm.'),
('king_lear_act3_scene6',39,41,'EDGAR','Pur! the cat is gray.'),
('king_lear_act3_scene6',40,42,'KING LEAR','Arraign her first; ’tis Goneril. I here take my'),
('king_lear_act3_scene6',41,43,'KING LEAR','oath before this honourable assembly, she kicked the'),
('king_lear_act3_scene6',42,44,'KING LEAR','poor king her father.'),
('king_lear_act3_scene6',43,45,'FOOL','Come hither, mistress. Is your name Goneril?'),
('king_lear_act3_scene6',44,46,'KING LEAR','She cannot deny it.'),
('king_lear_act3_scene6',45,47,'FOOL','Cry you mercy, I took you for a joint-stool.'),
('king_lear_act3_scene6',46,48,'KING LEAR','And here’s another, whose warp’d looks proclaim'),
('king_lear_act3_scene6',47,49,'KING LEAR','What store her heart is made on. Stop her there!'),
('king_lear_act3_scene6',48,50,'KING LEAR','Arms, arms, sword, fire! Corruption in the place!'),
('king_lear_act3_scene6',49,51,'KING LEAR','False justicer, why hast thou let her ’scape?'),
('king_lear_act3_scene6',50,52,'EDGAR','Bless thy five wits!'),
('king_lear_act3_scene6',51,53,'KENT','O pity! Sir, where is the patience now,'),
('king_lear_act3_scene6',52,54,'KENT','That thou so oft have boasted to retain?'),
('king_lear_act3_scene6',53,55,'EDGAR','My tears begin to take his part so much,'),
('king_lear_act3_scene6',54,56,'EDGAR','They’ll mar my counterfeiting.'),
('king_lear_act3_scene6',55,57,'KING LEAR','The little dogs and all, Tray, Blanch, and'),
('king_lear_act3_scene6',56,58,'KING LEAR','Sweet-heart, see, they bark at me.'),
('king_lear_act3_scene6',57,59,'EDGAR','Tom will throw his head at them. Avaunt, you curs!'),
('king_lear_act3_scene6',58,60,'EDGAR','Be thy mouth or black or white,'),
('king_lear_act3_scene6',59,61,'EDGAR','Tooth that poisons if it bite;'),
('king_lear_act3_scene6',60,62,'EDGAR','Mastiff, grey-hound, mongrel grim,'),
('king_lear_act3_scene6',61,63,'EDGAR','Hound or spaniel, brach or lym,'),
('king_lear_act3_scene6',62,64,'EDGAR','Or bobtail tike or trundle-tail,'),
('king_lear_act3_scene6',63,65,'EDGAR','Tom will make them weep and wail:'),
('king_lear_act3_scene6',64,66,'EDGAR','For, with throwing thus my head,'),
('king_lear_act3_scene6',65,67,'EDGAR','Dogs leap the hatch, and all are fled.'),
('king_lear_act3_scene6',66,68,'KING LEAR','Then let them anatomize Regan; see what breeds about her heart. Is'),
('king_lear_act3_scene6',67,69,'KING LEAR','there any cause in nature that makes these hard hearts? To Edgar.'),
('king_lear_act3_scene6',68,70,'KING LEAR','You, sir, I entertain for one of my hundred; only I do'),
('king_lear_act3_scene6',69,71,'KING LEAR','not like the fashion of your garments: you will say they are'),
('king_lear_act3_scene6',70,72,'KING LEAR','Persian attire: but let them be changed.'),
('king_lear_act3_scene6',71,73,'KENT','Now, good my lord, lie here and rest awhile.'),
('king_lear_act3_scene6',72,74,'KING LEAR','Make no noise, make no noise; draw the curtains: so, so, so.'),
('king_lear_act3_scene6',73,75,'KING LEAR','We’ll go to supper i’ he morning. So, so, so.'),
('king_lear_act3_scene6',74,76,'FOOL','And I’ll go to bed at noon.'),
('king_lear_act3_scene6',75,77,'GLOUCESTER','Come hither, friend: where is the king my master?'),
('king_lear_act3_scene6',76,78,'KENT','Here, sir; but trouble him not, his wits are gone.'),
('king_lear_act3_scene6',77,79,'GLOUCESTER','Good friend, I prithee, take him in thy arms;'),
('king_lear_act3_scene6',78,80,'GLOUCESTER','I have o’erheard a plot of death upon him:'),
('king_lear_act3_scene6',79,81,'GLOUCESTER','There is a litter ready; lay him in ’t,'),
('king_lear_act3_scene6',80,82,'GLOUCESTER','And drive towards Dover, friend, where thou shalt meet'),
('king_lear_act3_scene6',81,83,'GLOUCESTER','Both welcome and protection. Take up thy master:'),
('king_lear_act3_scene6',82,84,'GLOUCESTER','If thou shouldst dally half an hour, his life,'),
('king_lear_act3_scene6',83,85,'GLOUCESTER','With thine, and all that offer to defend him,'),
('king_lear_act3_scene6',84,86,'GLOUCESTER','Stand in assured loss: take up, take up;'),
('king_lear_act3_scene6',85,87,'GLOUCESTER','And follow me, that will to some provision'),
('king_lear_act3_scene6',86,88,'GLOUCESTER','Give thee quick conduct.'),
('king_lear_act3_scene6',86,89,'KENT','Oppressed nature sleeps:'),
('king_lear_act3_scene6',87,90,'KENT','This rest might yet have balm’d thy broken senses,'),
('king_lear_act3_scene6',88,91,'KENT','Which, if convenience will not allow,'),
('king_lear_act3_scene6',89,92,'KENT','Stand in hard cure.'),
('king_lear_act3_scene6',90,93,'KENT','To the Fool. Come, help to bear thy master;'),
('king_lear_act3_scene6',91,94,'KENT','Thou must not stay behind.'),
('king_lear_act3_scene6',91,95,'GLOUCESTER','Come, come, away.'),
('king_lear_act3_scene6',92,96,'EDGAR','When we our betters see bearing our woes,'),
('king_lear_act3_scene6',93,97,'EDGAR','We scarcely think our miseries our foes.'),
('king_lear_act3_scene6',94,98,'EDGAR','Who alone suffers suffers most i’ the mind,'),
('king_lear_act3_scene6',95,99,'EDGAR','Leaving free things and happy shows behind:'),
('king_lear_act3_scene6',96,100,'EDGAR','But then the mind much sufferance doth o’er skip,'),
('king_lear_act3_scene6',97,101,'EDGAR','When grief hath mates, and bearing fellowship.'),
('king_lear_act3_scene6',98,102,'EDGAR','How light and portable my pain seems now,'),
('king_lear_act3_scene6',99,103,'EDGAR','When that which makes me bend makes the king bow,'),
('king_lear_act3_scene6',100,104,'EDGAR','He childed as I father’d! Tom, away!'),
('king_lear_act3_scene6',101,105,'EDGAR','Mark the high noises; and thyself bewray,'),
('king_lear_act3_scene6',102,106,'EDGAR','When false opinion, whose wrong thought defiles thee,'),
('king_lear_act3_scene6',103,107,'EDGAR','In thy just proof, repeals and reconciles thee.'),
('king_lear_act3_scene6',104,108,'EDGAR','What will hap more to-night, safe ’scape the king!'),
('king_lear_act3_scene6',105,109,'EDGAR','Lurk, lurk.'),
('king_lear_act3_scene7',1,0,'CORNWALL','Post speedily to my lord your husband; show him this letter: the'),
('king_lear_act3_scene7',2,1,'CORNWALL','army of France is landed. Seek out the villain Gloucester.'),
('king_lear_act3_scene7',3,2,'REGAN','Hang him instantly.'),
('king_lear_act3_scene7',3,3,'GONERIL','Pluck out his eyes.'),
('king_lear_act3_scene7',4,4,'CORNWALL','Leave him to my displeasure. Edmund, keep you our sister company: the'),
('king_lear_act3_scene7',5,5,'CORNWALL','revenges we are bound to take upon your traitorous father are not'),
('king_lear_act3_scene7',6,6,'CORNWALL','fit for your beholding. Advise the duke, where you are going, to'),
('king_lear_act3_scene7',7,7,'CORNWALL','a most festinate preparation: we are bound to the like. Our posts'),
('king_lear_act3_scene7',8,8,'CORNWALL','shall be swift and intelligent betwixt us. Farewell, dear sister: farewell, my'),
('king_lear_act3_scene7',9,9,'CORNWALL','lord of Gloucester.'),
('king_lear_act3_scene7',10,10,'OSWALD','My lord of Gloucester hath convey’d him hence:'),
('king_lear_act3_scene7',11,11,'OSWALD','Some five or six and thirty of his knights,'),
('king_lear_act3_scene7',12,12,'OSWALD','Hot questrists after him, met him at gate;'),
('king_lear_act3_scene7',13,13,'OSWALD','Who, with some other of the lords dependants,'),
('king_lear_act3_scene7',14,14,'OSWALD','Are gone with him towards Dover; where they boast'),
('king_lear_act3_scene7',15,15,'OSWALD','To have well-armed friends.'),
('king_lear_act3_scene7',15,16,'CORNWALL','Get horses for your mistress.'),
('king_lear_act3_scene7',16,17,'GONERIL','Farewell, sweet lord, and sister.'),
('king_lear_act3_scene7',16,18,'CORNWALL','Edmund, farewell.'),
('king_lear_act3_scene7',17,19,'CORNWALL','Go seek the traitor Gloucester,'),
('king_lear_act3_scene7',18,20,'CORNWALL','Pinion him like a thief, bring him before us.'),
('king_lear_act3_scene7',19,21,'CORNWALL','Though well we may not pass upon his life'),
('king_lear_act3_scene7',20,22,'CORNWALL','Without the form of justice, yet our power'),
('king_lear_act3_scene7',21,23,'CORNWALL','Shall do a courtesy to our wrath, which men'),
('king_lear_act3_scene7',22,24,'CORNWALL','May blame, but not control. Who’s there? the traitor?'),
('king_lear_act3_scene7',23,25,'REGAN','Ingrateful fox! ’tis he.'),
('king_lear_act3_scene7',23,26,'CORNWALL','Bind fast his corky arms.'),
('king_lear_act3_scene7',24,27,'GLOUCESTER','What mean your graces? Good my friends, consider'),
('king_lear_act3_scene7',25,28,'GLOUCESTER','You are my guests: do me no foul play, friends.'),
('king_lear_act3_scene7',26,29,'CORNWALL','Bind him, I say. Servants bind him.'),
('king_lear_act3_scene7',27,30,'REGAN','Hard, hard. O filthy traitor!'),
('king_lear_act3_scene7',28,31,'GLOUCESTER','Unmerciful lady as you are, I’m none.'),
('king_lear_act3_scene7',29,32,'CORNWALL','To this chair bind him. Villain, thou shalt find—Regan plucks his beard.'),
('king_lear_act3_scene7',30,33,'GLOUCESTER','By the kind gods, ’tis most ignobly done'),
('king_lear_act3_scene7',31,34,'GLOUCESTER','To pluck me by the beard.'),
('king_lear_act3_scene7',31,35,'REGAN','So white, and such a traitor!'),
('king_lear_act3_scene7',32,36,'GLOUCESTER','Naughty lady,'),
('king_lear_act3_scene7',33,37,'GLOUCESTER','These hairs, which thou dost ravish from my chin,'),
('king_lear_act3_scene7',34,38,'GLOUCESTER','Will quicken, and accuse thee: I am your host:'),
('king_lear_act3_scene7',35,39,'GLOUCESTER','With robbers’ hands my hospitable favours'),
('king_lear_act3_scene7',36,40,'GLOUCESTER','You should not ruffle thus. What will you do?'),
('king_lear_act3_scene7',37,41,'CORNWALL','Come, sir, what letters had you late from France?'),
('king_lear_act3_scene7',38,42,'REGAN','Be simple answerer, for we know the truth.'),
('king_lear_act3_scene7',39,43,'CORNWALL','And what confederacy have you with the traitors'),
('king_lear_act3_scene7',40,44,'CORNWALL','Late footed in the kingdom?'),
('king_lear_act3_scene7',41,45,'REGAN','To whose hands have you sent the lunatic king? Speak.'),
('king_lear_act3_scene7',42,46,'GLOUCESTER','I have a letter guessingly set down,'),
('king_lear_act3_scene7',43,47,'GLOUCESTER','Which came from one that’s of a neutral heart,'),
('king_lear_act3_scene7',44,48,'GLOUCESTER','And not from one opposed.'),
('king_lear_act3_scene7',44,49,'CORNWALL','Cunning.'),
('king_lear_act3_scene7',45,50,'REGAN','And false.'),
('king_lear_act3_scene7',45,51,'CORNWALL','Where hast thou sent the king?'),
('king_lear_act3_scene7',46,52,'GLOUCESTER','To Dover.'),
('king_lear_act3_scene7',47,53,'REGAN','Wherefore to Dover? Wast thou not charged at peril—'),
('king_lear_act3_scene7',48,54,'CORNWALL','Wherefore to Dover? Let him first answer that.'),
('king_lear_act3_scene7',49,55,'GLOUCESTER','I am tied to the stake, and I must stand the course.'),
('king_lear_act3_scene7',50,56,'REGAN','Wherefore to Dover, sir?'),
('king_lear_act3_scene7',51,57,'GLOUCESTER','Because I would not see thy cruel nails'),
('king_lear_act3_scene7',52,58,'GLOUCESTER','Pluck out his poor old eyes; nor thy fierce sister'),
('king_lear_act3_scene7',53,59,'GLOUCESTER','In his anointed flesh stick boarish fangs.'),
('king_lear_act3_scene7',54,60,'GLOUCESTER','The sea, with such a storm as his bare head'),
('king_lear_act3_scene7',55,61,'GLOUCESTER','In hell-black night endured, would have buoy’d up,'),
('king_lear_act3_scene7',56,62,'GLOUCESTER','And quench’d the stelled fires:'),
('king_lear_act3_scene7',57,63,'GLOUCESTER','Yet, poor old heart, he holp the heavens to rain.'),
('king_lear_act3_scene7',58,64,'GLOUCESTER','If wolves had at thy gate howl’d that stern time,'),
('king_lear_act3_scene7',59,65,'GLOUCESTER','Thou shouldst have said “Good porter, turn the key,”'),
('king_lear_act3_scene7',60,66,'GLOUCESTER','All cruels else subscribed: but I shall see'),
('king_lear_act3_scene7',61,67,'GLOUCESTER','The winged vengeance overtake such children.'),
('king_lear_act3_scene7',62,68,'CORNWALL','See’t shalt thou never. Fellows, hold the chair.'),
('king_lear_act3_scene7',63,69,'CORNWALL','Upon these eyes of thine I’ll set my foot.'),
('king_lear_act3_scene7',64,70,'GLOUCESTER','He that will think to live till he be old,'),
('king_lear_act3_scene7',65,71,'GLOUCESTER','Give me some help! O cruel! O you gods!'),
('king_lear_act3_scene7',66,72,'REGAN','One side will mock another; the other too.'),
('king_lear_act3_scene7',67,73,'CORNWALL','If you see vengeance—'),
('king_lear_act3_scene7',67,74,'FIRST SERVANT','Hold your hand, my lord:'),
('king_lear_act3_scene7',68,75,'FIRST SERVANT','I have served you ever since I was a child;'),
('king_lear_act3_scene7',69,76,'FIRST SERVANT','But better service have I never done you'),
('king_lear_act3_scene7',70,77,'FIRST SERVANT','Than now to bid you hold.'),
('king_lear_act3_scene7',70,78,'REGAN','How now, you dog!'),
('king_lear_act3_scene7',71,79,'FIRST SERVANT','If you did wear a beard upon your chin,'),
('king_lear_act3_scene7',72,80,'FIRST SERVANT','I’d shake it on this quarrel. What do you mean?'),
('king_lear_act3_scene7',73,81,'CORNWALL','My villain! They draw and fight.'),
('king_lear_act3_scene7',74,82,'FIRST SERVANT','Nay, then, come on, and take the chance of anger.'),
('king_lear_act3_scene7',75,83,'REGAN','Give me thy sword. A peasant stand up thus!'),
('king_lear_act3_scene7',76,84,'FIRST SERVANT','O, I am slain! My lord, you have one eye left'),
('king_lear_act3_scene7',77,85,'FIRST SERVANT','To see some mischief on him. O!'),
('king_lear_act3_scene7',78,86,'CORNWALL','Lest it see more, prevent it. Out, vile jelly!'),
('king_lear_act3_scene7',79,87,'CORNWALL','Where is thy lustre now?'),
('king_lear_act3_scene7',80,88,'GLOUCESTER','All dark and comfortless. Where’s my son Edmund?'),
('king_lear_act3_scene7',81,89,'GLOUCESTER','Edmund, enkindle all the sparks of nature,'),
('king_lear_act3_scene7',82,90,'GLOUCESTER','To quit this horrid act.'),
('king_lear_act3_scene7',82,91,'REGAN','Out, treacherous villain!'),
('king_lear_act3_scene7',83,92,'REGAN','Thou call’st on him that hates thee: it was he'),
('king_lear_act3_scene7',84,93,'REGAN','That made the overture of thy treasons to us;'),
('king_lear_act3_scene7',85,94,'REGAN','Who is too good to pity thee.'),
('king_lear_act3_scene7',86,95,'GLOUCESTER','O my follies! then Edgar was abused.'),
('king_lear_act3_scene7',87,96,'GLOUCESTER','Kind gods, forgive me that, and prosper him!'),
('king_lear_act3_scene7',88,97,'REGAN','Go thrust him out at gates, and let him smell'),
('king_lear_act3_scene7',89,98,'REGAN','His way to Dover.'),
('king_lear_act3_scene7',90,99,'REGAN','How is’t, my lord? how look you?'),
('king_lear_act3_scene7',91,100,'CORNWALL','I have received a hurt: follow me, lady.'),
('king_lear_act3_scene7',92,101,'CORNWALL','Turn out that eyeless villain; throw this slave'),
('king_lear_act3_scene7',93,102,'CORNWALL','Upon the dunghill. Regan, I bleed apace:'),
('king_lear_act3_scene7',94,103,'CORNWALL','Untimely comes this hurt: give me your arm.'),
('king_lear_act3_scene7',95,104,'SECOND SERVANT','I’ll never care what wickedness I do,'),
('king_lear_act3_scene7',96,105,'SECOND SERVANT','If this man come to good.'),
('king_lear_act3_scene7',96,106,'THIRD SERVANT','If she live long,'),
('king_lear_act3_scene7',97,107,'THIRD SERVANT','And in the end meet the old course of death,'),
('king_lear_act3_scene7',98,108,'THIRD SERVANT','Women will all turn monsters.'),
('king_lear_act3_scene7',99,109,'SECOND SERVANT','Let’s follow the old earl, and get the Bedlam'),
('king_lear_act3_scene7',100,110,'SECOND SERVANT','To lead him where he would: his roguish madness'),
('king_lear_act3_scene7',101,111,'SECOND SERVANT','Allows itself to any thing.'),
('king_lear_act3_scene7',102,112,'THIRD SERVANT','Go thou: I’ll fetch some flax and whites of eggs'),
('king_lear_act3_scene7',103,113,'THIRD SERVANT','To apply to his bleeding face. Now, heaven help him!'),
('king_lear_act4_scene1',1,0,'EDGAR','Yet better thus, and known to be contemn’d,'),
('king_lear_act4_scene1',2,1,'EDGAR','Than still contemn’d and flatter’d. To be worst,'),
('king_lear_act4_scene1',3,2,'EDGAR','The lowest and most dejected thing of fortune,'),
('king_lear_act4_scene1',4,3,'EDGAR','Stands still in esperance, lives not in fear:'),
('king_lear_act4_scene1',5,4,'EDGAR','The lamentable change is from the best;'),
('king_lear_act4_scene1',6,5,'EDGAR','The worst returns to laughter. Welcome, then,'),
('king_lear_act4_scene1',7,6,'EDGAR','Thou unsubstantial air that I embrace!'),
('king_lear_act4_scene1',8,7,'EDGAR','The wretch that thou hast blown unto the worst'),
('king_lear_act4_scene1',9,8,'EDGAR','Owes nothing to thy blasts. But who comes here?'),
('king_lear_act4_scene1',10,9,'EDGAR','My father, poorly led? World, world, O world!'),
('king_lear_act4_scene1',11,10,'EDGAR','But that thy strange mutations make us hate thee,'),
('king_lear_act4_scene1',12,11,'EDGAR','Lie would not yield to age.'),
('king_lear_act4_scene1',13,12,'OLD MAN','O, my good lord, I have been your tenant, and your father’s'),
('king_lear_act4_scene1',14,13,'OLD MAN','tenant, these fourscore years.'),
('king_lear_act4_scene1',15,14,'GLOUCESTER','Away, get thee away; good friend, be gone:'),
('king_lear_act4_scene1',16,15,'GLOUCESTER','Thy comforts can do me no good at all;'),
('king_lear_act4_scene1',17,16,'GLOUCESTER','Thee they may hurt.'),
('king_lear_act4_scene1',18,17,'OLD MAN','Alack, sir, you cannot see your way.'),
('king_lear_act4_scene1',19,18,'GLOUCESTER','I have no way, and therefore want no eyes;'),
('king_lear_act4_scene1',20,19,'GLOUCESTER','I stumbled when I saw: full oft ’tis seen,'),
('king_lear_act4_scene1',21,20,'GLOUCESTER','Our means secure us, and our mere defects'),
('king_lear_act4_scene1',22,21,'GLOUCESTER','Prove our commodities. O dear son Edgar,'),
('king_lear_act4_scene1',23,22,'GLOUCESTER','The food of thy abused father’s wrath!'),
('king_lear_act4_scene1',24,23,'GLOUCESTER','Might I but live to see thee in my touch,'),
('king_lear_act4_scene1',25,24,'GLOUCESTER','I’ld say I had eyes again!'),
('king_lear_act4_scene1',25,25,'OLD MAN','How now! Who’s there?'),
('king_lear_act4_scene1',26,26,'EDGAR','O gods! Who is’t can say “I am at the worst”?'),
('king_lear_act4_scene1',27,27,'EDGAR','I am worse than e’er I was.'),
('king_lear_act4_scene1',28,28,'OLD MAN','’Tis poor mad Tom.'),
('king_lear_act4_scene1',29,29,'EDGAR','And worse I may be yet: the worst is not'),
('king_lear_act4_scene1',30,30,'EDGAR','So long as we can say “This is the worst.”'),
('king_lear_act4_scene1',31,31,'OLD MAN','Fellow, where goest?'),
('king_lear_act4_scene1',31,32,'GLOUCESTER','Is it a beggar-man?'),
('king_lear_act4_scene1',32,33,'OLD MAN','Madman and beggar too.'),
('king_lear_act4_scene1',33,34,'GLOUCESTER','He has some reason, else he could not beg.'),
('king_lear_act4_scene1',34,35,'GLOUCESTER','I’ the last night’s storm I such a fellow saw;'),
('king_lear_act4_scene1',35,36,'GLOUCESTER','Which made me think a man a worm: my son'),
('king_lear_act4_scene1',36,37,'GLOUCESTER','Came then into my mind; and yet my mind'),
('king_lear_act4_scene1',37,38,'GLOUCESTER','Was then scarce friends with him: I have heard more since.'),
('king_lear_act4_scene1',38,39,'GLOUCESTER','As flies to wanton boys, are we to the gods.'),
('king_lear_act4_scene1',39,40,'GLOUCESTER','They kill us for their sport.'),
('king_lear_act4_scene1',39,41,'EDGAR','How should this be?'),
('king_lear_act4_scene1',40,42,'EDGAR','Bad is the trade that must play fool to sorrow,'),
('king_lear_act4_scene1',41,43,'EDGAR','Angering itself and others.—Bless thee, master!'),
('king_lear_act4_scene1',41,44,'GLOUCESTER','Is that the naked fellow?'),
('king_lear_act4_scene1',42,45,'OLD MAN','Ay, my lord.'),
('king_lear_act4_scene1',43,46,'GLOUCESTER','Then, prithee, get thee gone: if, for my sake,'),
('king_lear_act4_scene1',44,47,'GLOUCESTER','Thou wilt o’ertake us, hence a mile or twain,'),
('king_lear_act4_scene1',45,48,'GLOUCESTER','I’ the way toward Dover, do it for ancient love;'),
('king_lear_act4_scene1',46,49,'GLOUCESTER','And bring some covering for this naked soul,'),
('king_lear_act4_scene1',47,50,'GLOUCESTER','Who I’ll entreat to lead me.'),
('king_lear_act4_scene1',47,51,'OLD MAN','Alack, sir, he is mad.'),
('king_lear_act4_scene1',48,52,'GLOUCESTER','’Tis the times’ plague, when madmen lead the blind.'),
('king_lear_act4_scene1',49,53,'GLOUCESTER','Do as I bid thee, or rather do thy pleasure;'),
('king_lear_act4_scene1',50,54,'GLOUCESTER','Above the rest, be gone.'),
('king_lear_act4_scene1',51,55,'OLD MAN','I’ll bring him the best ’parel that I have,'),
('king_lear_act4_scene1',52,56,'OLD MAN','Come on’t what will.'),
('king_lear_act4_scene1',52,57,'GLOUCESTER','Sirrah, naked fellow—'),
('king_lear_act4_scene1',53,58,'EDGAR','Poor Tom’s a-cold. I cannot daub it further.'),
('king_lear_act4_scene1',54,59,'GLOUCESTER','Come hither, fellow.'),
('king_lear_act4_scene1',55,60,'EDGAR','And yet I must.—Bless thy sweet eyes, they bleed.'),
('king_lear_act4_scene1',56,61,'GLOUCESTER','Know’st thou the way to Dover?'),
('king_lear_act4_scene1',57,62,'EDGAR','Both stile and gate, horse-way and foot-path. Poor Tom hath been scared'),
('king_lear_act4_scene1',58,63,'EDGAR','out of his good wits: bless thee, good man’s son, from the'),
('king_lear_act4_scene1',59,64,'EDGAR','foul fiend! five fiends have been in poor Tom at once; of'),
('king_lear_act4_scene1',60,65,'EDGAR','lust, as Obidicut; Hobbididence, prince of dumbness; Mahu, of stealing; Modo, of'),
('king_lear_act4_scene1',61,66,'EDGAR','murder; Flibbertigibbet, of mopping and mowing, who since possesses chambermaids and waiting-women.'),
('king_lear_act4_scene1',62,67,'EDGAR','So, bless thee, master!'),
('king_lear_act4_scene1',63,68,'GLOUCESTER','Here, take this purse, thou whom the heavens’ plagues'),
('king_lear_act4_scene1',64,69,'GLOUCESTER','Have humbled to all strokes: that I am wretched'),
('king_lear_act4_scene1',65,70,'GLOUCESTER','Makes thee the happier: heavens, deal so still!'),
('king_lear_act4_scene1',66,71,'GLOUCESTER','Let the superfluous and lust-dieted man,'),
('king_lear_act4_scene1',67,72,'GLOUCESTER','That slaves your ordinance, that will not see'),
('king_lear_act4_scene1',68,73,'GLOUCESTER','Because he doth not feel, feel your power quickly;'),
('king_lear_act4_scene1',69,74,'GLOUCESTER','So distribution should undo excess,'),
('king_lear_act4_scene1',70,75,'GLOUCESTER','And each man have enough. Dost thou know Dover?'),
('king_lear_act4_scene1',71,76,'EDGAR','Ay, master.'),
('king_lear_act4_scene1',72,77,'GLOUCESTER','There is a cliff, whose high and bending head'),
('king_lear_act4_scene1',73,78,'GLOUCESTER','Looks fearfully in the confined deep:'),
('king_lear_act4_scene1',74,79,'GLOUCESTER','Bring me but to the very brim of it,'),
('king_lear_act4_scene1',75,80,'GLOUCESTER','And I’ll repair the misery thou dost bear'),
('king_lear_act4_scene1',76,81,'GLOUCESTER','With something rich about me: from that place'),
('king_lear_act4_scene1',77,82,'GLOUCESTER','I shall no leading need.'),
('king_lear_act4_scene1',77,83,'EDGAR','Give me thy arm:'),
('king_lear_act4_scene1',78,84,'EDGAR','Poor Tom shall lead thee.'),
('king_lear_act4_scene2',1,0,'GONERIL','Welcome, my lord: I marvel our mild husband'),
('king_lear_act4_scene2',2,1,'GONERIL','Not met us on the way.'),
('king_lear_act4_scene2',3,2,'OSWALD','Madam, within; but never man so changed.'),
('king_lear_act4_scene2',4,3,'OSWALD','I told him of the army that was landed;'),
('king_lear_act4_scene2',5,4,'OSWALD','He smiled at it: I told him you were coming:'),
('king_lear_act4_scene2',6,5,'OSWALD','His answer was “The worse:” of Gloucester’s treachery,'),
('king_lear_act4_scene2',7,6,'OSWALD','And of the loyal service of his son,'),
('king_lear_act4_scene2',8,7,'OSWALD','When I inform’d him, then he call’d me sot,'),
('king_lear_act4_scene2',9,8,'OSWALD','And told me I had turn’d the wrong side out:'),
('king_lear_act4_scene2',10,9,'OSWALD','What most he should dislike seems pleasant to him;'),
('king_lear_act4_scene2',11,10,'OSWALD','What like, offensive.'),
('king_lear_act4_scene2',12,11,'GONERIL','To Edmund. Then shall you go no further.'),
('king_lear_act4_scene2',13,12,'GONERIL','It is the cowish terror of his spirit,'),
('king_lear_act4_scene2',14,13,'GONERIL','That dares not undertake: he’ll not feel wrongs'),
('king_lear_act4_scene2',15,14,'GONERIL','Which tie him to an answer. Our wishes on the way'),
('king_lear_act4_scene2',16,15,'GONERIL','May prove effects. Back, Edmund, to my brother;'),
('king_lear_act4_scene2',17,16,'GONERIL','Hasten his musters and conduct his powers:'),
('king_lear_act4_scene2',18,17,'GONERIL','I must change arms at home, and give the distaff'),
('king_lear_act4_scene2',19,18,'GONERIL','Into my husband’s hands. This trusty servant'),
('king_lear_act4_scene2',20,19,'GONERIL','Shall pass between us: ere long you are like to hear,'),
('king_lear_act4_scene2',21,20,'GONERIL','If you dare venture in your own behalf,'),
('king_lear_act4_scene2',22,21,'GONERIL','A mistress’s command. Wear this; spare speech;'),
('king_lear_act4_scene2',23,22,'GONERIL','Decline your head: this kiss, if it durst speak,'),
('king_lear_act4_scene2',24,23,'GONERIL','Would stretch thy spirits up into the air:'),
('king_lear_act4_scene2',25,24,'GONERIL','Conceive, and fare thee well.'),
('king_lear_act4_scene2',25,25,'EDMUND','Yours in the ranks of death.'),
('king_lear_act4_scene2',26,26,'GONERIL','My most dear Gloucester!'),
('king_lear_act4_scene2',27,27,'GONERIL','O, the difference of man and man!'),
('king_lear_act4_scene2',28,28,'GONERIL','To thee a woman’s services are due:'),
('king_lear_act4_scene2',29,29,'GONERIL','My fool usurps my body.'),
('king_lear_act4_scene2',29,30,'OSWALD','Madam, here comes my lord.'),
('king_lear_act4_scene2',30,31,'GONERIL','I have been worth the whistle.'),
('king_lear_act4_scene2',30,32,'ALBANY','O Goneril!'),
('king_lear_act4_scene2',31,33,'ALBANY','You are not worth the dust which the rude wind'),
('king_lear_act4_scene2',32,34,'ALBANY','Blows in your face. I fear your disposition:'),
('king_lear_act4_scene2',33,35,'ALBANY','That nature, which contemns its origin,'),
('king_lear_act4_scene2',34,36,'ALBANY','Cannot be border’d certain in itself;'),
('king_lear_act4_scene2',35,37,'ALBANY','She that herself will sliver and disbranch'),
('king_lear_act4_scene2',36,38,'ALBANY','From her material sap, perforce must wither'),
('king_lear_act4_scene2',37,39,'ALBANY','And come to deadly use.'),
('king_lear_act4_scene2',37,40,'GONERIL','No more; the text is foolish.'),
('king_lear_act4_scene2',38,41,'ALBANY','Wisdom and goodness to the vile seem vile:'),
('king_lear_act4_scene2',39,42,'ALBANY','Filths savour but themselves. What have you done?'),
('king_lear_act4_scene2',40,43,'ALBANY','Tigers, not daughters, what have you perform’d?'),
('king_lear_act4_scene2',41,44,'ALBANY','A father, and a gracious aged man,'),
('king_lear_act4_scene2',42,45,'ALBANY','Whose reverence even the head-lugg’d bear would lick,'),
('king_lear_act4_scene2',43,46,'ALBANY','Most barbarous, most degenerate! have you madded.'),
('king_lear_act4_scene2',44,47,'ALBANY','Could my good brother suffer you to do it?'),
('king_lear_act4_scene2',45,48,'ALBANY','A man, a prince, by him so benefited!'),
('king_lear_act4_scene2',46,49,'ALBANY','If that the heavens do not their visible spirits'),
('king_lear_act4_scene2',47,50,'ALBANY','Send quickly down to tame these vile offences,'),
('king_lear_act4_scene2',48,51,'ALBANY','It will come,'),
('king_lear_act4_scene2',49,52,'ALBANY','Humanity must perforce prey on itself,'),
('king_lear_act4_scene2',50,53,'ALBANY','Like monsters of the deep.'),
('king_lear_act4_scene2',50,54,'GONERIL','Milk-liver’d man!'),
('king_lear_act4_scene2',51,55,'GONERIL','That bear’st a cheek for blows, a head for wrongs;'),
('king_lear_act4_scene2',52,56,'GONERIL','Who hast not in thy brows an eye discerning'),
('king_lear_act4_scene2',53,57,'GONERIL','Thine honour from thy suffering; that not know’st'),
('king_lear_act4_scene2',54,58,'GONERIL','Fools do those villains pity who are punish’d'),
('king_lear_act4_scene2',55,59,'GONERIL','Ere they have done their mischief. Where’s thy drum?'),
('king_lear_act4_scene2',56,60,'GONERIL','France spreads his banners in our noiseless land;'),
('king_lear_act4_scene2',57,61,'GONERIL','With plumed helm thy slayer begins threats;'),
('king_lear_act4_scene2',58,62,'GONERIL','Whiles thou, a moral fool, sit’st still, and criest'),
('king_lear_act4_scene2',59,63,'GONERIL','“Alack, why does he so?”'),
('king_lear_act4_scene2',59,64,'ALBANY','See thyself, devil!'),
('king_lear_act4_scene2',60,65,'ALBANY','Proper deformity seems not in the fiend'),
('king_lear_act4_scene2',61,66,'ALBANY','So horrid as in woman.'),
('king_lear_act4_scene2',61,67,'GONERIL','O vain fool!'),
('king_lear_act4_scene2',62,68,'ALBANY','Thou changed and self-cover’d thing, for shame,'),
('king_lear_act4_scene2',63,69,'ALBANY','Be-monster not thy feature. Were’t my fitness'),
('king_lear_act4_scene2',64,70,'ALBANY','To let these hands obey my blood,'),
('king_lear_act4_scene2',65,71,'ALBANY','They are apt enough to dislocate and tear'),
('king_lear_act4_scene2',66,72,'ALBANY','Thy flesh and bones: howe’er thou art a fiend,'),
('king_lear_act4_scene2',67,73,'ALBANY','A woman’s shape doth shield thee.'),
('king_lear_act4_scene2',67,74,'GONERIL','Marry, your manhood now—'),
('king_lear_act4_scene2',68,75,'ALBANY','What news?'),
('king_lear_act4_scene2',69,76,'MESSENGER','O, my good lord, the Duke of Cornwall’s dead:'),
('king_lear_act4_scene2',70,77,'MESSENGER','Slain by his servant, going to put out'),
('king_lear_act4_scene2',71,78,'MESSENGER','The other eye of Gloucester.'),
('king_lear_act4_scene2',71,79,'ALBANY','Gloucester’s eye!'),
('king_lear_act4_scene2',72,80,'MESSENGER','A servant that he bred, thrill’d with remorse,'),
('king_lear_act4_scene2',73,81,'MESSENGER','Opposed against the act, bending his sword'),
('king_lear_act4_scene2',74,82,'MESSENGER','To his great master; who, thereat enraged,'),
('king_lear_act4_scene2',75,83,'MESSENGER','Flew on him, and amongst them fell’d him dead;'),
('king_lear_act4_scene2',76,84,'MESSENGER','But not without that harmful stroke, which since'),
('king_lear_act4_scene2',77,85,'MESSENGER','Hath pluck’d him after.'),
('king_lear_act4_scene2',77,86,'ALBANY','This shows you are above,'),
('king_lear_act4_scene2',78,87,'ALBANY','You justicers, that these our nether crimes'),
('king_lear_act4_scene2',79,88,'ALBANY','So speedily can venge! But, O poor Gloucester!'),
('king_lear_act4_scene2',80,89,'ALBANY','Lost he his other eye?'),
('king_lear_act4_scene2',80,90,'MESSENGER','Both, both, my lord.'),
('king_lear_act4_scene2',81,91,'MESSENGER','This letter, madam, craves a speedy answer;'),
('king_lear_act4_scene2',82,92,'MESSENGER','’Tis from your sister.'),
('king_lear_act4_scene2',82,93,'GONERIL','One way I like this well;'),
('king_lear_act4_scene2',83,94,'GONERIL','But being widow, and my Gloucester with her,'),
('king_lear_act4_scene2',84,95,'GONERIL','May all the building in my fancy pluck'),
('king_lear_act4_scene2',85,96,'GONERIL','Upon my hateful life: another way,'),
('king_lear_act4_scene2',86,97,'GONERIL','The news is not so tart.—I’ll read, and answer.'),
('king_lear_act4_scene2',87,98,'ALBANY','Where was his son when they did take his eyes?'),
('king_lear_act4_scene2',88,99,'MESSENGER','Come with my lady hither.'),
('king_lear_act4_scene2',88,100,'ALBANY','He is not here.'),
('king_lear_act4_scene2',89,101,'MESSENGER','No, my good lord; I met him back again.'),
('king_lear_act4_scene2',90,102,'ALBANY','Knows he the wickedness?'),
('king_lear_act4_scene2',91,103,'MESSENGER','Ay, my good lord; ’twas he inform’d against him;'),
('king_lear_act4_scene2',92,104,'MESSENGER','And quit the house on purpose, that their punishment'),
('king_lear_act4_scene2',93,105,'MESSENGER','Might have the freer course.'),
('king_lear_act4_scene2',93,106,'ALBANY','Gloucester, I live'),
('king_lear_act4_scene2',94,107,'ALBANY','To thank thee for the love thou show’dst the king,'),
('king_lear_act4_scene2',95,108,'ALBANY','And to revenge thine eyes. Come hither, friend:'),
('king_lear_act4_scene2',96,109,'ALBANY','Tell me what more thou know’st.'),
('king_lear_act4_scene3',1,0,'KENT','Why the King of France is so suddenly gone back know you the reason?'),
('king_lear_act4_scene3',2,1,'GENTLEMAN','Something he left imperfect in the state, which since his coming forth'),
('king_lear_act4_scene3',3,2,'GENTLEMAN','is thought of; which imports to the kingdom so much fear and'),
('king_lear_act4_scene3',4,3,'GENTLEMAN','danger, that his personal return was most required and necessary.'),
('king_lear_act4_scene3',5,4,'KENT','Who hath he left behind him general?'),
('king_lear_act4_scene3',6,5,'GENTLEMAN','The Marshal of France, Monsieur La Far.'),
('king_lear_act4_scene3',7,6,'KENT','Did your letters pierce the queen to any demonstration of grief?'),
('king_lear_act4_scene3',8,7,'GENTLEMAN','Ay, sir; she took them, read them in my presence;'),
('king_lear_act4_scene3',9,8,'GENTLEMAN','And now and then an ample tear trill’d down'),
('king_lear_act4_scene3',10,9,'GENTLEMAN','Her delicate cheek: it seem’d she was a queen'),
('king_lear_act4_scene3',11,10,'GENTLEMAN','Over her passion; who, most rebel-like,'),
('king_lear_act4_scene3',12,11,'GENTLEMAN','Sought to be king o’er her.'),
('king_lear_act4_scene3',12,12,'KENT','O, then it moved her.'),
('king_lear_act4_scene3',13,13,'GENTLEMAN','Not to a rage: patience and sorrow strove'),
('king_lear_act4_scene3',14,14,'GENTLEMAN','Who should express her goodliest. You have seen'),
('king_lear_act4_scene3',15,15,'GENTLEMAN','Sunshine and rain at once: her smiles and tears'),
('king_lear_act4_scene3',16,16,'GENTLEMAN','Were like a better way: those happy smilets,'),
('king_lear_act4_scene3',17,17,'GENTLEMAN','That play’d on her ripe lip, seem’d not to know'),
('king_lear_act4_scene3',18,18,'GENTLEMAN','What guests were in her eyes; which parted thence,'),
('king_lear_act4_scene3',19,19,'GENTLEMAN','As pearls from diamonds dropp’d. In brief,'),
('king_lear_act4_scene3',20,20,'GENTLEMAN','Sorrow would be a rarity most beloved,'),
('king_lear_act4_scene3',21,21,'GENTLEMAN','If all could so become it.'),
('king_lear_act4_scene3',21,22,'KENT','Made she no verbal question?'),
('king_lear_act4_scene3',22,23,'GENTLEMAN','’Faith, once or twice she heaved the name of “father”'),
('king_lear_act4_scene3',23,24,'GENTLEMAN','Pantingly forth, as if it press’d her heart:'),
('king_lear_act4_scene3',24,25,'GENTLEMAN','Cried “Sisters! sisters! Shame of ladies! sisters!'),
('king_lear_act4_scene3',25,26,'GENTLEMAN','Kent! father! sisters! What, i’ the storm? i’ the night?'),
('king_lear_act4_scene3',26,27,'GENTLEMAN','Let pity not be believed!” There she shook'),
('king_lear_act4_scene3',27,28,'GENTLEMAN','The holy water from her heavenly eyes,'),
('king_lear_act4_scene3',28,29,'GENTLEMAN','And clamour moisten’d: then away she started'),
('king_lear_act4_scene3',29,30,'GENTLEMAN','To deal with grief alone.'),
('king_lear_act4_scene3',29,31,'KENT','It is the stars,'),
('king_lear_act4_scene3',30,32,'KENT','The stars above us, govern our conditions;'),
('king_lear_act4_scene3',31,33,'KENT','Else one self mate and mate could not beget'),
('king_lear_act4_scene3',32,34,'KENT','Such different issues. You spoke not with her since?'),
('king_lear_act4_scene3',33,35,'GENTLEMAN','No.'),
('king_lear_act4_scene3',33,36,'KENT','Was this before the king return’d?'),
('king_lear_act4_scene3',34,37,'GENTLEMAN','No, since.'),
('king_lear_act4_scene3',35,38,'KENT','Well, sir, the poor distressed Lear’s i’ the town;'),
('king_lear_act4_scene3',36,39,'KENT','Who sometime, in his better tune, remembers'),
('king_lear_act4_scene3',37,40,'KENT','What we are come about, and by no means'),
('king_lear_act4_scene3',38,41,'KENT','Will yield to see his daughter.'),
('king_lear_act4_scene3',38,42,'GENTLEMAN','Why, good sir?'),
('king_lear_act4_scene3',39,43,'KENT','A sovereign shame so elbows him: his own unkindness,'),
('king_lear_act4_scene3',40,44,'KENT','That stripp’d her from his benediction, turn’d her'),
('king_lear_act4_scene3',41,45,'KENT','To foreign casualties, gave her dear rights'),
('king_lear_act4_scene3',42,46,'KENT','To his dog-hearted daughters, these things sting'),
('king_lear_act4_scene3',43,47,'KENT','His mind so venomously, that burning shame'),
('king_lear_act4_scene3',44,48,'KENT','Detains him from Cordelia.'),
('king_lear_act4_scene3',44,49,'GENTLEMAN','Alack, poor gentleman!'),
('king_lear_act4_scene3',45,50,'KENT','Of Albany’s and Cornwall’s powers you heard not?'),
('king_lear_act4_scene3',46,51,'GENTLEMAN','’Tis so, they are afoot.'),
('king_lear_act4_scene3',47,52,'KENT','Well, sir, I’ll bring you to our master Lear,'),
('king_lear_act4_scene3',48,53,'KENT','And leave you to attend him: some dear cause'),
('king_lear_act4_scene3',49,54,'KENT','Will in concealment wrap me up awhile;'),
('king_lear_act4_scene3',50,55,'KENT','When I am known aright, you shall not grieve'),
('king_lear_act4_scene3',51,56,'KENT','Lending me this acquaintance. I pray you, go'),
('king_lear_act4_scene3',52,57,'KENT','Along with me.'),
('king_lear_act4_scene4',1,0,'CORDELIA','Alack, ’tis he: why, he was met even now'),
('king_lear_act4_scene4',2,1,'CORDELIA','As mad as the vex’d sea; singing aloud;'),
('king_lear_act4_scene4',3,2,'CORDELIA','Crown’d with rank fumiter and furrow-weeds,'),
('king_lear_act4_scene4',4,3,'CORDELIA','With bur-docks, hemlock, nettles, cuckoo-flowers,'),
('king_lear_act4_scene4',5,4,'CORDELIA','Darnel, and all the idle weeds that grow'),
('king_lear_act4_scene4',6,5,'CORDELIA','In our sustaining corn. A century send forth;'),
('king_lear_act4_scene4',7,6,'CORDELIA','Search every acre in the high-grown field,'),
('king_lear_act4_scene4',8,7,'CORDELIA','And bring him to our eye.'),
('king_lear_act4_scene4',9,8,'CORDELIA','What can man’s wisdom'),
('king_lear_act4_scene4',10,9,'CORDELIA','In the restoring his bereaved sense?'),
('king_lear_act4_scene4',11,10,'CORDELIA','He that helps him take all my outward worth.'),
('king_lear_act4_scene4',12,11,'DOCTOR','There is means, madam:'),
('king_lear_act4_scene4',13,12,'DOCTOR','Our foster-nurse of nature is repose,'),
('king_lear_act4_scene4',14,13,'DOCTOR','The which he lacks; that to provoke in him,'),
('king_lear_act4_scene4',15,14,'DOCTOR','Are many simples operative, whose power'),
('king_lear_act4_scene4',16,15,'DOCTOR','Will close the eye of anguish.'),
('king_lear_act4_scene4',16,16,'CORDELIA','All blest secrets,'),
('king_lear_act4_scene4',17,17,'CORDELIA','All you unpublish’d virtues of the earth,'),
('king_lear_act4_scene4',18,18,'CORDELIA','Spring with my tears! be aidant and remediate'),
('king_lear_act4_scene4',19,19,'CORDELIA','In the good man’s distress! Seek, seek for him;'),
('king_lear_act4_scene4',20,20,'CORDELIA','Lest his ungovern’d rage dissolve the life'),
('king_lear_act4_scene4',21,21,'CORDELIA','That wants the means to lead it.'),
('king_lear_act4_scene4',22,22,'MESSENGER','News, madam;'),
('king_lear_act4_scene4',23,23,'MESSENGER','The British powers are marching hitherward.'),
('king_lear_act4_scene4',23,24,'CORDELIA','’Tis known before; our preparation stands'),
('king_lear_act4_scene4',24,25,'CORDELIA','In expectation of them. O dear father,'),
('king_lear_act4_scene4',25,26,'CORDELIA','It is thy business that I go about;'),
('king_lear_act4_scene4',26,27,'CORDELIA','Therefore great France'),
('king_lear_act4_scene4',27,28,'CORDELIA','My mourning and important tears hath pitied.'),
('king_lear_act4_scene4',28,29,'CORDELIA','No blown ambition doth our arms incite,'),
('king_lear_act4_scene4',29,30,'CORDELIA','But love, dear love, and our aged father’s right:'),
('king_lear_act4_scene4',30,31,'CORDELIA','Soon may I hear and see him!'),
('king_lear_act4_scene5',1,0,'REGAN','But are my brother’s powers set forth?'),
('king_lear_act4_scene5',2,1,'OSWALD','Ay, madam.'),
('king_lear_act4_scene5',2,2,'REGAN','Himself in person there?'),
('king_lear_act4_scene5',3,3,'OSWALD','Madam, with much ado: Your sister is the better soldier.'),
('king_lear_act4_scene5',4,4,'REGAN','Lord Edmund spake not with your lord at home?'),
('king_lear_act4_scene5',5,5,'OSWALD','No, madam.'),
('king_lear_act4_scene5',6,6,'REGAN','What might import my sister’s letter to him?'),
('king_lear_act4_scene5',7,7,'OSWALD','I know not, lady.'),
('king_lear_act4_scene5',8,8,'REGAN','’Faith, he is posted hence on serious matter.'),
('king_lear_act4_scene5',9,9,'REGAN','It was great ignorance, Gloucester’s eyes being out,'),
('king_lear_act4_scene5',10,10,'REGAN','To let him live: where he arrives he moves'),
('king_lear_act4_scene5',11,11,'REGAN','All hearts against us: Edmund, I think, is gone,'),
('king_lear_act4_scene5',12,12,'REGAN','In pity of his misery, to dispatch'),
('king_lear_act4_scene5',13,13,'REGAN','His nighted life: moreover, to descry'),
('king_lear_act4_scene5',14,14,'REGAN','The strength o’ the enemy.'),
('king_lear_act4_scene5',15,15,'OSWALD','I must needs after him, madam, with my letter.'),
('king_lear_act4_scene5',16,16,'REGAN','Our troops set forth to-morrow: stay with us;'),
('king_lear_act4_scene5',17,17,'REGAN','The ways are dangerous.'),
('king_lear_act4_scene5',17,18,'OSWALD','I may not, madam:'),
('king_lear_act4_scene5',18,19,'OSWALD','My lady charged my duty in this business.'),
('king_lear_act4_scene5',19,20,'REGAN','Why should she write to Edmund? Might not you'),
('king_lear_act4_scene5',20,21,'REGAN','Transport her purposes by word? Belike,'),
('king_lear_act4_scene5',21,22,'REGAN','Something—I know not what: I’ll love thee much,'),
('king_lear_act4_scene5',22,23,'REGAN','Let me unseal the letter.'),
('king_lear_act4_scene5',22,24,'OSWALD','Madam, I had rather—'),
('king_lear_act4_scene5',23,25,'REGAN','I know your lady does not love her husband;'),
('king_lear_act4_scene5',24,26,'REGAN','I am sure of that: and at her late being here'),
('king_lear_act4_scene5',25,27,'REGAN','She gave strange oeillades and most speaking looks'),
('king_lear_act4_scene5',26,28,'REGAN','To noble Edmund. I know you are of her bosom.'),
('king_lear_act4_scene5',27,29,'OSWALD','I, madam?'),
('king_lear_act4_scene5',28,30,'REGAN','I speak in understanding; you are; I know’t:'),
('king_lear_act4_scene5',29,31,'REGAN','Therefore I do advise you, take this note:'),
('king_lear_act4_scene5',30,32,'REGAN','My lord is dead; Edmund and I have talk’d;'),
('king_lear_act4_scene5',31,33,'REGAN','And more convenient is he for my hand'),
('king_lear_act4_scene5',32,34,'REGAN','Than for your lady’s: you may gather more.'),
('king_lear_act4_scene5',33,35,'REGAN','If you do find him, pray you, give him this;'),
('king_lear_act4_scene5',34,36,'REGAN','And when your mistress hears thus much from you,'),
('king_lear_act4_scene5',35,37,'REGAN','I pray, desire her call her wisdom to her.'),
('king_lear_act4_scene5',36,38,'REGAN','So, fare you well.'),
('king_lear_act4_scene5',37,39,'REGAN','If you do chance to hear of that blind traitor,'),
('king_lear_act4_scene5',38,40,'REGAN','Preferment falls on him that cuts him off.'),
('king_lear_act4_scene5',39,41,'OSWALD','Would I could meet him, madam! I should show'),
('king_lear_act4_scene5',40,42,'OSWALD','What party I do follow.'),
('king_lear_act4_scene5',40,43,'REGAN','Fare thee well.'),
('king_lear_act4_scene6',1,0,'GLOUCESTER','When shall we come to the top of that same hill?'),
('king_lear_act4_scene6',2,1,'EDGAR','You do climb up it now: look, how we labour.'),
('king_lear_act4_scene6',3,2,'GLOUCESTER','Methinks the ground is even.'),
('king_lear_act4_scene6',4,3,'EDGAR','Horrible steep. Hark, do you hear the sea?'),
('king_lear_act4_scene6',5,4,'GLOUCESTER','No, truly.'),
('king_lear_act4_scene6',6,5,'EDGAR','Why, then, your other senses grow imperfect'),
('king_lear_act4_scene6',7,6,'EDGAR','By your eyes’ anguish.'),
('king_lear_act4_scene6',7,7,'GLOUCESTER','So may it be, indeed:'),
('king_lear_act4_scene6',8,8,'GLOUCESTER','Methinks thy voice is alter’d; and thou speak’st'),
('king_lear_act4_scene6',9,9,'GLOUCESTER','In better phrase and matter than thou didst.'),
('king_lear_act4_scene6',10,10,'EDGAR','You’re much deceived: in nothing am I changed'),
('king_lear_act4_scene6',11,11,'EDGAR','But in my garments.'),
('king_lear_act4_scene6',11,12,'GLOUCESTER','Methinks you’re better spoken.'),
('king_lear_act4_scene6',12,13,'EDGAR','Come on, sir; here’s the place: stand still. How fearful'),
('king_lear_act4_scene6',13,14,'EDGAR','And dizzy ’tis, to cast one’s eyes so low!'),
('king_lear_act4_scene6',14,15,'EDGAR','The crows and choughs that wing the midway air'),
('king_lear_act4_scene6',15,16,'EDGAR','Show scarce so gross as beetles: half way down'),
('king_lear_act4_scene6',16,17,'EDGAR','Hangs one that gathers samphire, dreadful trade!'),
('king_lear_act4_scene6',17,18,'EDGAR','Methinks he seems no bigger than his head:'),
('king_lear_act4_scene6',18,19,'EDGAR','The fishermen, that walk upon the beach,'),
('king_lear_act4_scene6',19,20,'EDGAR','Appear like mice; and yond tall anchoring bark,'),
('king_lear_act4_scene6',20,21,'EDGAR','Diminish’d to her cock; her cock, a buoy'),
('king_lear_act4_scene6',21,22,'EDGAR','Almost too small for sight: the murmuring surge,'),
('king_lear_act4_scene6',22,23,'EDGAR','That on the unnumber’d idle pebbles chafes,'),
('king_lear_act4_scene6',23,24,'EDGAR','Cannot be heard so high. I’ll look no more;'),
('king_lear_act4_scene6',24,25,'EDGAR','Lest my brain turn, and the deficient sight'),
('king_lear_act4_scene6',25,26,'EDGAR','Topple down headlong.'),
('king_lear_act4_scene6',25,27,'GLOUCESTER','Set me where you stand.'),
('king_lear_act4_scene6',26,28,'EDGAR','Give me your hand: you are now within a foot'),
('king_lear_act4_scene6',27,29,'EDGAR','Of the extreme verge: for all beneath the moon'),
('king_lear_act4_scene6',28,30,'EDGAR','Would I not leap upright.'),
('king_lear_act4_scene6',28,31,'GLOUCESTER','Let go my hand.');
INSERT INTO lines (section_id,number,array_index,speaker,text) VALUES
('king_lear_act4_scene6',29,32,'GLOUCESTER','Here, friend, ’s another purse; in it a jewel'),
('king_lear_act4_scene6',30,33,'GLOUCESTER','Well worth a poor man’s taking: fairies and gods'),
('king_lear_act4_scene6',31,34,'GLOUCESTER','Prosper it with thee! Go thou farther off;'),
('king_lear_act4_scene6',32,35,'GLOUCESTER','Bid me farewell, and let me hear thee going.'),
('king_lear_act4_scene6',33,36,'EDGAR','Now fare you well, good sir.'),
('king_lear_act4_scene6',33,37,'GLOUCESTER','With all my heart.'),
('king_lear_act4_scene6',34,38,'EDGAR','Why I do trifle thus with his despair Is done to cure it.'),
('king_lear_act4_scene6',35,39,'GLOUCESTER','O you mighty gods!'),
('king_lear_act4_scene6',36,40,'GLOUCESTER','This world I do renounce, and, in your sights,'),
('king_lear_act4_scene6',37,41,'GLOUCESTER','Shake patiently my great affliction off:'),
('king_lear_act4_scene6',38,42,'GLOUCESTER','If I could bear it longer, and not fall'),
('king_lear_act4_scene6',39,43,'GLOUCESTER','To quarrel with your great opposeless wills,'),
('king_lear_act4_scene6',40,44,'GLOUCESTER','My snuff and loathed part of nature should'),
('king_lear_act4_scene6',41,45,'GLOUCESTER','Burn itself out. If Edgar live, O, bless him!'),
('king_lear_act4_scene6',42,46,'GLOUCESTER','Now, fellow, fare thee well. He falls forward.'),
('king_lear_act4_scene6',43,47,'EDGAR','Gone, sir: farewell.'),
('king_lear_act4_scene6',44,48,'EDGAR','And yet I know not how conceit may rob'),
('king_lear_act4_scene6',45,49,'EDGAR','The treasury of life, when life itself'),
('king_lear_act4_scene6',46,50,'EDGAR','Yields to the theft: had he been where he thought,'),
('king_lear_act4_scene6',47,51,'EDGAR','By this, had thought been past. Alive or dead?'),
('king_lear_act4_scene6',48,52,'EDGAR','Ho, you sir! friend! Hear you, sir! speak!'),
('king_lear_act4_scene6',49,53,'EDGAR','Thus might he pass indeed: yet he revives.'),
('king_lear_act4_scene6',50,54,'EDGAR','What are you, sir?'),
('king_lear_act4_scene6',50,55,'GLOUCESTER','Away, and let me die.'),
('king_lear_act4_scene6',51,56,'EDGAR','Hadst thou been aught but gossamer, feathers, air,'),
('king_lear_act4_scene6',52,57,'EDGAR','So many fathom down precipitating,'),
('king_lear_act4_scene6',53,58,'EDGAR','Thou’dst shiver’d like an egg: but thou dost breathe;'),
('king_lear_act4_scene6',54,59,'EDGAR','Hast heavy substance; bleed’st not; speak’st; art sound.'),
('king_lear_act4_scene6',55,60,'EDGAR','Ten masts at each make not the altitude'),
('king_lear_act4_scene6',56,61,'EDGAR','Which thou hast perpendicularly fell:'),
('king_lear_act4_scene6',57,62,'EDGAR','Thy life’s a miracle. Speak yet again.'),
('king_lear_act4_scene6',58,63,'GLOUCESTER','But have I fall’n, or no?'),
('king_lear_act4_scene6',59,64,'EDGAR','From the dread summit of this chalky bourn.'),
('king_lear_act4_scene6',60,65,'EDGAR','Look up a-height; the shrill-gorged lark so far'),
('king_lear_act4_scene6',61,66,'EDGAR','Cannot be seen or heard: do but look up.'),
('king_lear_act4_scene6',62,67,'GLOUCESTER','Alack, I have no eyes.'),
('king_lear_act4_scene6',63,68,'GLOUCESTER','Is wretchedness deprived that benefit,'),
('king_lear_act4_scene6',64,69,'GLOUCESTER','To end itself by death? ’Twas yet some comfort,'),
('king_lear_act4_scene6',65,70,'GLOUCESTER','When misery could beguile the tyrant’s rage,'),
('king_lear_act4_scene6',66,71,'GLOUCESTER','And frustrate his proud will.'),
('king_lear_act4_scene6',67,72,'EDGAR','Give me your arm: Up: so. How is ’t? Feel you your legs? You stand.'),
('king_lear_act4_scene6',68,73,'GLOUCESTER','Too well, too well.'),
('king_lear_act4_scene6',68,74,'EDGAR','This is above all strangeness.'),
('king_lear_act4_scene6',69,75,'EDGAR','Upon the crown o’ the cliff, what thing was that'),
('king_lear_act4_scene6',70,76,'EDGAR','Which parted from you?'),
('king_lear_act4_scene6',70,77,'GLOUCESTER','A poor unfortunate beggar.'),
('king_lear_act4_scene6',71,78,'EDGAR','As I stood here below, methought his eyes'),
('king_lear_act4_scene6',72,79,'EDGAR','Were two full moons; he had a thousand noses,'),
('king_lear_act4_scene6',73,80,'EDGAR','Horns whelk’d and waved like the enridged sea:'),
('king_lear_act4_scene6',74,81,'EDGAR','It was some fiend; therefore, thou happy father,'),
('king_lear_act4_scene6',75,82,'EDGAR','Think that the clearest gods, who make them honours'),
('king_lear_act4_scene6',76,83,'EDGAR','Of men’s impossibilities, have preserved thee.'),
('king_lear_act4_scene6',77,84,'GLOUCESTER','I do remember now: henceforth I’ll bear'),
('king_lear_act4_scene6',78,85,'GLOUCESTER','Affliction till it do cry out itself'),
('king_lear_act4_scene6',79,86,'GLOUCESTER','“Enough, enough,” and die. That thing you speak of,'),
('king_lear_act4_scene6',80,87,'GLOUCESTER','I took it for a man; often ’twould say'),
('king_lear_act4_scene6',81,88,'GLOUCESTER','“The fiend, the fiend:” he led me to that place.'),
('king_lear_act4_scene6',82,89,'EDGAR','Bear free and patient thoughts. But who comes here?'),
('king_lear_act4_scene6',83,90,'KING LEAR','No, they cannot touch me for coining; I am the king himself.'),
('king_lear_act4_scene6',84,91,'EDGAR','O thou side-piercing sight!'),
('king_lear_act4_scene6',85,92,'KING LEAR','Nature’s above art in that respect. There’s your press-money. That fellow handles'),
('king_lear_act4_scene6',86,93,'KING LEAR','his bow like a crow-keeper: draw me a clothier’s yard. Look, look,'),
('king_lear_act4_scene6',87,94,'KING LEAR','a mouse! Peace, peace; this piece of toasted cheese will do ’t.'),
('king_lear_act4_scene6',88,95,'KING LEAR','There’s my gauntlet; I’ll prove it on a giant. Bring up the'),
('king_lear_act4_scene6',89,96,'KING LEAR','brown bills. O, well flown, bird! i’ the clout, i’ the clout:'),
('king_lear_act4_scene6',90,97,'KING LEAR','hewgh! Give the word.'),
('king_lear_act4_scene6',90,98,'EDGAR','Sweet marjoram.'),
('king_lear_act4_scene6',91,99,'KING LEAR','Pass.'),
('king_lear_act4_scene6',91,100,'GLOUCESTER','I know that voice.'),
('king_lear_act4_scene6',92,101,'KING LEAR','Ha! Goneril, with a white beard! They flattered me like a dog;'),
('king_lear_act4_scene6',93,102,'KING LEAR','and told me I had white hairs in my beard ere the'),
('king_lear_act4_scene6',94,103,'KING LEAR','black ones were there. To say “ay” and “no” to every thing'),
('king_lear_act4_scene6',95,104,'KING LEAR','that I said!—“Ay” and “no” too was no good divinity. When the'),
('king_lear_act4_scene6',96,105,'KING LEAR','rain came to wet me once, and the wind to make me'),
('king_lear_act4_scene6',97,106,'KING LEAR','chatter; when the thunder would not peace at my bidding; there I'),
('king_lear_act4_scene6',98,107,'KING LEAR','found ’em, there I smelt ’em out. Go to, they are not'),
('king_lear_act4_scene6',99,108,'KING LEAR','men o’ their words: they told me I was every thing; ’tis'),
('king_lear_act4_scene6',100,109,'KING LEAR','a lie, I am not ague-proof.'),
('king_lear_act4_scene6',101,110,'GLOUCESTER','The trick of that voice I do well remember:'),
('king_lear_act4_scene6',102,111,'GLOUCESTER','Is ’t not the king?'),
('king_lear_act4_scene6',102,112,'KING LEAR','Ay, every inch a king:'),
('king_lear_act4_scene6',103,113,'KING LEAR','When I do stare, see how the subject quakes.'),
('king_lear_act4_scene6',104,114,'KING LEAR','I pardon that man’s life. What was thy cause? Adultery?'),
('king_lear_act4_scene6',105,115,'KING LEAR','Thou shalt not die: die for adultery! No:'),
('king_lear_act4_scene6',106,116,'KING LEAR','The wren goes to ’t, and the small gilded fly'),
('king_lear_act4_scene6',107,117,'KING LEAR','Does lecher in my sight.'),
('king_lear_act4_scene6',108,118,'KING LEAR','Let copulation thrive; for Gloucester’s bastard son'),
('king_lear_act4_scene6',109,119,'KING LEAR','Was kinder to his father than my daughters'),
('king_lear_act4_scene6',110,120,'KING LEAR','Got ’tween the lawful sheets.'),
('king_lear_act4_scene6',111,121,'KING LEAR','To ’t, luxury, pell-mell! for I lack soldiers.'),
('king_lear_act4_scene6',112,122,'KING LEAR','Behold yond simpering dame,'),
('king_lear_act4_scene6',113,123,'KING LEAR','Whose face between her forks presages snow;'),
('king_lear_act4_scene6',114,124,'KING LEAR','That minces virtue, and does shake the head'),
('king_lear_act4_scene6',115,125,'KING LEAR','To hear of pleasure’s name;'),
('king_lear_act4_scene6',116,126,'KING LEAR','The fitchew, nor the soiled horse, goes to ’t'),
('king_lear_act4_scene6',117,127,'KING LEAR','With a more riotous appetite.'),
('king_lear_act4_scene6',118,128,'KING LEAR','Down from the waist they are Centaurs,'),
('king_lear_act4_scene6',119,129,'KING LEAR','Though women all above:'),
('king_lear_act4_scene6',120,130,'KING LEAR','But to the girdle do the gods inherit,'),
('king_lear_act4_scene6',121,131,'KING LEAR','Beneath is all the fiends’;'),
('king_lear_act4_scene6',121,132,'GLOUCESTER','O, let me kiss that hand!'),
('king_lear_act4_scene6',122,133,'KING LEAR','Let me wipe it first; it smells of mortality.'),
('king_lear_act4_scene6',123,134,'GLOUCESTER','O ruin’d piece of nature! This great world'),
('king_lear_act4_scene6',124,135,'GLOUCESTER','Shall so wear out to nought. Dost thou know me?'),
('king_lear_act4_scene6',125,136,'KING LEAR','I remember thine eyes well enough. Dost thou squiny at me? No,'),
('king_lear_act4_scene6',126,137,'KING LEAR','do thy worst, blind Cupid! I’ll not love. Read thou this challenge;'),
('king_lear_act4_scene6',127,138,'KING LEAR','mark but the penning of it.'),
('king_lear_act4_scene6',128,139,'GLOUCESTER','Were all the letters suns, I could not see one.'),
('king_lear_act4_scene6',129,140,'EDGAR','I would not take this from report; it is,'),
('king_lear_act4_scene6',130,141,'EDGAR','And my heart breaks at it.'),
('king_lear_act4_scene6',130,142,'KING LEAR','Read.'),
('king_lear_act4_scene6',131,143,'GLOUCESTER','What, with the case of eyes?'),
('king_lear_act4_scene6',132,144,'KING LEAR','O, ho, are you there with me? No eyes in your head,'),
('king_lear_act4_scene6',133,145,'KING LEAR','nor no money in your purse? Your eyes are in a heavy'),
('king_lear_act4_scene6',134,146,'KING LEAR','case, your purse in a light; yet you see how this world'),
('king_lear_act4_scene6',135,147,'KING LEAR','goes.'),
('king_lear_act4_scene6',135,148,'GLOUCESTER','I see it feelingly.'),
('king_lear_act4_scene6',136,149,'KING LEAR','What, art mad? A man may see how this world goes with'),
('king_lear_act4_scene6',137,150,'KING LEAR','no eyes. Look with thine ears: see how yond justice rails upon'),
('king_lear_act4_scene6',138,151,'KING LEAR','yond simple thief. Hark, in thine ear: change places; and, handy-dandy, which'),
('king_lear_act4_scene6',139,152,'KING LEAR','is the justice, which is the thief? Thou hast seen a farmer’s'),
('king_lear_act4_scene6',140,153,'KING LEAR','dog bark at a beggar?'),
('king_lear_act4_scene6',140,154,'GLOUCESTER','Ay, sir.'),
('king_lear_act4_scene6',141,155,'KING LEAR','And the creature run from the cur? There thou mightst behold the'),
('king_lear_act4_scene6',142,156,'KING LEAR','great image of authority: a dog’s obeyed in office.'),
('king_lear_act4_scene6',143,157,'EDGAR','O, matter and impertinency mix’d! Reason in madness!'),
('king_lear_act4_scene6',144,158,'KING LEAR','If thou wilt weep my fortunes, take my eyes.'),
('king_lear_act4_scene6',145,159,'KING LEAR','I know thee well enough; thy name is Gloucester:'),
('king_lear_act4_scene6',146,160,'KING LEAR','Thou must be patient; we came crying hither:'),
('king_lear_act4_scene6',147,161,'KING LEAR','Thou know’st, the first time that we smell the air,'),
('king_lear_act4_scene6',148,162,'KING LEAR','We wawl and cry. I will preach to thee: mark.'),
('king_lear_act4_scene6',149,163,'GLOUCESTER','Alack, alack the day!'),
('king_lear_act4_scene6',150,164,'KING LEAR','When we are born, we cry that we are come'),
('king_lear_act4_scene6',151,165,'KING LEAR','To this great stage of fools: this a good block;'),
('king_lear_act4_scene6',152,166,'KING LEAR','It were a delicate stratagem, to shoe'),
('king_lear_act4_scene6',153,167,'KING LEAR','A troop of horse with felt: I’ll put ’t in proof;'),
('king_lear_act4_scene6',154,168,'KING LEAR','And when I have stol’n upon these sons-in-law,'),
('king_lear_act4_scene6',155,169,'KING LEAR','Then, kill, kill, kill, kill, kill, kill!'),
('king_lear_act4_scene6',156,170,'GENTLEMAN','O, here he is: lay hand upon him. Sir,'),
('king_lear_act4_scene6',157,171,'GENTLEMAN','Your most dear daughter—'),
('king_lear_act4_scene6',158,172,'KING LEAR','No rescue? What, a prisoner? I am even'),
('king_lear_act4_scene6',159,173,'KING LEAR','The natural fool of fortune. Use me well;'),
('king_lear_act4_scene6',160,174,'KING LEAR','You shall have ransom. Let me have surgeons;'),
('king_lear_act4_scene6',161,175,'KING LEAR','I am cut to the brains.'),
('king_lear_act4_scene6',161,176,'GENTLEMAN','You shall have any thing.'),
('king_lear_act4_scene6',162,177,'KING LEAR','No seconds? all myself?'),
('king_lear_act4_scene6',163,178,'KING LEAR','Why, this would make a man a man of salt,'),
('king_lear_act4_scene6',164,179,'KING LEAR','To use his eyes for garden water-pots,'),
('king_lear_act4_scene6',165,180,'KING LEAR','Ay, and laying autumn’s dust.'),
('king_lear_act4_scene6',165,181,'GENTLEMAN','Good sir—'),
('king_lear_act4_scene6',166,182,'KING LEAR','I will die bravely, like a bridegroom. What!'),
('king_lear_act4_scene6',167,183,'KING LEAR','I will be jovial: come, come; I am a king,'),
('king_lear_act4_scene6',168,184,'KING LEAR','My masters, know you that.'),
('king_lear_act4_scene6',169,185,'GENTLEMAN','You are a royal one, and we obey you.'),
('king_lear_act4_scene6',170,186,'KING LEAR','Then there’s life in’t. Nay, if you get it, you shall get'),
('king_lear_act4_scene6',171,187,'KING LEAR','it with running. Sa, sa, sa, sa.'),
('king_lear_act4_scene6',172,188,'GENTLEMAN','A sight most pitiful in the meanest wretch,'),
('king_lear_act4_scene6',173,189,'GENTLEMAN','Past speaking of in a king! Thou hast one daughter,'),
('king_lear_act4_scene6',174,190,'GENTLEMAN','Who redeems nature from the general curse'),
('king_lear_act4_scene6',175,191,'GENTLEMAN','Which twain have brought her to.'),
('king_lear_act4_scene6',175,192,'EDGAR','Hail, gentle sir.'),
('king_lear_act4_scene6',176,193,'GENTLEMAN','Sir, speed you: what’s your will?'),
('king_lear_act4_scene6',177,194,'EDGAR','Do you hear aught, sir, of a battle toward?'),
('king_lear_act4_scene6',178,195,'GENTLEMAN','Most sure and vulgar: every one hears that,'),
('king_lear_act4_scene6',179,196,'GENTLEMAN','Which can distinguish sound.'),
('king_lear_act4_scene6',179,197,'EDGAR','But, by your favour,'),
('king_lear_act4_scene6',180,198,'EDGAR','How near’s the other army?'),
('king_lear_act4_scene6',181,199,'GENTLEMAN','Near and on speedy foot; the main descry'),
('king_lear_act4_scene6',182,200,'GENTLEMAN','Stands on the hourly thought.'),
('king_lear_act4_scene6',182,201,'EDGAR','I thank you, sir: that’s all.'),
('king_lear_act4_scene6',183,202,'GENTLEMAN','Though that the queen on special cause is here,'),
('king_lear_act4_scene6',184,203,'GENTLEMAN','Her army is moved on.'),
('king_lear_act4_scene6',184,204,'EDGAR','I thank you, sir.'),
('king_lear_act4_scene6',185,205,'GLOUCESTER','You ever-gentle gods, take my breath from me:'),
('king_lear_act4_scene6',186,206,'GLOUCESTER','Let not my worser spirit tempt me again'),
('king_lear_act4_scene6',187,207,'GLOUCESTER','To die before you please!'),
('king_lear_act4_scene6',187,208,'EDGAR','Well pray you, father.'),
('king_lear_act4_scene6',188,209,'GLOUCESTER','Now, good sir, what are you?'),
('king_lear_act4_scene6',189,210,'EDGAR','A most poor man, made tame to fortune’s blows;'),
('king_lear_act4_scene6',190,211,'EDGAR','Who, by the art of known and feeling sorrows,'),
('king_lear_act4_scene6',191,212,'EDGAR','Am pregnant to good pity. Give me your hand,'),
('king_lear_act4_scene6',192,213,'EDGAR','I’ll lead you to some biding.'),
('king_lear_act4_scene6',192,214,'GLOUCESTER','Hearty thanks:'),
('king_lear_act4_scene6',193,215,'GLOUCESTER','The bounty and the benison of heaven'),
('king_lear_act4_scene6',194,216,'GLOUCESTER','To boot, and boot!'),
('king_lear_act4_scene6',194,217,'OSWALD','A proclaim’d prize! Most happy!'),
('king_lear_act4_scene6',195,218,'OSWALD','That eyeless head of thine was first framed flesh'),
('king_lear_act4_scene6',196,219,'OSWALD','To raise my fortunes. Thou old unhappy traitor,'),
('king_lear_act4_scene6',197,220,'OSWALD','Briefly thyself remember: the sword is out'),
('king_lear_act4_scene6',198,221,'OSWALD','That must destroy thee.'),
('king_lear_act4_scene6',198,222,'GLOUCESTER','Now let thy friendly hand'),
('king_lear_act4_scene6',199,223,'GLOUCESTER','Put strength enough to’t. Edgar interposes.'),
('king_lear_act4_scene6',199,224,'OSWALD','Wherefore, bold peasant,'),
('king_lear_act4_scene6',200,225,'OSWALD','Darest thou support a publish’d traitor? Hence;'),
('king_lear_act4_scene6',201,226,'OSWALD','Lest that the infection of his fortune take'),
('king_lear_act4_scene6',202,227,'OSWALD','Like hold on thee. Let go his arm.'),
('king_lear_act4_scene6',203,228,'EDGAR','Ch’ill not let go, zir, without vurther ’casion.'),
('king_lear_act4_scene6',204,229,'OSWALD','Let go, slave, or thou diest!'),
('king_lear_act4_scene6',205,230,'EDGAR','Good gentleman, go your gait, and let poor volk pass. An chud'),
('king_lear_act4_scene6',206,231,'EDGAR','ha’ bin zwaggered out of my life, ’twould not ha’ bin zo'),
('king_lear_act4_scene6',207,232,'EDGAR','long as ’tis by a vortnight. Nay, come not near th’ old'),
('king_lear_act4_scene6',208,233,'EDGAR','man; keep out, che vor ye, or ise try whether your costard'),
('king_lear_act4_scene6',209,234,'EDGAR','or my ballow be the harder: ch’ill be plain with you.'),
('king_lear_act4_scene6',210,235,'OSWALD','Out, dunghill!'),
('king_lear_act4_scene6',211,236,'EDGAR','Ch’ill pick your teeth, zir: come; no matter vor your foins. They'),
('king_lear_act4_scene6',212,237,'EDGAR','fight, and Edgar knocks him down.'),
('king_lear_act4_scene6',213,238,'OSWALD','Slave, thou hast slain me: villain, take my purse:'),
('king_lear_act4_scene6',214,239,'OSWALD','If ever thou wilt thrive, bury my body;'),
('king_lear_act4_scene6',215,240,'OSWALD','And give the letters which thou find’st about me'),
('king_lear_act4_scene6',216,241,'OSWALD','To Edmund earl of Gloucester; seek him out'),
('king_lear_act4_scene6',217,242,'OSWALD','Upon the British party: O, untimely death!'),
('king_lear_act4_scene6',218,243,'EDGAR','I know thee well: a serviceable villain;'),
('king_lear_act4_scene6',219,244,'EDGAR','As duteous to the vices of thy mistress'),
('king_lear_act4_scene6',220,245,'EDGAR','As badness would desire.'),
('king_lear_act4_scene6',220,246,'GLOUCESTER','What, is he dead?'),
('king_lear_act4_scene6',221,247,'EDGAR','Sit you down, father; rest you'),
('king_lear_act4_scene6',222,248,'EDGAR','Let’s see these pockets: the letters that he speaks of'),
('king_lear_act4_scene6',223,249,'EDGAR','May be my friends. He’s dead; I am only sorry'),
('king_lear_act4_scene6',224,250,'EDGAR','He had no other death’s-man. Let us see:'),
('king_lear_act4_scene6',225,251,'EDGAR','Leave, gentle wax; and, manners, blame us not:'),
('king_lear_act4_scene6',226,252,'EDGAR','To know our enemies’ minds, we’ld rip their hearts;'),
('king_lear_act4_scene6',227,253,'EDGAR','Their papers, is more lawful.'),
('king_lear_act4_scene6',228,254,'GLOUCESTER','The king is mad: how stiff is my vile sense,'),
('king_lear_act4_scene6',229,255,'GLOUCESTER','That I stand up, and have ingenious feeling'),
('king_lear_act4_scene6',230,256,'GLOUCESTER','Of my huge sorrows! Better I were distract:'),
('king_lear_act4_scene6',231,257,'GLOUCESTER','So should my thoughts be sever’d from my griefs,'),
('king_lear_act4_scene6',232,258,'GLOUCESTER','And woes by wrong imaginations lose'),
('king_lear_act4_scene6',233,259,'GLOUCESTER','The knowledge of themselves.'),
('king_lear_act4_scene6',233,260,'EDGAR','Give me your hand:'),
('king_lear_act4_scene6',234,261,'EDGAR','Far off, methinks, I hear the beaten drum:'),
('king_lear_act4_scene6',235,262,'EDGAR','Come, father, I’ll bestow you with a friend.'),
('king_lear_act4_scene7',1,0,'CORDELIA','O thou good Kent, how shall I live and work,'),
('king_lear_act4_scene7',2,1,'CORDELIA','To match thy goodness? My life will be too short,'),
('king_lear_act4_scene7',3,2,'CORDELIA','And every measure fail me.'),
('king_lear_act4_scene7',3,3,'KENT','To be acknowledged, madam, is o’erpaid.'),
('king_lear_act4_scene7',4,4,'KENT','All my reports go with the modest truth;'),
('king_lear_act4_scene7',5,5,'KENT','Nor more nor clipp’d, but so.'),
('king_lear_act4_scene7',5,6,'CORDELIA','Be better suited:'),
('king_lear_act4_scene7',6,7,'CORDELIA','These weeds are memories of those worser hours:'),
('king_lear_act4_scene7',7,8,'CORDELIA','I prithee, put them off.'),
('king_lear_act4_scene7',7,9,'KENT','Pardon me, dear madam;'),
('king_lear_act4_scene7',8,10,'KENT','Yet to be known shortens my made intent:'),
('king_lear_act4_scene7',9,11,'KENT','My boon I make it, that you know me not'),
('king_lear_act4_scene7',10,12,'KENT','Till time and I think meet.'),
('king_lear_act4_scene7',10,13,'CORDELIA','Then be’t so, my good lord.'),
('king_lear_act4_scene7',11,14,'CORDELIA','To the Doctor. How does the king?'),
('king_lear_act4_scene7',12,15,'DOCTOR','Madam, sleeps still.'),
('king_lear_act4_scene7',12,16,'CORDELIA','O you kind gods,'),
('king_lear_act4_scene7',13,17,'CORDELIA','Cure this great breach in his abused nature!'),
('king_lear_act4_scene7',14,18,'CORDELIA','The untuned and jarring senses, O, wind up'),
('king_lear_act4_scene7',15,19,'CORDELIA','Of this child-changed father!'),
('king_lear_act4_scene7',15,20,'DOCTOR','So please your majesty'),
('king_lear_act4_scene7',16,21,'DOCTOR','That we may wake the king: he hath slept long.'),
('king_lear_act4_scene7',17,22,'CORDELIA','Be govern’d by your knowledge, and proceed'),
('king_lear_act4_scene7',18,23,'CORDELIA','I’ the sway of your own will. Is he array’d?'),
('king_lear_act4_scene7',19,24,'GENTLEMAN','Ay, madam; in the heaviness of his sleep'),
('king_lear_act4_scene7',20,25,'GENTLEMAN','We put fresh garments on him.'),
('king_lear_act4_scene7',21,26,'DOCTOR','Be by, good madam, when we do awake him;'),
('king_lear_act4_scene7',22,27,'DOCTOR','I doubt not of his temperance.'),
('king_lear_act4_scene7',22,28,'CORDELIA','Very well.'),
('king_lear_act4_scene7',23,29,'DOCTOR','Please you, draw near. Louder the music there!'),
('king_lear_act4_scene7',24,30,'CORDELIA','O my dear father! Restoration hang'),
('king_lear_act4_scene7',25,31,'CORDELIA','Thy medicine on my lips; and let this kiss'),
('king_lear_act4_scene7',26,32,'CORDELIA','Repair those violent harms that my two sisters'),
('king_lear_act4_scene7',27,33,'CORDELIA','Have in thy reverence made!'),
('king_lear_act4_scene7',27,34,'KENT','Kind and dear princess!'),
('king_lear_act4_scene7',28,35,'CORDELIA','Had you not been their father, these white flakes'),
('king_lear_act4_scene7',29,36,'CORDELIA','Had challenged pity of them. Was this a face'),
('king_lear_act4_scene7',30,37,'CORDELIA','To be opposed against the warring winds?'),
('king_lear_act4_scene7',31,38,'CORDELIA','To stand against the deep dread-bolted thunder?'),
('king_lear_act4_scene7',32,39,'CORDELIA','In the most terrible and nimble stroke'),
('king_lear_act4_scene7',33,40,'CORDELIA','Of quick, cross lightning? to watch—poor perdu!—'),
('king_lear_act4_scene7',34,41,'CORDELIA','With this thin helm? Mine enemy’s dog,'),
('king_lear_act4_scene7',35,42,'CORDELIA','Though he had bit me, should have stood that night'),
('king_lear_act4_scene7',36,43,'CORDELIA','Against my fire; and wast thou fain, poor father,'),
('king_lear_act4_scene7',37,44,'CORDELIA','To hovel thee with swine, and rogues forlorn,'),
('king_lear_act4_scene7',38,45,'CORDELIA','In short and musty straw? Alack, alack!'),
('king_lear_act4_scene7',39,46,'CORDELIA','’Tis wonder that thy life and wits at once'),
('king_lear_act4_scene7',40,47,'CORDELIA','Had not concluded all. He wakes; speak to him.'),
('king_lear_act4_scene7',41,48,'DOCTOR','Madam, do you; ’tis fittest.'),
('king_lear_act4_scene7',42,49,'CORDELIA','How does my royal lord? How fares your majesty?'),
('king_lear_act4_scene7',43,50,'KING LEAR','You do me wrong to take me out o’ the grave:'),
('king_lear_act4_scene7',44,51,'KING LEAR','Thou art a soul in bliss; but I am bound'),
('king_lear_act4_scene7',45,52,'KING LEAR','Upon a wheel of fire, that mine own tears'),
('king_lear_act4_scene7',46,53,'KING LEAR','Do scald like moulten lead.'),
('king_lear_act4_scene7',46,54,'CORDELIA','Sir, do you know me?'),
('king_lear_act4_scene7',47,55,'KING LEAR','You are a spirit, I know: when did you die?'),
('king_lear_act4_scene7',48,56,'CORDELIA','Still, still, far wide!'),
('king_lear_act4_scene7',49,57,'DOCTOR','He’s scarce awake: let him alone awhile.'),
('king_lear_act4_scene7',50,58,'KING LEAR','Where have I been? Where am I? Fair daylight?'),
('king_lear_act4_scene7',51,59,'KING LEAR','I am mightily abused. I should e’en die with pity,'),
('king_lear_act4_scene7',52,60,'KING LEAR','To see another thus. I know not what to say.'),
('king_lear_act4_scene7',53,61,'KING LEAR','I will not swear these are my hands: let’s see;'),
('king_lear_act4_scene7',54,62,'KING LEAR','I feel this pin prick. Would I were assured'),
('king_lear_act4_scene7',55,63,'KING LEAR','Of my condition!'),
('king_lear_act4_scene7',55,64,'CORDELIA','O, look upon me, sir,'),
('king_lear_act4_scene7',56,65,'CORDELIA','And hold your hands in benediction o’er me:'),
('king_lear_act4_scene7',57,66,'CORDELIA','No, sir, you must not kneel.'),
('king_lear_act4_scene7',57,67,'KING LEAR','Pray, do not mock me:'),
('king_lear_act4_scene7',58,68,'KING LEAR','I am a very foolish fond old man,'),
('king_lear_act4_scene7',59,69,'KING LEAR','Fourscore and upward, not an hour more nor less;'),
('king_lear_act4_scene7',60,70,'KING LEAR','And, to deal plainly,'),
('king_lear_act4_scene7',61,71,'KING LEAR','I fear I am not in my perfect mind.'),
('king_lear_act4_scene7',62,72,'KING LEAR','Methinks I should know you, and know this man;'),
('king_lear_act4_scene7',63,73,'KING LEAR','Yet I am doubtful for I am mainly ignorant'),
('king_lear_act4_scene7',64,74,'KING LEAR','What place this is; and all the skill I have'),
('king_lear_act4_scene7',65,75,'KING LEAR','Remembers not these garments; nor I know not'),
('king_lear_act4_scene7',66,76,'KING LEAR','Where I did lodge last night. Do not laugh at me;'),
('king_lear_act4_scene7',67,77,'KING LEAR','For, as I am a man, I think this lady'),
('king_lear_act4_scene7',68,78,'KING LEAR','To be my child Cordelia.'),
('king_lear_act4_scene7',68,79,'CORDELIA','And so I am, I am.'),
('king_lear_act4_scene7',69,80,'KING LEAR','Be your tears wet? yes, ’faith. I pray, weep not:'),
('king_lear_act4_scene7',70,81,'KING LEAR','If you have poison for me, I will drink it.'),
('king_lear_act4_scene7',71,82,'KING LEAR','I know you do not love me; for your sisters'),
('king_lear_act4_scene7',72,83,'KING LEAR','Have, as I do remember, done me wrong:'),
('king_lear_act4_scene7',73,84,'KING LEAR','You have some cause, they have not.'),
('king_lear_act4_scene7',74,85,'CORDELIA','No cause, no cause.'),
('king_lear_act4_scene7',74,86,'KING LEAR','Am I in France?'),
('king_lear_act4_scene7',75,87,'KENT','In your own kingdom, sir.'),
('king_lear_act4_scene7',75,88,'KING LEAR','Do not abuse me.'),
('king_lear_act4_scene7',76,89,'DOCTOR','Be comforted, good madam: the great rage,'),
('king_lear_act4_scene7',77,90,'DOCTOR','You see, is kill’d in him: and yet it is danger'),
('king_lear_act4_scene7',78,91,'DOCTOR','To make him even o’er the time he has lost.'),
('king_lear_act4_scene7',79,92,'DOCTOR','Desire him to go in; trouble him no more'),
('king_lear_act4_scene7',80,93,'DOCTOR','Till further settling.'),
('king_lear_act4_scene7',80,94,'CORDELIA','Will’t please your highness walk?'),
('king_lear_act4_scene7',81,95,'KING LEAR','You must bear with me:'),
('king_lear_act4_scene7',82,96,'KING LEAR','Pray you now, forget and forgive: I am old and foolish.'),
('king_lear_act4_scene7',83,97,'GENTLEMAN','Holds it true, sir, that the Duke of Cornwall was so slain?'),
('king_lear_act4_scene7',84,98,'KENT','Most certain, sir.'),
('king_lear_act4_scene7',84,99,'GENTLEMAN','Who is conductor of his people?'),
('king_lear_act4_scene7',85,100,'KENT','As ’tis said, the bastard son of Gloucester.'),
('king_lear_act4_scene7',86,101,'GENTLEMAN','They say Edgar, his banished son, is with the Earl of Kent in Germany.'),
('king_lear_act4_scene7',87,102,'KENT','Report is changeable. ’Tis time to look about; the powers of the kingdom approach apace.'),
('king_lear_act4_scene7',88,103,'GENTLEMAN','The arbitrement is like to be bloody. Fare you well, sir.'),
('king_lear_act4_scene7',89,104,'KENT','My point and period will be throughly wrought,'),
('king_lear_act4_scene7',90,105,'KENT','Or well or ill, as this day’s battle’s fought.'),
('king_lear_act5_scene1',1,0,'EDMUND','Know of the duke if his last purpose hold,'),
('king_lear_act5_scene1',2,1,'EDMUND','Or whether since he is advised by aught'),
('king_lear_act5_scene1',3,2,'EDMUND','To change the course: he’s full of alteration'),
('king_lear_act5_scene1',4,3,'EDMUND','And self-reproving: bring his constant pleasure. To a Gentleman, who goes out.'),
('king_lear_act5_scene1',5,4,'REGAN','Our sister’s man is certainly miscarried.'),
('king_lear_act5_scene1',5,5,'EDMUND','’Tis to be doubted, madam.'),
('king_lear_act5_scene1',6,6,'REGAN','Now, sweet lord,'),
('king_lear_act5_scene1',7,7,'REGAN','You know the goodness I intend upon you:'),
('king_lear_act5_scene1',8,8,'REGAN','Tell me—but truly—but then speak the truth,'),
('king_lear_act5_scene1',9,9,'REGAN','Do you not love my sister?'),
('king_lear_act5_scene1',9,10,'EDMUND','In honour’d love.'),
('king_lear_act5_scene1',10,11,'REGAN','But have you never found my brother’s way'),
('king_lear_act5_scene1',11,12,'REGAN','To the forfended place?'),
('king_lear_act5_scene1',11,13,'EDMUND','That thought abuses you.'),
('king_lear_act5_scene1',12,14,'REGAN','I am doubtful that you have been conjunct'),
('king_lear_act5_scene1',13,15,'REGAN','And bosom’d with her, as far as we call hers.'),
('king_lear_act5_scene1',14,16,'EDMUND','No, by mine honour, madam.'),
('king_lear_act5_scene1',15,17,'REGAN','I never shall endure her: dear my lord,'),
('king_lear_act5_scene1',16,18,'REGAN','Be not familiar with her.'),
('king_lear_act5_scene1',16,19,'EDMUND','Fear me not:'),
('king_lear_act5_scene1',17,20,'EDMUND','She and the duke her husband!'),
('king_lear_act5_scene1',18,21,'GONERIL','I had rather lose the battle than that sister'),
('king_lear_act5_scene1',19,22,'GONERIL','Should loosen him and me.'),
('king_lear_act5_scene1',19,23,'ALBANY','Our very loving sister, well be-met.'),
('king_lear_act5_scene1',20,24,'ALBANY','Sir, this I hear; the king is come to his daughter,'),
('king_lear_act5_scene1',21,25,'ALBANY','With others whom the rigor of our state'),
('king_lear_act5_scene1',22,26,'ALBANY','Forced to cry out. Where I could not be honest,'),
('king_lear_act5_scene1',23,27,'ALBANY','I never yet was valiant: for this business,'),
('king_lear_act5_scene1',24,28,'ALBANY','It toucheth us, as France invades our land,'),
('king_lear_act5_scene1',25,29,'ALBANY','Not bolds the king, with others, whom, I fear,'),
('king_lear_act5_scene1',26,30,'ALBANY','Most just and heavy causes make oppose.'),
('king_lear_act5_scene1',27,31,'EDMUND','Sir, you speak nobly.'),
('king_lear_act5_scene1',27,32,'REGAN','Why is this reason’d?'),
('king_lear_act5_scene1',28,33,'GONERIL','Combine together ’gainst the enemy;'),
('king_lear_act5_scene1',29,34,'GONERIL','For these domestic and particular broils'),
('king_lear_act5_scene1',30,35,'GONERIL','Are not the question here.'),
('king_lear_act5_scene1',30,36,'ALBANY','Let’s then determine'),
('king_lear_act5_scene1',31,37,'ALBANY','With the ancient of war on our proceedings.'),
('king_lear_act5_scene1',32,38,'EDMUND','I shall attend you presently at your tent.'),
('king_lear_act5_scene1',33,39,'REGAN','Sister, you’ll go with us?'),
('king_lear_act5_scene1',33,40,'GONERIL','No.'),
('king_lear_act5_scene1',34,41,'REGAN','’Tis most convenient; pray you, go with us.'),
('king_lear_act5_scene1',35,42,'GONERIL','O, ho, I know the riddle.—I will go.'),
('king_lear_act5_scene1',36,43,'EDGAR','If e’er your grace had speech with man so poor,'),
('king_lear_act5_scene1',37,44,'EDGAR','Hear me one word.'),
('king_lear_act5_scene1',37,45,'ALBANY','I’ll overtake you. Speak.'),
('king_lear_act5_scene1',38,46,'EDGAR','Before you fight the battle, ope this letter.'),
('king_lear_act5_scene1',39,47,'EDGAR','If you have victory, let the trumpet sound'),
('king_lear_act5_scene1',40,48,'EDGAR','For him that brought it: wretched though I seem,'),
('king_lear_act5_scene1',41,49,'EDGAR','I can produce a champion that will prove'),
('king_lear_act5_scene1',42,50,'EDGAR','What is avouched there. If you miscarry,'),
('king_lear_act5_scene1',43,51,'EDGAR','Your business of the world hath so an end,'),
('king_lear_act5_scene1',44,52,'EDGAR','And machination ceases. Fortune love you.'),
('king_lear_act5_scene1',45,53,'ALBANY','Stay till I have read the letter.'),
('king_lear_act5_scene1',46,54,'EDGAR','I was forbid it.'),
('king_lear_act5_scene1',47,55,'EDGAR','When time shall serve, let but the herald cry,'),
('king_lear_act5_scene1',48,56,'EDGAR','And I’ll appear again.'),
('king_lear_act5_scene1',49,57,'ALBANY','Why, fare thee well: I will o’erlook thy paper.'),
('king_lear_act5_scene1',50,58,'EDMUND','The enemy’s in view; draw up your powers.'),
('king_lear_act5_scene1',51,59,'EDMUND','Here is the guess of their true strength and forces'),
('king_lear_act5_scene1',52,60,'EDMUND','By diligent discovery; but your haste'),
('king_lear_act5_scene1',53,61,'EDMUND','Is now urged on you.'),
('king_lear_act5_scene1',53,62,'ALBANY','We will greet the time.'),
('king_lear_act5_scene1',54,63,'EDMUND','To both these sisters have I sworn my love;'),
('king_lear_act5_scene1',55,64,'EDMUND','Each jealous of the other, as the stung'),
('king_lear_act5_scene1',56,65,'EDMUND','Are of the adder. Which of them shall I take?'),
('king_lear_act5_scene1',57,66,'EDMUND','Both? one? or neither? Neither can be enjoy’d,'),
('king_lear_act5_scene1',58,67,'EDMUND','If both remain alive: to take the widow'),
('king_lear_act5_scene1',59,68,'EDMUND','Exasperates, makes mad her sister Goneril;'),
('king_lear_act5_scene1',60,69,'EDMUND','And hardly shall I carry out my side,'),
('king_lear_act5_scene1',61,70,'EDMUND','Her husband being alive. Now then we’ll use'),
('king_lear_act5_scene1',62,71,'EDMUND','His countenance for the battle; which being done,'),
('king_lear_act5_scene1',63,72,'EDMUND','Let her who would be rid of him devise'),
('king_lear_act5_scene1',64,73,'EDMUND','His speedy taking off. As for the mercy'),
('king_lear_act5_scene1',65,74,'EDMUND','Which he intends to Lear and to Cordelia,'),
('king_lear_act5_scene1',66,75,'EDMUND','The battle done, and they within our power,'),
('king_lear_act5_scene1',67,76,'EDMUND','Shall never see his pardon; for my state'),
('king_lear_act5_scene1',68,77,'EDMUND','Stands on me to defend, not to debate.'),
('king_lear_act5_scene2',1,0,'EDGAR','Here, father, take the shadow of this tree'),
('king_lear_act5_scene2',2,1,'EDGAR','For your good host; pray that the right may thrive:'),
('king_lear_act5_scene2',3,2,'EDGAR','If ever I return to you again,'),
('king_lear_act5_scene2',4,3,'EDGAR','I’ll bring you comfort.'),
('king_lear_act5_scene2',4,4,'GLOUCESTER','Grace go with you, sir!'),
('king_lear_act5_scene2',5,5,'EDGAR','Away, old man; give me thy hand; away!'),
('king_lear_act5_scene2',6,6,'EDGAR','King Lear hath lost, he and his daughter ta’en:'),
('king_lear_act5_scene2',7,7,'EDGAR','Give me thy hand; come on.'),
('king_lear_act5_scene2',8,8,'GLOUCESTER','No farther, sir; a man may rot even here.'),
('king_lear_act5_scene2',9,9,'EDGAR','What, in ill thoughts again? Men must endure'),
('king_lear_act5_scene2',10,10,'EDGAR','Their going hence, even as their coming hither;'),
('king_lear_act5_scene2',11,11,'EDGAR','Ripeness is all: come on.'),
('king_lear_act5_scene2',11,12,'GLOUCESTER','And that’s true too.'),
('king_lear_act5_scene3',1,0,'EDMUND','Some officers take them away: good guard,'),
('king_lear_act5_scene3',2,1,'EDMUND','Until their greater pleasures first be known'),
('king_lear_act5_scene3',3,2,'EDMUND','That are to censure them.'),
('king_lear_act5_scene3',3,3,'CORDELIA','We are not the first'),
('king_lear_act5_scene3',4,4,'CORDELIA','Who, with best meaning, have incurr’d the worst.'),
('king_lear_act5_scene3',5,5,'CORDELIA','For thee, oppressed king, am I cast down;'),
('king_lear_act5_scene3',6,6,'CORDELIA','Myself could else out-frown false fortune’s frown.'),
('king_lear_act5_scene3',7,7,'CORDELIA','Shall we not see these daughters and these sisters?'),
('king_lear_act5_scene3',8,8,'KING LEAR','No, no, no, no! Come, let’s away to prison:'),
('king_lear_act5_scene3',9,9,'KING LEAR','We two alone will sing like birds i’ the cage:'),
('king_lear_act5_scene3',10,10,'KING LEAR','When thou dost ask me blessing, I’ll kneel down,'),
('king_lear_act5_scene3',11,11,'KING LEAR','And ask of thee forgiveness: so we’ll live,'),
('king_lear_act5_scene3',12,12,'KING LEAR','And pray, and sing, and tell old tales, and laugh'),
('king_lear_act5_scene3',13,13,'KING LEAR','At gilded butterflies, and hear poor rogues'),
('king_lear_act5_scene3',14,14,'KING LEAR','Talk of court news; and we’ll talk with them too,'),
('king_lear_act5_scene3',15,15,'KING LEAR','Who loses and who wins; who’s in, who’s out;'),
('king_lear_act5_scene3',16,16,'KING LEAR','And take upon’s the mystery of things,'),
('king_lear_act5_scene3',17,17,'KING LEAR','As if we were God’s spies: and we’ll wear out,'),
('king_lear_act5_scene3',18,18,'KING LEAR','In a wall’d prison, packs and sects of great ones,'),
('king_lear_act5_scene3',19,19,'KING LEAR','That ebb and flow by the moon.'),
('king_lear_act5_scene3',20,20,'EDMUND','Take them away.'),
('king_lear_act5_scene3',20,21,'KING LEAR','Upon such sacrifices, my Cordelia,'),
('king_lear_act5_scene3',21,22,'KING LEAR','The gods themselves throw incense. Have I caught thee?'),
('king_lear_act5_scene3',22,23,'KING LEAR','He that parts us shall bring a brand from heaven,'),
('king_lear_act5_scene3',23,24,'KING LEAR','And fire us hence like foxes. Wipe thine eyes;'),
('king_lear_act5_scene3',24,25,'KING LEAR','The good-years shall devour them, flesh and fell,'),
('king_lear_act5_scene3',25,26,'KING LEAR','Ere they shall make us weep: we’ll see ’em starve first.'),
('king_lear_act5_scene3',26,27,'KING LEAR','Come.'),
('king_lear_act5_scene3',26,28,'EDMUND','Come hither, captain; hark.'),
('king_lear_act5_scene3',27,29,'EDMUND','Take thou this note; go follow them to prison:'),
('king_lear_act5_scene3',28,30,'EDMUND','One step I have advanced thee; if thou dost'),
('king_lear_act5_scene3',29,31,'EDMUND','As this instructs thee, thou dost make thy way'),
('king_lear_act5_scene3',30,32,'EDMUND','To noble fortunes: know thou this, that men'),
('king_lear_act5_scene3',31,33,'EDMUND','Are as the time is: to be tender-minded'),
('king_lear_act5_scene3',32,34,'EDMUND','Does not become a sword: thy great employment'),
('king_lear_act5_scene3',33,35,'EDMUND','Will not bear question; either say thou’lt do ’t,'),
('king_lear_act5_scene3',34,36,'EDMUND','Or thrive by other means.'),
('king_lear_act5_scene3',34,37,'CAPTAIN','I’ll do ’t, my lord.'),
('king_lear_act5_scene3',35,38,'EDMUND','About it; and write happy when thou hast done.'),
('king_lear_act5_scene3',36,39,'EDMUND','Mark, I say, instantly; and carry it so'),
('king_lear_act5_scene3',37,40,'EDMUND','As I have set it down.'),
('king_lear_act5_scene3',38,41,'CAPTAIN','I cannot draw a cart, nor eat dried oats;'),
('king_lear_act5_scene3',39,42,'CAPTAIN','If it be man’s work, I’ll do ’t.'),
('king_lear_act5_scene3',40,43,'ALBANY','Sir, you have shown to-day your valiant strain,'),
('king_lear_act5_scene3',41,44,'ALBANY','And fortune led you well: you have the captives'),
('king_lear_act5_scene3',42,45,'ALBANY','That were the opposites of this day’s strife:'),
('king_lear_act5_scene3',43,46,'ALBANY','We do require them of you, so to use them'),
('king_lear_act5_scene3',44,47,'ALBANY','As we shall find their merits and our safety'),
('king_lear_act5_scene3',45,48,'ALBANY','May equally determine.'),
('king_lear_act5_scene3',45,49,'EDMUND','Sir, I thought it fit'),
('king_lear_act5_scene3',46,50,'EDMUND','To send the old and miserable king'),
('king_lear_act5_scene3',47,51,'EDMUND','To some retention and appointed guard;'),
('king_lear_act5_scene3',48,52,'EDMUND','Whose age has charms in it, whose title more,'),
('king_lear_act5_scene3',49,53,'EDMUND','To pluck the common bosom on his side,'),
('king_lear_act5_scene3',50,54,'EDMUND','An turn our impress’d lances in our eyes'),
('king_lear_act5_scene3',51,55,'EDMUND','Which do command them. With him I sent the queen;'),
('king_lear_act5_scene3',52,56,'EDMUND','My reason all the same; and they are ready'),
('king_lear_act5_scene3',53,57,'EDMUND','To-morrow, or at further space, to appear'),
('king_lear_act5_scene3',54,58,'EDMUND','Where you shall hold your session. At this time'),
('king_lear_act5_scene3',55,59,'EDMUND','We sweat and bleed: the friend hath lost his friend;'),
('king_lear_act5_scene3',56,60,'EDMUND','And the best quarrels, in the heat, are cursed'),
('king_lear_act5_scene3',57,61,'EDMUND','By those that feel their sharpness:'),
('king_lear_act5_scene3',58,62,'EDMUND','The question of Cordelia and her father'),
('king_lear_act5_scene3',59,63,'EDMUND','Requires a fitter place.'),
('king_lear_act5_scene3',59,64,'ALBANY','Sir, by your patience,'),
('king_lear_act5_scene3',60,65,'ALBANY','I hold you but a subject of this war,'),
('king_lear_act5_scene3',61,66,'ALBANY','Not as a brother.'),
('king_lear_act5_scene3',62,67,'REGAN','That’s as we list to grace him.'),
('king_lear_act5_scene3',63,68,'REGAN','Methinks our pleasure might have been demanded,'),
('king_lear_act5_scene3',64,69,'REGAN','Ere you had spoke so far. He led our powers;'),
('king_lear_act5_scene3',65,70,'REGAN','Bore the commission of my place and person;'),
('king_lear_act5_scene3',66,71,'REGAN','The which immediacy may well stand up,'),
('king_lear_act5_scene3',67,72,'REGAN','And call itself your brother.'),
('king_lear_act5_scene3',67,73,'GONERIL','Not so hot:'),
('king_lear_act5_scene3',68,74,'GONERIL','In his own grace he doth exalt himself,'),
('king_lear_act5_scene3',69,75,'GONERIL','More than in your addition.'),
('king_lear_act5_scene3',69,76,'REGAN','In my rights,'),
('king_lear_act5_scene3',70,77,'REGAN','By me invested, he compeers the best.'),
('king_lear_act5_scene3',71,78,'GONERIL','That were the most, if he should husband you.'),
('king_lear_act5_scene3',72,79,'REGAN','Jesters do oft prove prophets.'),
('king_lear_act5_scene3',72,80,'GONERIL','Holla, holla!'),
('king_lear_act5_scene3',73,81,'GONERIL','That eye that told you so look’d but a-squint.'),
('king_lear_act5_scene3',74,82,'REGAN','Lady, I am not well; else I should answer'),
('king_lear_act5_scene3',75,83,'REGAN','From a full-flowing stomach. General,'),
('king_lear_act5_scene3',76,84,'REGAN','Take thou my soldiers, prisoners, patrimony;'),
('king_lear_act5_scene3',77,85,'REGAN','Dispose of them, of me; the walls are thine:'),
('king_lear_act5_scene3',78,86,'REGAN','Witness the world, that I create thee here'),
('king_lear_act5_scene3',79,87,'REGAN','My lord and master.'),
('king_lear_act5_scene3',79,88,'GONERIL','Mean you to enjoy him?'),
('king_lear_act5_scene3',80,89,'ALBANY','The let-alone lies not in your good will.'),
('king_lear_act5_scene3',81,90,'EDMUND','Nor in thine, lord.'),
('king_lear_act5_scene3',81,91,'ALBANY','Half-blooded fellow, yes.'),
('king_lear_act5_scene3',82,92,'REGAN','To Edmund. Let the drum strike, and prove my title thine.'),
('king_lear_act5_scene3',83,93,'ALBANY','Stay yet; hear reason. Edmund, I arrest thee'),
('king_lear_act5_scene3',84,94,'ALBANY','On capital treason; and, in thine attaint,'),
('king_lear_act5_scene3',85,95,'ALBANY','This gilded serpent'),
('king_lear_act5_scene3',86,96,'ALBANY','For your claim, fair sister,'),
('king_lear_act5_scene3',87,97,'ALBANY','I bar it in the interest of my wife:'),
('king_lear_act5_scene3',88,98,'ALBANY','’Tis she is sub-contracted to this lord,'),
('king_lear_act5_scene3',89,99,'ALBANY','And I, her husband, contradict your bans.'),
('king_lear_act5_scene3',90,100,'ALBANY','If you will marry, make your loves to me,'),
('king_lear_act5_scene3',91,101,'ALBANY','My lady is bespoke.'),
('king_lear_act5_scene3',91,102,'GONERIL','An interlude!'),
('king_lear_act5_scene3',92,103,'ALBANY','Thou art arm’d, Gloucester: let the trumpet sound:'),
('king_lear_act5_scene3',93,104,'ALBANY','If none appear to prove upon thy head'),
('king_lear_act5_scene3',94,105,'ALBANY','Thy heinous, manifest, and many treasons,'),
('king_lear_act5_scene3',95,106,'ALBANY','There is my pledge; Throwing down a glove.'),
('king_lear_act5_scene3',96,107,'ALBANY','I’ll prove it on thy heart,'),
('king_lear_act5_scene3',97,108,'ALBANY','Ere I taste bread, thou art in nothing less'),
('king_lear_act5_scene3',98,109,'ALBANY','Than I have here proclaim’d thee.'),
('king_lear_act5_scene3',98,110,'REGAN','Sick, O, sick!'),
('king_lear_act5_scene3',99,111,'GONERIL','If not, I’ll ne’er trust medicine.'),
('king_lear_act5_scene3',100,112,'EDMUND','There’s my exchange: Throwing down a glove.'),
('king_lear_act5_scene3',101,113,'EDMUND','what in the world he is'),
('king_lear_act5_scene3',102,114,'EDMUND','That names me traitor, villain-like he lies:'),
('king_lear_act5_scene3',103,115,'EDMUND','Call by thy trumpet: he that dares approach,'),
('king_lear_act5_scene3',104,116,'EDMUND','On him, on you, who not? I will maintain'),
('king_lear_act5_scene3',105,117,'EDMUND','My truth and honour firmly.'),
('king_lear_act5_scene3',105,118,'ALBANY','A herald, ho!'),
('king_lear_act5_scene3',106,119,'EDMUND','A herald, ho, a herald!'),
('king_lear_act5_scene3',107,120,'ALBANY','Trust to thy single virtue; for thy soldiers,'),
('king_lear_act5_scene3',108,121,'ALBANY','All levied in my name, have in my name'),
('king_lear_act5_scene3',109,122,'ALBANY','Took their discharge.'),
('king_lear_act5_scene3',109,123,'REGAN','My sickness grows upon me.'),
('king_lear_act5_scene3',110,124,'ALBANY','She is not well; convey her to my tent.'),
('king_lear_act5_scene3',111,125,'CAPTAIN','Sound, trumpet! A trumpet sounds.'),
('king_lear_act5_scene3',112,126,'HERALD','“If any man of quality or degree within the lists of the'),
('king_lear_act5_scene3',113,127,'HERALD','army will maintain upon Edmund, supposed Earl of Gloucester, that he is'),
('king_lear_act5_scene3',114,128,'HERALD','a manifold traitor, let him appear by the third sound of the'),
('king_lear_act5_scene3',115,129,'HERALD','trumpet: he is bold in his defence.”'),
('king_lear_act5_scene3',116,130,'EDMUND','Sound! First trumpet.'),
('king_lear_act5_scene3',116,131,'HERALD','Again! Second trumpet.'),
('king_lear_act5_scene3',117,132,'HERALD','Again! Third trumpet.'),
('king_lear_act5_scene3',118,133,'ALBANY','Ask him his purposes, why he appears'),
('king_lear_act5_scene3',119,134,'ALBANY','Upon this call o’ the trumpet.'),
('king_lear_act5_scene3',119,135,'HERALD','What are you?'),
('king_lear_act5_scene3',120,136,'HERALD','Your name, your quality? and why you answer'),
('king_lear_act5_scene3',121,137,'HERALD','This present summons?'),
('king_lear_act5_scene3',121,138,'EDGAR','Know, my name is lost;'),
('king_lear_act5_scene3',122,139,'EDGAR','By treason’s tooth bare-gnawn and canker-bit:'),
('king_lear_act5_scene3',123,140,'EDGAR','Yet am I noble as the adversary'),
('king_lear_act5_scene3',124,141,'EDGAR','I come to cope.'),
('king_lear_act5_scene3',124,142,'ALBANY','Which is that adversary?'),
('king_lear_act5_scene3',125,143,'EDGAR','What’s he that speaks for Edmund Earl of Gloucester?'),
('king_lear_act5_scene3',126,144,'EDMUND','Himself: what say’st thou to him?'),
('king_lear_act5_scene3',126,145,'EDGAR','Draw thy sword,'),
('king_lear_act5_scene3',127,146,'EDGAR','That, if my speech offend a noble heart,'),
('king_lear_act5_scene3',128,147,'EDGAR','Thy arm may do thee justice: here is mine.'),
('king_lear_act5_scene3',129,148,'EDGAR','Behold, it is the privilege of mine honours,'),
('king_lear_act5_scene3',130,149,'EDGAR','My oath, and my profession: I protest,'),
('king_lear_act5_scene3',131,150,'EDGAR','Maugre thy strength, youth, place, and eminence,'),
('king_lear_act5_scene3',132,151,'EDGAR','Despite thy victor sword and fire-new fortune,'),
('king_lear_act5_scene3',133,152,'EDGAR','Thy valour and thy heart, thou art a traitor;'),
('king_lear_act5_scene3',134,153,'EDGAR','False to thy gods, thy brother, and thy father;'),
('king_lear_act5_scene3',135,154,'EDGAR','Conspirant ’gainst this high-illustrious prince;'),
('king_lear_act5_scene3',136,155,'EDGAR','And, from the extremest upward of thy head'),
('king_lear_act5_scene3',137,156,'EDGAR','To the descent and dust below thy foot,'),
('king_lear_act5_scene3',138,157,'EDGAR','A most toad-spotted traitor. Say thou “No,”'),
('king_lear_act5_scene3',139,158,'EDGAR','This sword, this arm, and my best spirits, are bent'),
('king_lear_act5_scene3',140,159,'EDGAR','To prove upon thy heart, whereto I speak,'),
('king_lear_act5_scene3',141,160,'EDGAR','Thou liest.'),
('king_lear_act5_scene3',142,161,'EDMUND','In wisdom I should ask thy name;'),
('king_lear_act5_scene3',143,162,'EDMUND','But, since thy outside looks so fair and warlike,'),
('king_lear_act5_scene3',144,163,'EDMUND','And that thy tongue some say of breeding breathes,'),
('king_lear_act5_scene3',145,164,'EDMUND','What safe and nicely I might well delay'),
('king_lear_act5_scene3',146,165,'EDMUND','By rule of knighthood, I disdain and spurn:'),
('king_lear_act5_scene3',147,166,'EDMUND','Back do I toss these treasons to thy head;'),
('king_lear_act5_scene3',148,167,'EDMUND','With the hell-hated lie o’erwhelm thy heart;'),
('king_lear_act5_scene3',149,168,'EDMUND','Which, for they yet glance by and scarcely bruise,'),
('king_lear_act5_scene3',150,169,'EDMUND','This sword of mine shall give them instant way,'),
('king_lear_act5_scene3',151,170,'EDMUND','Where they shall rest for ever. Trumpets, speak!'),
('king_lear_act5_scene3',152,171,'ALBANY','Save him, save him!'),
('king_lear_act5_scene3',152,172,'GONERIL','This is practise, Gloucester:'),
('king_lear_act5_scene3',153,173,'GONERIL','By the law of arms thou wast not bound to answer'),
('king_lear_act5_scene3',154,174,'GONERIL','An unknown opposite; thou art not vanquish’d,'),
('king_lear_act5_scene3',155,175,'GONERIL','But cozen’d and beguiled.'),
('king_lear_act5_scene3',155,176,'ALBANY','Shut your mouth, dame,'),
('king_lear_act5_scene3',156,177,'ALBANY','Or with this paper shall I stop it: Hold, sir:'),
('king_lear_act5_scene3',157,178,'ALBANY','Thou worse than any name, read thine own evil:'),
('king_lear_act5_scene3',158,179,'ALBANY','No tearing, lady: I perceive you know it. Gives the letter to Edmund.'),
('king_lear_act5_scene3',159,180,'GONERIL','Say, if I do, the laws are mine, not thine:'),
('king_lear_act5_scene3',160,181,'GONERIL','Who can arraign me for’t.'),
('king_lear_act5_scene3',160,182,'ALBANY','Most monstrous! oh!'),
('king_lear_act5_scene3',161,183,'ALBANY','Know’st thou this paper?'),
('king_lear_act5_scene3',161,184,'GONERIL','Ask me not what I know.'),
('king_lear_act5_scene3',162,185,'ALBANY','Go after her: she’s desperate; govern her.'),
('king_lear_act5_scene3',163,186,'EDMUND','What you have charged me with, that have I done;'),
('king_lear_act5_scene3',164,187,'EDMUND','And more, much more; the time will bring it out:'),
('king_lear_act5_scene3',165,188,'EDMUND','’Tis past, and so am I. But what art thou'),
('king_lear_act5_scene3',166,189,'EDMUND','That hast this fortune on me? If thou’rt noble,'),
('king_lear_act5_scene3',167,190,'EDMUND','I do forgive thee.'),
('king_lear_act5_scene3',167,191,'EDGAR','Let’s exchange charity.'),
('king_lear_act5_scene3',168,192,'EDGAR','I am no less in blood than thou art, Edmund;'),
('king_lear_act5_scene3',169,193,'EDGAR','If more, the more thou hast wrong’d me.'),
('king_lear_act5_scene3',170,194,'EDGAR','My name is Edgar, and thy father’s son.'),
('king_lear_act5_scene3',171,195,'EDGAR','The gods are just, and of our pleasant vices'),
('king_lear_act5_scene3',172,196,'EDGAR','Make instruments to plague us:'),
('king_lear_act5_scene3',173,197,'EDGAR','The dark and vicious place where thee he got'),
('king_lear_act5_scene3',174,198,'EDGAR','Cost him his eyes.'),
('king_lear_act5_scene3',174,199,'EDMUND','Thou hast spoken right, ’tis true;'),
('king_lear_act5_scene3',175,200,'EDMUND','The wheel is come full circle: I am here.'),
('king_lear_act5_scene3',176,201,'ALBANY','Methought thy very gait did prophesy'),
('king_lear_act5_scene3',177,202,'ALBANY','A royal nobleness: I must embrace thee:'),
('king_lear_act5_scene3',178,203,'ALBANY','Let sorrow split my heart, if ever I'),
('king_lear_act5_scene3',179,204,'ALBANY','Did hate thee or thy father!'),
('king_lear_act5_scene3',179,205,'EDGAR','Worthy prince, I know’t.'),
('king_lear_act5_scene3',180,206,'ALBANY','Where have you hid yourself?'),
('king_lear_act5_scene3',181,207,'ALBANY','How have you known the miseries of your father?'),
('king_lear_act5_scene3',182,208,'EDGAR','By nursing them, my lord. List a brief tale;'),
('king_lear_act5_scene3',183,209,'EDGAR','And when ’tis told, O, that my heart would burst!'),
('king_lear_act5_scene3',184,210,'EDGAR','The bloody proclamation to escape,'),
('king_lear_act5_scene3',185,211,'EDGAR','That follow’d me so near—O, our lives’ sweetness!'),
('king_lear_act5_scene3',186,212,'EDGAR','That we the pain of death would hourly die'),
('king_lear_act5_scene3',187,213,'EDGAR','Rather than die at once!—taught me to shift'),
('king_lear_act5_scene3',188,214,'EDGAR','Into a madman’s rags; to assume a semblance'),
('king_lear_act5_scene3',189,215,'EDGAR','That very dogs disdain’d: and in this habit'),
('king_lear_act5_scene3',190,216,'EDGAR','Met I my father with his bleeding rings,'),
('king_lear_act5_scene3',191,217,'EDGAR','Their precious stones new lost: became his guide,'),
('king_lear_act5_scene3',192,218,'EDGAR','Led him, begg’d for him, saved him from despair;'),
('king_lear_act5_scene3',193,219,'EDGAR','Never—O fault!—reveal’d myself unto him,'),
('king_lear_act5_scene3',194,220,'EDGAR','Until some half-hour past, when I was arm’d:'),
('king_lear_act5_scene3',195,221,'EDGAR','Not sure, though hoping, of this good success,'),
('king_lear_act5_scene3',196,222,'EDGAR','I ask’d his blessing, and from first to last'),
('king_lear_act5_scene3',197,223,'EDGAR','Told him my pilgrimage: but his flaw’d heart,'),
('king_lear_act5_scene3',198,224,'EDGAR','Alack, too weak the conflict to support!'),
('king_lear_act5_scene3',199,225,'EDGAR','’Twixt two extremes of passion, joy and grief,'),
('king_lear_act5_scene3',200,226,'EDGAR','Burst smilingly.'),
('king_lear_act5_scene3',201,227,'EDMUND','This speech of yours hath moved me,'),
('king_lear_act5_scene3',202,228,'EDMUND','And shall perchance do good: but speak you on;'),
('king_lear_act5_scene3',203,229,'EDMUND','You look as you had something more to say.'),
('king_lear_act5_scene3',204,230,'ALBANY','If there be more, more woeful, hold it in;'),
('king_lear_act5_scene3',205,231,'ALBANY','For I am almost ready to dissolve,'),
('king_lear_act5_scene3',206,232,'ALBANY','Hearing of this.'),
('king_lear_act5_scene3',206,233,'EDGAR','This would have seem’d a period'),
('king_lear_act5_scene3',207,234,'EDGAR','To such as love not sorrow; but another,'),
('king_lear_act5_scene3',208,235,'EDGAR','To amplify too much, would make much more,'),
('king_lear_act5_scene3',209,236,'EDGAR','And top extremity.'),
('king_lear_act5_scene3',210,237,'EDGAR','Whilst I was big in clamour came there in a man,'),
('king_lear_act5_scene3',211,238,'EDGAR','Who, having seen me in my worst estate,'),
('king_lear_act5_scene3',212,239,'EDGAR','Shunn’d my abhorr’d society; but then, finding'),
('king_lear_act5_scene3',213,240,'EDGAR','Who ’twas that so endured, with his strong arms'),
('king_lear_act5_scene3',214,241,'EDGAR','He fastened on my neck, and bellow’d out'),
('king_lear_act5_scene3',215,242,'EDGAR','As he’d burst heaven; threw him on my father;'),
('king_lear_act5_scene3',216,243,'EDGAR','Told the most piteous tale of Lear and him'),
('king_lear_act5_scene3',217,244,'EDGAR','That ever ear received: which in recounting'),
('king_lear_act5_scene3',218,245,'EDGAR','His grief grew puissant and the strings of life'),
('king_lear_act5_scene3',219,246,'EDGAR','Began to crack: twice then the trumpets sounded,'),
('king_lear_act5_scene3',220,247,'EDGAR','And there I left him tranced.'),
('king_lear_act5_scene3',220,248,'ALBANY','But who was this?'),
('king_lear_act5_scene3',221,249,'EDGAR','Kent, sir, the banish’d Kent; who in disguise'),
('king_lear_act5_scene3',222,250,'EDGAR','Follow’d his enemy king, and did him service'),
('king_lear_act5_scene3',223,251,'EDGAR','Improper for a slave.'),
('king_lear_act5_scene3',223,252,'GENTLEMAN','Help, help, O, help!'),
('king_lear_act5_scene3',224,253,'EDGAR','What kind of help?'),
('king_lear_act5_scene3',224,254,'ALBANY','Speak, man.'),
('king_lear_act5_scene3',225,255,'EDGAR','What means that bloody knife?'),
('king_lear_act5_scene3',225,256,'GENTLEMAN','’Tis hot, it smokes;'),
('king_lear_act5_scene3',226,257,'GENTLEMAN','It came even from the heart of—O, she’s dead!'),
('king_lear_act5_scene3',227,258,'ALBANY','Who dead? speak, man.'),
('king_lear_act5_scene3',228,259,'GENTLEMAN','Your lady, sir, your lady: and her sister'),
('king_lear_act5_scene3',229,260,'GENTLEMAN','By her is poisoned; she hath confess’d it.'),
('king_lear_act5_scene3',230,261,'EDMUND','I was contracted to them both: all three'),
('king_lear_act5_scene3',231,262,'EDMUND','Now marry in an instant.'),
('king_lear_act5_scene3',231,263,'EDGAR','Here comes Kent.'),
('king_lear_act5_scene3',232,264,'ALBANY','Produce their bodies, be they alive or dead:'),
('king_lear_act5_scene3',233,265,'ALBANY','This judgment of the heavens, that makes us tremble,'),
('king_lear_act5_scene3',234,266,'ALBANY','Touches us not with pity.'),
('king_lear_act5_scene3',235,267,'ALBANY','O, is this he?'),
('king_lear_act5_scene3',236,268,'ALBANY','The time will not allow the compliment'),
('king_lear_act5_scene3',237,269,'ALBANY','Which very manners urges.'),
('king_lear_act5_scene3',237,270,'KENT','I am come'),
('king_lear_act5_scene3',238,271,'KENT','To bid my king and master aye good night:'),
('king_lear_act5_scene3',239,272,'KENT','Is he not here?'),
('king_lear_act5_scene3',239,273,'ALBANY','Great thing of us forgot!'),
('king_lear_act5_scene3',240,274,'ALBANY','Speak, Edmund, where’s the king? and where’s Cordelia?'),
('king_lear_act5_scene3',241,275,'ALBANY','See’st thou this object, Kent?'),
('king_lear_act5_scene3',241,276,'KENT','Alack, why thus?'),
('king_lear_act5_scene3',242,277,'EDMUND','Yet Edmund was beloved:'),
('king_lear_act5_scene3',243,278,'EDMUND','The one the other poison’d for my sake,'),
('king_lear_act5_scene3',244,279,'EDMUND','And after slew herself.'),
('king_lear_act5_scene3',244,280,'ALBANY','Even so. Cover their faces.'),
('king_lear_act5_scene3',245,281,'EDMUND','I pant for life: some good I mean to do,'),
('king_lear_act5_scene3',246,282,'EDMUND','Despite of mine own nature. Quickly send,'),
('king_lear_act5_scene3',247,283,'EDMUND','Be brief in it, to the castle; for my writ'),
('king_lear_act5_scene3',248,284,'EDMUND','Is on the life of Lear and on Cordelia:'),
('king_lear_act5_scene3',249,285,'EDMUND','Nay, send in time.'),
('king_lear_act5_scene3',249,286,'ALBANY','Run, run, O, run!'),
('king_lear_act5_scene3',250,287,'EDGAR','To who, my lord? Who hath the office? send'),
('king_lear_act5_scene3',251,288,'EDGAR','Thy token of reprieve.'),
('king_lear_act5_scene3',251,289,'EDMUND','Well thought on: take my sword,'),
('king_lear_act5_scene3',252,290,'EDMUND','Give it the captain.'),
('king_lear_act5_scene3',252,291,'ALBANY','Haste thee, for thy life.'),
('king_lear_act5_scene3',253,292,'EDMUND','He hath commission from thy wife and me'),
('king_lear_act5_scene3',254,293,'EDMUND','To hang Cordelia in the prison, and'),
('king_lear_act5_scene3',255,294,'EDMUND','To lay the blame upon her own despair,'),
('king_lear_act5_scene3',256,295,'EDMUND','That she fordid herself.'),
('king_lear_act5_scene3',257,296,'ALBANY','The gods defend her! Bear him hence awhile. Edmund is borne off.'),
('king_lear_act5_scene3',258,297,'KING LEAR','Howl, howl, howl, howl! O, you are men of stones:'),
('king_lear_act5_scene3',259,298,'KING LEAR','Had I your tongues and eyes, I’ld use them so'),
('king_lear_act5_scene3',260,299,'KING LEAR','That heaven’s vault should crack. She’s gone for ever!'),
('king_lear_act5_scene3',261,300,'KING LEAR','I know when one is dead, and when one lives;'),
('king_lear_act5_scene3',262,301,'KING LEAR','She’s dead as earth. Lend me a looking-glass;'),
('king_lear_act5_scene3',263,302,'KING LEAR','If that her breath will mist or stain the stone,'),
('king_lear_act5_scene3',264,303,'KING LEAR','Why, then she lives.'),
('king_lear_act5_scene3',264,304,'KENT','Is this the promised end?'),
('king_lear_act5_scene3',265,305,'EDGAR','Or image of that horror?'),
('king_lear_act5_scene3',265,306,'ALBANY','Fall, and cease!'),
('king_lear_act5_scene3',266,307,'KING LEAR','This feather stirs; she lives! if it be so,'),
('king_lear_act5_scene3',267,308,'KING LEAR','It is a chance which does redeem all sorrows'),
('king_lear_act5_scene3',268,309,'KING LEAR','That ever I have felt.'),
('king_lear_act5_scene3',268,310,'KENT','O my good master!'),
('king_lear_act5_scene3',269,311,'KING LEAR','Prithee, away.'),
('king_lear_act5_scene3',269,312,'EDGAR','’Tis noble Kent, your friend.'),
('king_lear_act5_scene3',270,313,'KING LEAR','A plague upon you, murderers, traitors all!'),
('king_lear_act5_scene3',271,314,'KING LEAR','I might have saved her; now she’s gone for ever!'),
('king_lear_act5_scene3',272,315,'KING LEAR','Cordelia, Cordelia! stay a little. Ha!'),
('king_lear_act5_scene3',273,316,'KING LEAR','What is’t thou say’st? Her voice was ever soft,'),
('king_lear_act5_scene3',274,317,'KING LEAR','Gentle, and low, an excellent thing in woman.'),
('king_lear_act5_scene3',275,318,'KING LEAR','I kill’d the slave that was a-hanging thee.'),
('king_lear_act5_scene3',276,319,'CAPTAIN','’Tis true, my lords, he did.'),
('king_lear_act5_scene3',276,320,'KING LEAR','Did I not, fellow?'),
('king_lear_act5_scene3',277,321,'KING LEAR','I have seen the day, with my good biting falchion'),
('king_lear_act5_scene3',278,322,'KING LEAR','I would have made them skip: I am old now,'),
('king_lear_act5_scene3',279,323,'KING LEAR','And these same crosses spoil me. Who are you?'),
('king_lear_act5_scene3',280,324,'KING LEAR','Mine eyes are not o’ the best: I’ll tell you straight.'),
('king_lear_act5_scene3',281,325,'KENT','If fortune brag of two she loved and hated,'),
('king_lear_act5_scene3',282,326,'KENT','One of them we behold.'),
('king_lear_act5_scene3',283,327,'KING LEAR','This is a dull sight. Are you not Kent?'),
('king_lear_act5_scene3',284,328,'KENT','The same,'),
('king_lear_act5_scene3',285,329,'KENT','Your servant Kent: Where is your servant Caius?'),
('king_lear_act5_scene3',286,330,'KING LEAR','He’s a good fellow, I can tell you that;'),
('king_lear_act5_scene3',287,331,'KING LEAR','He’ll strike, and quickly too: he’s dead and rotten.'),
('king_lear_act5_scene3',288,332,'KENT','No, my good lord; I am the very man—'),
('king_lear_act5_scene3',289,333,'KING LEAR','I’ll see that straight.'),
('king_lear_act5_scene3',290,334,'KENT','That, from your first of difference and decay,'),
('king_lear_act5_scene3',291,335,'KENT','Have follow’d your sad steps.'),
('king_lear_act5_scene3',291,336,'KING LEAR','You are welcome hither.'),
('king_lear_act5_scene3',292,337,'KENT','Nor no man else: all’s cheerless, dark, and deadly.'),
('king_lear_act5_scene3',293,338,'KENT','Your eldest daughters have fordone them selves,'),
('king_lear_act5_scene3',294,339,'KENT','And desperately are dead.'),
('king_lear_act5_scene3',294,340,'KING LEAR','Ay, so I think.'),
('king_lear_act5_scene3',295,341,'ALBANY','He knows not what he says: and vain it is'),
('king_lear_act5_scene3',296,342,'ALBANY','That we present us to him.'),
('king_lear_act5_scene3',296,343,'EDGAR','Very bootless.'),
('king_lear_act5_scene3',297,344,'CAPTAIN','Edmund is dead, my lord.'),
('king_lear_act5_scene3',297,345,'ALBANY','That’s but a trifle here.'),
('king_lear_act5_scene3',298,346,'ALBANY','You lords and noble friends, know our intent.'),
('king_lear_act5_scene3',299,347,'ALBANY','What comfort to this great decay may come'),
('king_lear_act5_scene3',300,348,'ALBANY','Shall be applied: for us we will resign,'),
('king_lear_act5_scene3',301,349,'ALBANY','During the life of this old majesty,'),
('king_lear_act5_scene3',302,350,'ALBANY','To him our absolute power: To Edgar and Kent. you, to your rights:'),
('king_lear_act5_scene3',303,351,'ALBANY','With boot, and such addition as your honours'),
('king_lear_act5_scene3',304,352,'ALBANY','Have more than merited. All friends shall taste'),
('king_lear_act5_scene3',305,353,'ALBANY','The wages of their virtue, and all foes'),
('king_lear_act5_scene3',306,354,'ALBANY','The cup of their deservings. O, see, see!'),
('king_lear_act5_scene3',307,355,'KING LEAR','And my poor fool is hang’d! No, no, no life!'),
('king_lear_act5_scene3',308,356,'KING LEAR','Why should a dog, a horse, a rat, have life,'),
('king_lear_act5_scene3',309,357,'KING LEAR','And thou no breath at all? Thou’lt come no more,'),
('king_lear_act5_scene3',310,358,'KING LEAR','Never, never, never, never, never!'),
('king_lear_act5_scene3',311,359,'KING LEAR','Pray you, undo this button: thank you, sir.'),
('king_lear_act5_scene3',312,360,'KING LEAR','Do you see this? Look on her, look, her lips,'),
('king_lear_act5_scene3',313,361,'KING LEAR','Look there, look there!'),
('king_lear_act5_scene3',313,362,'EDGAR','He faints! My lord, my lord!'),
('king_lear_act5_scene3',314,363,'KENT','Break, heart; I prithee, break!'),
('king_lear_act5_scene3',314,364,'EDGAR','Look up, my lord.'),
('king_lear_act5_scene3',315,365,'KENT','Vex not his ghost: O, let him pass! he hates him much'),
('king_lear_act5_scene3',316,366,'KENT','That would upon the rack of this tough world'),
('king_lear_act5_scene3',317,367,'KENT','Stretch him out longer.'),
('king_lear_act5_scene3',317,368,'EDGAR','He is gone, indeed.'),
('king_lear_act5_scene3',318,369,'KENT','The wonder is, he hath endured so long:'),
('king_lear_act5_scene3',319,370,'KENT','He but usurp’d his life.'),
('king_lear_act5_scene3',320,371,'ALBANY','Bear them from hence. Our present business');
INSERT INTO lines (section_id,number,array_index,speaker,text) VALUES
('king_lear_act5_scene3',321,372,'ALBANY','Is general woe. To Kent and Edgar. Friends of my soul, you twain'),
('king_lear_act5_scene3',322,373,'ALBANY','Rule in this realm, and the gored state sustain.'),
('king_lear_act5_scene3',323,374,'KENT','I have a journey, sir, shortly to go;'),
('king_lear_act5_scene3',324,375,'KENT','My master calls me, I must not say no.'),
('king_lear_act5_scene3',325,376,'ALBANY','The weight of this sad time we must obey;'),
('king_lear_act5_scene3',326,377,'ALBANY','Speak what we feel, not what we ought to say.'),
('king_lear_act5_scene3',327,378,'ALBANY','The oldest hath borne most: we that are young'),
('king_lear_act5_scene3',328,379,'ALBANY','Shall never see so much, nor live so long.');
INSERT INTO stage_directions (section_id,after_line,text) VALUES
('king_lear_act1_scene1',0,'Enter Kent, Gloucester, and Edmund.'),
('king_lear_act1_scene1',24,'Sennet. Enter King Lear, Cornwall, Albany, Goneril, Regan, Cordelia, and Attendants.'),
('king_lear_act1_scene1',26,'Exeunt Gloucester and Edmund.'),
('king_lear_act1_scene1',53,'Aside.'),
('king_lear_act1_scene1',68,'Aside.'),
('king_lear_act1_scene1',128,'Giving the crown.'),
('king_lear_act1_scene1',177,'Exit.'),
('king_lear_act1_scene1',177,'Flourish. Reenter Gloucester, with King of France, Burgundy, and Attendants.'),
('king_lear_act1_scene1',256,'Flourish. Exeunt all but King of France, Goneril, Regan, and Cordelia.'),
('king_lear_act1_scene1',271,'Exeunt King of France and Cordelia.'),
('king_lear_act1_scene1',290,'Exeunt.'),
('king_lear_act1_scene2',0,'Enter Edmund, with a letter.'),
('king_lear_act1_scene2',22,'Enter Gloucester.'),
('king_lear_act1_scene2',50,'Reads.'),
('king_lear_act1_scene2',50,'Hum—conspiracy!—“Sleep till I waked him—you should enjoy half his revenue,”—My son Edgar! Had he a hand to write this? a heart and brain to breed it in?—When came this to you? who brought it?'),
('king_lear_act1_scene2',96,'Exit.'),
('king_lear_act1_scene2',108,'Enter Edgar.'),
('king_lear_act1_scene2',108,'And pat he comes like the catastrophe of the old comedy: my cue is villainous melancholy, with a sigh like Tom o’ Bedlam. O, these eclipses do portend these divisions! fa, sol, la, mi.'),
('king_lear_act1_scene2',138,'Exit Edgar.'),
('king_lear_act1_scene2',138,'A credulous father! and a brother noble, Whose nature is so far from doing harms, That he suspects none: on whose foolish honesty My practises ride easy! I see the business. Let me, if not by birth, have lands by wit: All with me’s meet that I can fashion fit. Exit.'),
('king_lear_act1_scene3',0,'Enter Goneril, and Oswald, her steward.'),
('king_lear_act1_scene3',26,'Exeunt.'),
('king_lear_act1_scene4',0,'Enter Kent, disguised.'),
('king_lear_act1_scene4',7,'Horns within. Enter King Lear, Knights, and Attendants.'),
('king_lear_act1_scene4',8,'Exit an Attendant.'),
('king_lear_act1_scene4',8,'How now! what art thou?'),
('king_lear_act1_scene4',33,'Exit an Attendant.'),
('king_lear_act1_scene4',33,'Enter Oswald.'),
('king_lear_act1_scene4',33,'You, you, sirrah, where’s my daughter?'),
('king_lear_act1_scene4',34,'Exit.'),
('king_lear_act1_scene4',35,'Exit a Knight.'),
('king_lear_act1_scene4',35,'Where’s my fool, ho? I think the world’s asleep.'),
('king_lear_act1_scene4',35,'Reenter Knight.'),
('king_lear_act1_scene4',35,'How now! where’s that mongrel?'),
('king_lear_act1_scene4',55,'Exit an Attendant.'),
('king_lear_act1_scene4',55,'Exit an Attendant.'),
('king_lear_act1_scene4',55,'Reenter Oswald.'),
('king_lear_act1_scene4',55,'O, you sir, you, come you hither, sir: who am I, sir?'),
('king_lear_act1_scene4',65,'Giving Kent money.'),
('king_lear_act1_scene4',65,'Enter Fool.'),
('king_lear_act1_scene4',66,'Offering Kent his cap.'),
('king_lear_act1_scene4',121,'Singing. Fools had ne’er less wit in a year; For wise men are grown foppish, They know not how their wits to wear, Their manners are so apish.'),
('king_lear_act1_scene4',125,'Singing. Then they for sudden joy did weep, And I for sorrow sung, That such a king should play bo-peep, And go the fools among.'),
('king_lear_act1_scene4',125,'Prithee, nuncle, keep a schoolmaster that can teach thy fool to lie: I would fain learn to lie.'),
('king_lear_act1_scene4',132,'Enter Goneril.'),
('king_lear_act1_scene4',139,'Mum, mum, He that keeps nor crust nor crum, Weary of all, shall want some.'),
('king_lear_act1_scene4',139,'Pointing to King Lear. That’s a shealed peascod.'),
('king_lear_act1_scene4',194,'Enter Albany.'),
('king_lear_act1_scene4',227,'Exit.'),
('king_lear_act1_scene4',231,'Reenter King Lear.'),
('king_lear_act1_scene4',250,'Exeunt King Lear, Kent, and Attendants.'),
('king_lear_act1_scene4',261,'Exit.'),
('king_lear_act1_scene4',273,'Reenter Oswald.'),
('king_lear_act1_scene4',273,'How now, Oswald! What, have you writ that letter to my sister?'),
('king_lear_act1_scene4',278,'Exit Oswald.'),
('king_lear_act1_scene4',278,'No, no, my lord, This milky gentleness and course of yours Though I condemn not, yet, under pardon, You are much more attask’d for want of wisdom Than praised for harmful mildness.'),
('king_lear_act1_scene4',281,'Exeunt.'),
('king_lear_act1_scene5',0,'Enter King Lear, Kent, and Fool.'),
('king_lear_act1_scene5',5,'Exit.'),
('king_lear_act1_scene5',36,'Enter Gentleman.'),
('king_lear_act1_scene5',36,'How now! are the horses ready?'),
('king_lear_act1_scene5',39,'Exeunt.'),
('king_lear_act2_scene1',0,'Enter Edmund, and Curan meets him.'),
('king_lear_act2_scene1',10,'Exit.'),
('king_lear_act2_scene1',16,'Enter Edgar.'),
('king_lear_act2_scene1',16,'My father watches: O sir, fly this place; Intelligence is given where you are hid; You have now the good advantage of the night: Have you not spoken ’gainst the Duke of Cornwall? He’s coming hither: now, i’ the night, i’ the haste, And Regan with him: have you nothing said Upon his party ’gainst the Duke of Albany? Advise yourself.'),
('king_lear_act2_scene1',22,'Exit Edgar.'),
('king_lear_act2_scene1',26,'Enter Gloucester, and Servants with torches.'),
('king_lear_act2_scene1',32,'Exeunt some Servants.'),
('king_lear_act2_scene1',74,'Enter Cornwall, Regan, and Attendants.'),
('king_lear_act2_scene1',118,'Exeunt.'),
('king_lear_act2_scene2',0,'Enter Kent and Oswald, severally.'),
('king_lear_act2_scene2',23,'Drawing his sword.'),
('king_lear_act2_scene2',30,'Enter Edmund, with his rapier drawn, Cornwall, Regan, Gloucester, and Servants.'),
('king_lear_act2_scene2',130,'Exeunt all but Gloucester and Kent.'),
('king_lear_act2_scene2',138,'Exit.'),
('king_lear_act2_scene3',0,'Enter Edgar.'),
('king_lear_act2_scene3',21,'Exit.'),
('king_lear_act2_scene4',0,'Kent in the stocks.'),
('king_lear_act2_scene4',0,'Enter King Lear, Fool, and Gentleman.'),
('king_lear_act2_scene4',54,'Exit.'),
('king_lear_act2_scene4',68,'That sir which serves and seeks for gain, And follows but for form, Will pack when it begins to rain, And leave thee in the storm, But I will tarry; the fool will stay, And let the wise man fly: The knave turns fool that runs away; The fool no knave, perdy.'),
('king_lear_act2_scene4',69,'Reenter King Lear with Gloucester.'),
('king_lear_act2_scene4',101,'Exit.'),
('king_lear_act2_scene4',106,'Enter Cornwall, Regan, Gloucester, and Servants.'),
('king_lear_act2_scene4',117,'Points to his heart.'),
('king_lear_act2_scene4',136,'Kneeling.'),
('king_lear_act2_scene4',140,'Rising.'),
('king_lear_act2_scene4',168,'Enter Oswald.'),
('king_lear_act2_scene4',168,'Is your lady come?'),
('king_lear_act2_scene4',173,'Enter Goneril.'),
('king_lear_act2_scene4',173,'If you do love old men, if your sweet sway Allow obedience, if yourselves are old, Make it your cause; send down, and take my part! To Goneril. Art not ashamed to look upon this beard? O Regan, wilt thou take her by the hand?'),
('king_lear_act2_scene4',196,'Pointing at Oswald.'),
('king_lear_act2_scene4',266,'Exeunt King Lear, Gloucester, Kent, and Fool.'),
('king_lear_act2_scene4',266,'Storm and tempest.'),
('king_lear_act2_scene4',275,'Reenter Gloucester.'),
('king_lear_act2_scene4',289,'Exeunt.'),
('king_lear_act3_scene1',0,'Storm still. Enter Kent and a Gentleman, meeting.'),
('king_lear_act3_scene1',54,'Exeunt severally.'),
('king_lear_act3_scene2',0,'Enter King Lear and Fool.'),
('king_lear_act3_scene2',24,'The cod-piece that will house Before the head has any, The head and he shall louse; So beggars marry many. The man that makes his toe What he his heart should make Shall of a corn cry woe, And turn his sleep to wake. For there was never yet fair woman but she made mouths in a glass.'),
('king_lear_act3_scene2',26,'Enter Kent.'),
('king_lear_act3_scene2',60,'Singing.'),
('king_lear_act3_scene2',64,'Exeunt King Lear and Kent.'),
('king_lear_act3_scene2',81,'Exit.'),
('king_lear_act3_scene3',0,'Enter Gloucester and Edmund.'),
('king_lear_act3_scene3',16,'Exit.'),
('king_lear_act3_scene3',21,'Exit.'),
('king_lear_act3_scene4',0,'Enter King Lear, Kent, and Fool.'),
('king_lear_act3_scene4',3,'Storm still.'),
('king_lear_act3_scene4',37,'Within.'),
('king_lear_act3_scene4',37,'The Fool runs out from the hovel.'),
('king_lear_act3_scene4',41,'Enter Edgar disguised as a mad man.'),
('king_lear_act3_scene4',55,'Storm still.'),
